        if (!raw || /[./]/.test(raw) || /^https?:\/\//i.test(raw) || /^(?:\/)?api\/icon\//i.test(raw)) return '';
        const parts = raw.split('-').map((part) => String(part || '').trim()).filter(Boolean);
        if (!parts.length || parts.some((part) => !/^[0-9a-f]{1,6}$/.test(part))) return '';
