    function __tmGetCalendarDocsToGroupMapSync() {
        const cachedMap = window.__tmCalendarDocsToGroupCache?.map;
        if (cachedMap instanceof Map) return new Map(cachedMap);
        const docsToGroup = new Map();
        try {
            const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
            groups.forEach((g) => {
                const gid = String(g?.id || '').trim();
                const docs = __tmNormalizeGroupDocEntries(g);
                if (!gid) return;
                docs.forEach((d) => {
                    const did = String((typeof d === 'object' ? d?.id : d) || '').trim();
                    if (!did) return;
                    if (!docsToGroup.has(did)) docsToGroup.set(did, gid);
                });
            });
        } catch (e) {}
        return docsToGroup;
    }

    function __tmFlattenCalendarTaskTreeSync() {
        const out = [];
        const seen = new Set();
        const walk = (tasks) => {
            const list = Array.isArray(tasks)
                ? tasks.slice().sort((a, b) => {
                    try { return __tmCompareTasksByDocFlow(a, b); } catch (e) { return 0; }
                })
                : [];
            list.forEach((task) => {
                if (!task || typeof task !== 'object') return;
                const id = String(task?.id || '').trim();
                if (!id || seen.has(id)) return;
                seen.add(id);
                out.push(task);
                if (Array.isArray(task?.children) && task.children.length > 0) walk(task.children);
            });
        };
        (Array.isArray(state.taskTree) ? state.taskTree : []).forEach((doc) => walk(doc?.tasks || []));
        return out;
    }

    function __tmGetCalendarTaskCandidatesSync() {
        const docsToGroup = __tmGetCalendarDocsToGroupMapSync();

        const pickFrom = (source) => {
            const list = Array.isArray(source) ? source : [];
            const out = [];
            const seen = new Set();
            list.forEach((task) => {
                if (!task || typeof task !== 'object') return;
                const id = String(task?.id || '').trim();
                if (!id || seen.has(id)) return;
                seen.add(id);
                out.push(task);
            });
            return out;
        };

        const filteredTasks = pickFrom(state.filteredTasks);
        if (filteredTasks.length > 0) return { tasks: filteredTasks, docsToGroup };

        const treeTasks = pickFrom(__tmFlattenCalendarTaskTreeSync());
        if (treeTasks.length > 0) return { tasks: treeTasks, docsToGroup };

        const cachedTasks = pickFrom(window.__tmCalendarAllTasksCache?.tasks);
        if (cachedTasks.length > 0) return { tasks: cachedTasks, docsToGroup };

        const flatTasks = pickFrom(
            (state.flatTasks && typeof state.flatTasks === 'object')
                ? Object.values(state.flatTasks).sort((a, b) => {
                    try { return __tmCompareTasksByDocFlow(a, b); } catch (e) { return 0; }
                })
                : []
        );
        return { tasks: flatTasks, docsToGroup };
    }

    let __tmCalendarTaskCacheWarmPromise = null;

    async function __tmLoadAllTasksForCalendarCache(options = {}) {
        const opts = (options && typeof options === 'object') ? options : {};
        const limit = Number.isFinite(Number(SettingsStore.data.queryLimit)) ? Number(SettingsStore.data.queryLimit) : 2000;
        const allDocIds = await resolveDocIdsFromGroups({
            groupId: 'all',
            includeQuickAddDoc: true,
            forceRefreshScope: opts.forceRefreshScope === true,
        });
        const docKey = allDocIds.slice().sort().join(',');
        const key = `${limit}|${docKey}`;
        const maxAgeMs = Number.isFinite(Number(opts.maxAgeMs)) ? Math.max(0, Math.floor(Number(opts.maxAgeMs))) : 8000;
        const prev = window.__tmCalendarAllTasksCache;
        if (!opts.force && prev && prev.key === key && Array.isArray(prev.tasks) && (Date.now() - (Number(prev.ts) || 0) < maxAgeMs)) {
            return prev.tasks;
        }
        if (!allDocIds.length) {
            window.__tmCalendarAllTasksCache = { key, ts: Date.now(), tasks: [] };
            return [];
        }
        try { await MetaStore.load?.(); } catch (e) {}
        const res = await API.getTasksByDocuments(allDocIds, limit, { doneOnly: false });
        const tasks = Array.isArray(res?.tasks) ? res.tasks : [];
        const out = [];
        for (const task of tasks) {
            if (!task || typeof task !== 'object') continue;
            const prevTask = state.flatTasks?.[String(task.id || '').trim()];
            let parsedDone = !!task.done;
            try {
                const parsed = API.parseTaskStatus(task.markdown);
                parsedDone = !!parsed.done;
                task.done = parsedDone;
                task.content = parsed.content;
            } catch (e) {}
            try { MetaStore.applyToTask?.(task); } catch (e) {}
            try { __tmMergeVisibleDateFieldsFromPrevTask(task, prevTask); } catch (e) {}
            task.done = parsedDone;
            try { normalizeTaskFields(task, task.docName || '未命名文档'); } catch (e) {}
            out.push(task);
        }
        window.__tmCalendarAllTasksCache = { key, ts: Date.now(), tasks: out };
        return out;
    }

    function __tmCalendarTaskCacheIsFresh(maxAgeMs = 8000) {
        const prev = window.__tmCalendarAllTasksCache;
        if (!prev || !Array.isArray(prev.tasks)) return false;
        return (Date.now() - (Number(prev.ts) || 0)) < maxAgeMs;
    }

    window.tmEnsureCalendarTaskCache = async function(options) {
        if (__tmCalendarTaskCacheWarmPromise) return __tmCalendarTaskCacheWarmPromise;
        const opts = (options && typeof options === 'object') ? options : {};
        const run = Promise.resolve().then(async () => {
            try { await window.tmCalendarWarmDocsToGroupCache?.(); } catch (e) {}
            const tasks = await __tmLoadAllTasksForCalendarCache(opts);
            if (opts.refresh !== false) {
                try { globalThis.__tmCalendar?.refreshInPlace?.({ hard: false }); } catch (e) {}
            }
            return tasks;
        });
        let tracked = null;
        tracked = run.finally(() => {
            if (__tmCalendarTaskCacheWarmPromise === tracked) __tmCalendarTaskCacheWarmPromise = null;
        });
        __tmCalendarTaskCacheWarmPromise = tracked;
        return tracked;
    };

    window.tmWarmCalendarTaskCacheIfStale = function(options) {
        const opts = (options && typeof options === 'object') ? options : {};
        const maxAgeMs = Number.isFinite(Number(opts.maxAgeMs)) ? Math.max(0, Math.floor(Number(opts.maxAgeMs))) : 8000;
        if (__tmCalendarTaskCacheWarmPromise) return false;
        if (__tmCalendarTaskCacheIsFresh(maxAgeMs)) return false;
        try {
            Promise.resolve().then(() => window.tmEnsureCalendarTaskCache?.(opts)).catch(() => null);
            return true;
        } catch (e) {
            return false;
        }
    };

    function __tmBuildCalendarTaskRowsSync(limit = 0) {
        const hasLimit = Number.isFinite(Number(limit)) && Number(limit) > 0;
        const max = hasLimit ? Math.max(1, Math.min(500, Math.floor(Number(limit)))) : Number.POSITIVE_INFINITY;
        const { tasks, docsToGroup } = __tmGetCalendarTaskCandidatesSync();
        const map = new Map(tasks.map((t) => [String(t?.id || '').trim(), t]).filter(([k]) => !!k));
        const depthMemo = new Map();
        const getDepth = (id) => {
            const tid = String(id || '').trim();
            if (!tid) return 0;
            if (depthMemo.has(tid)) return depthMemo.get(tid);
            const task = map.get(tid);
            if (!task) return 0;
            const pid = String(task.parentTaskId || '').trim();
            const depth = pid ? Math.min(20, getDepth(pid) + 1) : 0;
            depthMemo.set(tid, depth);
            return depth;
        };

        const out = [];
        for (const task of tasks) {
            if (!task || task.done) continue;
            const id = String(task.id || '').trim();
            if (!id) continue;
            const title = String(task.content || '').trim() || '(无标题)';
            const docId = String(task.root_id || '').trim();
            const gid = docId ? docsToGroup.get(docId) : '';
            const calendarId = gid ? `group:${gid}` : 'default';
            out.push({
                id,
                task,
                title,
                duration: String(task?.duration || '').trim(),
                spent: __tmGetTaskSpentDisplay(task),
                calendarId,
                depth: getDepth(id),
            });
            if (out.length >= max) break;
        }
        return out;
    }

    function __tmBuildCalendarTaskTableFallbackHtml() {
        const colOrder = Array.isArray(SettingsStore.data.columnOrder) && SettingsStore.data.columnOrder.length
            ? SettingsStore.data.columnOrder
            : ['content', 'duration', 'spent'];
        const widths = SettingsStore.data.columnWidths || SettingsStore.data.calendarColumnWidths || {};
        const tableLayout = __tmGetTableWidthLayout(colOrder, widths, state.tableAvailableWidth);
        const headers = {
            content: `<th data-col="content" style="${tableLayout.cellStyle('content', 'white-space: nowrap; overflow: hidden;')}">任务内容<span class="tm-col-resize" onmousedown="startColResize(event, 'content')"></span></th>`,
            duration: `<th data-col="duration" style="${tableLayout.cellStyle('duration', 'white-space: nowrap; overflow: hidden;')}">时长<span class="tm-col-resize" onmousedown="startColResize(event, 'duration')"></span></th>`,
            spent: `<th data-col="spent" style="${tableLayout.cellStyle('spent', 'text-align: center; white-space: nowrap; overflow: hidden;')}">耗时<span class="tm-col-resize" onmousedown="startColResize(event, 'spent')"></span></th>`,
        };
        const rows = __tmBuildCalendarTaskRowsSync(300);
        const tbody = rows.length
            ? rows.map((item) => {
                let contentHtml = '';
                try {
                    contentHtml = API.renderTaskContentHtml(item.task?.markdown, item.title);
                } catch (e) {
                    contentHtml = esc(item.title);
                }
                const depthPad = 8 + Math.min(6, Math.max(0, Number(item.depth) || 0)) * 14;
                return `
                    <tr data-id="${esc(item.id)}" data-calendar-id="${esc(item.calendarId)}">
                        <td style="${tableLayout.cellStyle('content')}">
                            <div class="tm-task-cell" style="padding-left:${depthPad}px;">
                                <span class="tm-task-text">
                                    <span class="tm-task-content-clickable"${__tmBuildTooltipAttrs(String(item.title || '').trim() || '(无内容)', { side: 'bottom', ariaLabel: false })}>${contentHtml}</span>
                                </span>
                            </div>
                        </td>
                        <td class="tm-task-meta-cell" style="${tableLayout.cellStyle('duration')}">${esc(item.duration || '')}</td>
                        <td class="tm-task-meta-cell" style="${tableLayout.cellStyle('spent', 'text-align: center; font-variant-numeric: inherit;')}">${esc(item.spent || '')}</td>
                    </tr>
                `;
            }).join('')
            : `<tr><td colspan="${Math.max(1, colOrder.length || 3)}" style="text-align: center; padding: 40px; color: var(--tm-secondary-text);">暂无任务</td></tr>`;
        const thead = colOrder.map((col) => headers[col] || '').join('');
        return `
            <div class="tm-calendar-task-list" style="height:100%; display:flex; flex-direction:column;">
                <table class="tm-table" id="tmTaskTable" data-tm-table="calendar" style="${tableLayout.tableStyle}">
                    <thead><tr>${thead}</tr></thead>
                    <tbody>${tbody}</tbody>
                </table>
            </div>
        `;
    }

    window.tmGetCalendarDragTasks = function(limit) {
        const max = Number.isFinite(Number(limit)) ? Math.max(1, Math.min(500, Math.floor(Number(limit)))) : 200;
        const { tasks, docsToGroup } = __tmGetCalendarTaskCandidatesSync();

        const mode = String(SettingsStore.data.tomatoSpentAttrMode || 'minutes').trim() || 'minutes';
        const useHours = !!(SettingsStore.data.enableTomatoIntegration && mode === 'hours');

        const out = [];
        for (const t of tasks) {
            if (!t) continue;
            if (t.done) continue;
            const id = String(t.id || '').trim();
            if (!id) continue;
            const title = String(t.content || '').trim();
            const docId = String(t.root_id || '').trim();
            const gid = docId ? docsToGroup.get(docId) : '';
            const calendarId = gid ? `group:${gid}` : 'default';

            const mins = __tmParseDurationMinutes(t?.duration);
            const durationMin = (Number.isFinite(Number(mins)) && Number(mins) > 0) ? Math.round(Number(mins)) : 60;

            let spent = '';
            try {
                if (useHours) spent = __tmFormatSpentHours(__tmParseNumber(t?.tomatoHours)) || '';
                else spent = __tmFormatSpentMinutes(__tmGetTaskSpentMinutes(t)) || '';
            } catch (e) {}

            out.push({ id, title: title || '(无标题)', spent, durationMin, calendarId });
            if (out.length >= max) break;
        }
        return out;
    };

    window.tmQueryCalendarTasks = function(params) {
        const p = (params && typeof params === 'object') ? params : {};
        const size = Number.isFinite(Number(p.pageSize)) ? Math.max(20, Math.min(500, Math.floor(Number(p.pageSize)))) : 200;
        const page = Number.isFinite(Number(p.page)) ? Math.max(1, Math.floor(Number(p.page))) : 1;
        const q = String(p.query || '').trim().toLowerCase();

        const { tasks, docsToGroup } = __tmGetCalendarTaskCandidatesSync();
        const map = new Map(tasks.map((t) => [String(t?.id || '').trim(), t]).filter(([k]) => !!k));
        const childSet = new Set();
        for (const t of tasks) {
            const pid = String(t?.parentTaskId || '').trim();
            if (pid) childSet.add(pid);
        }
        const depthMemo = new Map();
        const getDepth = (id) => {
            if (!id) return 0;
            if (depthMemo.has(id)) return depthMemo.get(id);
            const t = map.get(id);
            if (!t) return 0;
            const pid = String(t.parentTaskId || '').trim();
            const d = pid ? Math.min(20, getDepth(pid) + 1) : 0;
            depthMemo.set(id, d);
            return d;
        };

        const mode = String(SettingsStore.data.tomatoSpentAttrMode || 'minutes').trim() || 'minutes';
        const useHours = !!(SettingsStore.data.enableTomatoIntegration && mode === 'hours');

        const all = [];
        for (const t of tasks) {
            if (!t) continue;
            if (t.done) continue;
            const id = String(t.id || '').trim();
            if (!id) continue;
            const title = String(t.content || '').trim() || '(无标题)';
            if (q && !title.toLowerCase().includes(q)) continue;
            const docId = String(t.root_id || '').trim();
            const gid = docId ? docsToGroup.get(docId) : '';
            const calendarId = gid ? `group:${gid}` : 'default';

            const mins = __tmParseDurationMinutes(t?.duration);
            const durationMin = (Number.isFinite(Number(mins)) && Number(mins) > 0) ? Math.round(Number(mins)) : 60;

            let spent = '';
            try {
                if (useHours) spent = __tmFormatSpentHours(__tmParseNumber(t?.tomatoHours)) || '';
                else spent = __tmFormatSpentMinutes(__tmGetTaskSpentMinutes(t)) || '';
            } catch (e) {}

            all.push({
                id,
                title,
                spent,
                durationMin,
                calendarId,
                depth: getDepth(id),
                hasChildren: childSet.has(id),
            });
        }

        const total = all.length;
        if (total === 0) {
            try { window.tmWarmCalendarTaskCacheIfStale?.({ refresh: true }); } catch (e) {}
        }
        const start = (page - 1) * size;
        const items = all.slice(start, start + size);
        return { total, page, pageSize: size, items };
    };

    window.tmQueryCalendarTaskDateEvents = async function(rangeStart, rangeEnd) {
        const startKey = __tmNormalizeDateOnly(rangeStart);
        const endKey = __tmNormalizeDateOnly(rangeEnd);
        const toTs = (k) => {
            const kk = String(k || '').trim();
            if (!kk) return 0;
            const d = new Date(`${kk}T12:00:00`);
            return Number.isNaN(d.getTime()) ? 0 : d.getTime();
        };
        const rangeStartTs = toTs(startKey) || 0;
        const rangeEndTs = toTs(endKey) || 0;

        const getAllDocIdsForCalendar = async () => {
            const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
            const legacyIds = Array.isArray(SettingsStore.data.selectedDocIds) ? SettingsStore.data.selectedDocIds : [];
            const quickAddDocId = String(SettingsStore.data.newTaskDocId || '').trim();
            const targetDocs = [];
            legacyIds.forEach((id) => {
                const did = String(id || '').trim();
                if (did) targetDocs.push({ id: did, kind: 'doc', recursive: false });
            });
            groups.forEach((g) => {
                targetDocs.push(...__tmGetGroupSourceEntries(g));
            });
            const finalIds = new Set();
            if (quickAddDocId && quickAddDocId !== '__dailyNote__') finalIds.add(quickAddDocId);
            await Promise.all(targetDocs.map((doc) => __tmExpandSourceEntryDocIds(doc, (sid) => {
                const s = String(sid || '').trim();
                if (s) finalIds.add(s);
            })));
            return Array.from(finalIds);
        };

        const getAllTasksForCalendar = async () => {
            const limit = Number.isFinite(Number(SettingsStore.data.queryLimit)) ? Number(SettingsStore.data.queryLimit) : 2000;
            const allDocIds = await getAllDocIdsForCalendar();
            const docKey = allDocIds.slice().sort().join(',');
            const key = `${limit}|${docKey}`;
            const prev = window.__tmCalendarAllTasksCache;
            if (prev && prev.key === key && Array.isArray(prev.tasks) && (Date.now() - (Number(prev.ts) || 0) < 8000)) return prev.tasks;
            try { await MetaStore.load?.(); } catch (e) {}
            const res = await API.getTasksByDocuments(allDocIds, limit, { doneOnly: false });
                const tasks = Array.isArray(res?.tasks) ? res.tasks : [];
                const out = [];
                for (const task of tasks) {
                    if (!task || typeof task !== 'object') continue;
                    const prevTask = state.flatTasks?.[String(task.id || '').trim()];
                    let parsedDone = !!task.done;
                    try {
                        const parsed = API.parseTaskStatus(task.markdown);
                        parsedDone = !!parsed.done;
                        task.done = parsedDone;
                        task.content = parsed.content;
                    } catch (e) {}
                try { MetaStore.applyToTask?.(task); } catch (e) {}
                try { __tmMergeVisibleDateFieldsFromPrevTask(task, prevTask); } catch (e) {}
                task.done = parsedDone; // 以文档中的真实复选框状态为准
                try { normalizeTaskFields(task, task.docName || '未命名文档'); } catch (e) {}
                out.push(task);
            }
            window.__tmCalendarAllTasksCache = { key, ts: Date.now(), tasks: out };
            return out;
        };

        const getDocsToGroupMap = async () => {
            const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
            const parts = [];
            for (const g of groups) {
                const gid = String(g?.id || '').trim();
                if (!gid) continue;
                const ds = __tmGetGroupSourceEntries(g).map((d) => {
                    const did = String(d?.id || '').trim();
                    if (!did) return '';
                    return did + (d.kind === 'notebook' ? '#nb' : (d.recursive ? '*' : ''));
                }).filter(Boolean);
                parts.push(`${gid}:${ds.join(',')}`);
            }
            const key = parts.join('|');
            const prev = window.__tmCalendarDocsToGroupCache;
            if (prev && prev.key === key && prev.map instanceof Map) return prev.map;

            const map = new Map();
            for (const g of groups) {
                const gid = String(g?.id || '').trim();
                if (!gid) continue;
                const entries = __tmGetGroupSourceEntries(g);
                for (const entry of entries) {
                    await __tmExpandSourceEntryDocIds(entry, (did0) => {
                        const did = String(did0 || '').trim();
                        if (!did || map.has(did)) return;
                        map.set(did, gid);
                    });
                }
            }

            window.__tmCalendarDocsToGroupCache = { key, map };
            return map;
        };

        let docsToGroup = new Map();
        try { docsToGroup = await getDocsToGroupMap(); } catch (e) {}

        const nextDay = (k) => {
            const ts = toTs(k);
            if (!ts) return '';
            const d = new Date(ts + 86400000);
            const pad = (n) => String(n).padStart(2, '0');
            return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
        };

        let filtered = [];
        try { filtered = await getAllTasksForCalendar(); } catch (e) { filtered = []; }
        const out = [];
        for (const t of filtered) {
            if (!t) continue;
            if (t.done) continue;
            const id = String(t.id || '').trim();
            if (!id) continue;
            const s0 = __tmNormalizeDateOnly(t?.startDate);
            const e0 = __tmNormalizeDateOnly(t?.completionTime);
            if (!s0 && !e0) continue;
            const milestoneRaw = t?.milestone;
            const isMilestone = typeof milestoneRaw === 'boolean'
                ? milestoneRaw
                : ['1', 'true'].includes(String(milestoneRaw || '').trim().toLowerCase());
            const hasBothDates = !!s0 && !!e0;
            const start = (isMilestone && hasBothDates) ? e0 : (s0 || e0);
            const end = e0 || s0 || start;
            const startTs = toTs(start);
            const endExKey = nextDay(end);
            const endExTs = toTs(endExKey);
            if (rangeStartTs && endExTs && endExTs <= rangeStartTs) continue;
            if (rangeEndTs && startTs && startTs >= rangeEndTs) continue;

            const title = String(t.content || '').trim() || '(无标题)';
            const docId = String(t.root_id || '').trim();
            const gid = docId ? docsToGroup.get(docId) : '';
            const calendarId = gid ? `group:${gid}` : 'default';
            out.push({
                id,
                title,
                start,
                endExclusive: endExKey || nextDay(start),
                calendarId,
                docId,
                sourceStart: s0 || '',
                sourceCompletion: e0 || '',
                milestone: isMilestone,
            });
        }
        return out;
    };

    window.tmRenderCalendarTaskTableHtml = function() {
        const originalOrder = SettingsStore.data.columnOrder;
        const originalWidths = SettingsStore.data.columnWidths;
        const originalTableAvailableWidth = state.tableAvailableWidth;
        const originalFilteredTasks = state.filteredTasks;
        let patchedFilteredTasks = false;
        try {
            // Ensure calendarColumnWidths is initialized with defaults if missing or empty
            if (!SettingsStore.data.calendarColumnWidths || Object.keys(SettingsStore.data.calendarColumnWidths).length === 0) {
                SettingsStore.data.calendarColumnWidths = { content: 140, duration: 60, spent: 60 };
            }
            if (!(Array.isArray(state.filteredTasks) && state.filteredTasks.length > 0)) {
                const fallbackTasks = __tmGetCalendarTaskCandidatesSync().tasks;
                if (Array.isArray(fallbackTasks) && fallbackTasks.length > 0) {
                    state.filteredTasks = fallbackTasks;
                    patchedFilteredTasks = true;
                } else {
                    try { window.tmWarmCalendarTaskCacheIfStale?.({ refresh: true }); } catch (e) {}
                }
            }
            
            SettingsStore.data.columnOrder = ['content', 'duration', 'spent'];
            SettingsStore.data.columnWidths = SettingsStore.data.calendarColumnWidths;

            const colOrder = SettingsStore.data.columnOrder;
            const widths = SettingsStore.data.columnWidths || {};
            const tableFillColumns = SettingsStore.data.kanbanFillColumns === true;
            const tableAvailableWidth = tableFillColumns ? (() => {
                const values = [];
                try {
                    const el = state.modal?.querySelector?.('.tm-body.tm-body--calendar');
                    if (el) values.push(Number(el.clientWidth) || 0);
                } catch (e) {}
                try {
                    const root = __tmGetMountRoot?.();
                    if (root instanceof Element && root !== document.body && root !== document.documentElement) {
                        values.push(Number(root.clientWidth) || 0);
                    }
                } catch (e) {}
                try {
                    const vw = Number(window.innerWidth || document.documentElement?.clientWidth || 0);
                    if (vw > 0) values.push(Math.max(0, vw - 48));
                } catch (e) {}
                return values.find((n) => Number.isFinite(n) && n > 0) || 0;
            })() : 0;
            state.tableAvailableWidth = tableAvailableWidth;
            const tableLayout = __tmGetTableWidthLayout(colOrder, widths, tableAvailableWidth);
            const headers = {
                content: `<th data-col="content" style="${tableLayout.cellStyle('content', 'white-space: nowrap; overflow: hidden;')}">任务内容<span class="tm-col-resize" onmousedown="startColResize(event, 'content')"></span></th>`,
                duration: `<th data-col="duration" style="${tableLayout.cellStyle('duration', 'white-space: nowrap; overflow: hidden;')}">时长<span class="tm-col-resize" onmousedown="startColResize(event, 'duration')"></span></th>`,
                spent: `<th data-col="spent" style="${tableLayout.cellStyle('spent', 'text-align: center; white-space: nowrap; overflow: hidden;')}">耗时<span class="tm-col-resize" onmousedown="startColResize(event, 'spent')"></span></th>`,
            };
            const thead = colOrder.map((col) => headers[col] || __tmBuildTableHeaderCellHtml(col, tableLayout)).join('');
            return `
                <div class="tm-calendar-task-list" style="height:100%; display:flex; flex-direction:column;">
                    <table class="tm-table" id="tmTaskTable" data-tm-table="calendar" style="${tableLayout.tableStyle}">
                        <thead><tr>${thead}</tr></thead>
                        <tbody>${renderTaskList()}</tbody>
                    </table>
                </div>
            `;
        } catch (e) {
            try { console.error('[tmRenderCalendarTaskTableHtml] render failed', e); } catch (e2) {}
            try { return __tmBuildCalendarTaskTableFallbackHtml(); } catch (e2) {}
            return '';
        } finally {
            if (patchedFilteredTasks) state.filteredTasks = originalFilteredTasks;
            state.tableAvailableWidth = originalTableAvailableWidth;
            SettingsStore.data.columnOrder = originalOrder;
            SettingsStore.data.columnWidths = originalWidths;
        }
    };

    window.tmCalendarApplyCollapseDom = function() {
        try { __tmApplyVisibilityFromState(state.modal); } catch (e) {}
    };

    window.tmCalendarGetTaskDragMeta = function(id) {
        const tid = String(id || '').trim();
        if (!tid) return null;
        const t = state.flatTasks?.[tid] || null;
        if (!t) return null;

        const buildDocsToGroupKey = () => {
            const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
            const parts = [];
            for (const g of groups) {
                const gid = String(g?.id || '').trim();
                if (!gid) continue;
                const ds = __tmGetGroupSourceEntries(g).map((d) => {
                    const did = String(d?.id || '').trim();
                    if (!did) return '';
                    return did + (d.kind === 'notebook' ? '#nb' : (d.recursive ? '*' : ''));
                }).filter(Boolean);
                parts.push(`${gid}:${ds.join(',')}`);
            }
            return parts.join('|');
        };

        const key = buildDocsToGroupKey();
        let docsToGroup = null;
        const cached = window.__tmCalendarDocsToGroupCache;
        if (cached && cached.key === key && cached.map instanceof Map) {
            docsToGroup = cached.map;
        } else {
            docsToGroup = new Map();
            try {
                const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
                groups.forEach((g) => {
                    const gid = String(g?.id || '').trim();
                    const docs = __tmNormalizeGroupDocEntries(g);
                    if (!gid) return;
                    docs.forEach((d) => {
                        const did = String((typeof d === 'object' ? d?.id : d) || '').trim();
                        if (!did) return;
                        if (!docsToGroup.has(did)) docsToGroup.set(did, gid);
                    });
                });
            } catch (e) {}
            try { Promise.resolve().then(() => window.tmCalendarWarmDocsToGroupCache?.()).catch(() => null); } catch (e) {}
        }
        const docId = String(t.root_id || t.docId || '').trim();
        let gid = docId ? String(docsToGroup.get(docId) || '').trim() : '';
        if (!gid && docId) {
            try {
                const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
                for (const g of groups) {
                    const gId = String(g?.id || '').trim();
                    if (!gId) continue;
                    const docs = __tmNormalizeGroupDocEntries(g);
                    const hit = docs.some((d) => String((typeof d === 'object' ? d?.id : d) || '').trim() === docId);
                    if (hit) {
                        gid = gId;
                        break;
                    }
                }
            } catch (e) {}
        }
        const calendarId = gid ? `group:${gid}` : 'default';

        const mins = __tmParseDurationMinutes(t?.duration);
        const durationMin = (Number.isFinite(Number(mins)) && Number(mins) > 0) ? Math.round(Number(mins)) : 60;
        const title = String(t.content || '').trim() || '(无标题)';
        return {
            title,
            durationMin,
            calendarId,
            startDate: String(t.startDate || '').trim(),
            completionTime: String(t.completionTime || '').trim(),
        };
    };

    function __tmCalendarFloatingDragDetach() {
        const cleanup = state.__tmCalendarFloatingDragCleanup;
        if (typeof cleanup !== 'function') return;
        try { cleanup(); } catch (e) {}
        state.__tmCalendarFloatingDragCleanup = null;
    }

    function __tmShouldSuppressCalendarFloatingMiniPanel() {
        const viewMode = String(state.viewMode || '').trim();
        if (viewMode !== 'calendar') return false;
        return __tmIsRuntimeMobileClient() || __tmHostUsesMobileUI();
    }

    function __tmCalendarFloatingDragStart(taskId, meta, ev, opts = {}) {
        if (__tmShouldSuppressCalendarFloatingMiniPanel()) return false;
        const id = String(taskId || '').trim();
        if (!id) return false;
        const calendar = globalThis.__tmCalendar;
        if (!calendar || typeof calendar.showFloatingMiniCalendar !== 'function') return false;
        const options = (opts && typeof opts === 'object') ? opts : {};
        const nextMeta = (meta && typeof meta === 'object') ? meta : (
            (typeof window.tmCalendarGetTaskDragMeta === 'function')
                ? window.tmCalendarGetTaskDragMeta(id)
                : null
        );
        let shown = false;
        try {
            shown = !!calendar.showFloatingMiniCalendar({
                taskId: id,
                meta: nextMeta,
                dragPayload: nextMeta,
                clientX: Number(ev?.clientX),
                clientY: Number(ev?.clientY),
                mode: options.mode,
                containerRect: options.containerRect,
            });
        } catch (e) {}
        if (!shown) return false;
        if (options.html5 === false) return true;
        __tmCalendarFloatingDragDetach();
        const onDocDragOver = (e2) => {
            try {
                calendar.updateFloatingMiniCalendarDrag?.({
                    clientX: Number(e2?.clientX),
                    clientY: Number(e2?.clientY),
                    target: e2?.target,
                });
            } catch (e3) {}
        };
        const onDocDragEnd = () => {
            __tmCalendarFloatingDragEnd();
        };
        try { document.addEventListener('dragover', onDocDragOver, true); } catch (e) {}
        try { document.addEventListener('dragend', onDocDragEnd, true); } catch (e) {}
        state.__tmCalendarFloatingDragCleanup = () => {
            try { document.removeEventListener('dragover', onDocDragOver, true); } catch (e2) {}
            try { document.removeEventListener('dragend', onDocDragEnd, true); } catch (e2) {}
        };
        return true;
    }

    function __tmCalendarFloatingDragMove(ev, opts = {}) {
        if (__tmShouldSuppressCalendarFloatingMiniPanel()) return null;
        const calendar = globalThis.__tmCalendar;
        if (!calendar || typeof calendar.updateFloatingMiniCalendarDrag !== 'function') return null;
        const options = (opts && typeof opts === 'object') ? opts : {};
        try {
            return calendar.updateFloatingMiniCalendarDrag({
                clientX: Number(ev?.clientX),
                clientY: Number(ev?.clientY),
                target: ev?.target,
                mode: options.mode,
            });
        } catch (e) {
            return null;
        }
    }

    function __tmCalendarFloatingDragEnd() {
        __tmCalendarFloatingDragDetach();
        try { globalThis.__tmCalendar?.hideFloatingMiniCalendar?.(); } catch (e) {}
    }

    window.tmCalendarGetDraggingTaskId = function() {
        return String(state.draggingTaskId || '').trim();
    };

    window.tmIsTaskDone = function(id) {
        const tid = String(id || '').trim();
        if (!tid) return false;
        try {
            if (state.doneOverrides && Object.prototype.hasOwnProperty.call(state.doneOverrides, tid)) {
                return !!state.doneOverrides[tid];
            }
        } catch (e) {}
        const t = state.flatTasks?.[tid] || null;
        return !!(t && t.done);
    };

    window.tmUpdateTaskDates = async function(taskId, patch = {}, options = {}) {
        const requestedId = String(taskId || '').trim();
        if (!requestedId) throw new Error('缺少任务 ID');
        const nextPatch = (patch && typeof patch === 'object') ? patch : {};
        const opts = (options && typeof options === 'object') ? options : {};
        const hasStartDate = Object.prototype.hasOwnProperty.call(nextPatch, 'startDate');
        const hasCompletionTime = Object.prototype.hasOwnProperty.call(nextPatch, 'completionTime');
        if (!hasStartDate && !hasCompletionTime) throw new Error('缺少日期字段');
        let resolvedId = requestedId;
        let task = state.flatTasks?.[requestedId] || null;
        if (!task) {
            try {
                const nextResolved = await __tmResolveTaskIdFromAnyBlockId(requestedId);
                if (nextResolved) resolvedId = String(nextResolved || '').trim() || requestedId;
            } catch (e) {}
        }
        if (!task && resolvedId && resolvedId !== requestedId) {
            task = state.flatTasks?.[resolvedId] || null;
        }
        if (!task) {
            try { task = await __tmEnsureTaskInStateById(resolvedId || requestedId); } catch (e) { task = null; }
        }
        if (!task && resolvedId && resolvedId !== requestedId) {
            try { task = await __tmBuildTaskLikeFromBlockId(resolvedId); } catch (e) { task = null; }
        }
        if (!task) {
            try { task = await __tmBuildTaskLikeFromBlockId(requestedId); } catch (e) { task = null; }
        }
        const persistId = String(task?.id || resolvedId || requestedId).trim();
        if (!persistId) throw new Error('未找到任务');

        const normalizeDate = (value) => {
            const raw = String(value || '').trim();
            if (!raw) return '';
            try { return __tmNormalizeDateOnly(raw); } catch (e) { return raw; }
        };

        const prevStart = String(task?.startDate || '').trim();
        const prevEnd = String(task?.completionTime || '').trim();
        let nextStart = hasStartDate ? normalizeDate(nextPatch.startDate) : prevStart;
        let nextEnd = hasCompletionTime ? normalizeDate(nextPatch.completionTime) : prevEnd;

        if (nextStart && nextEnd && nextStart > nextEnd) {
            if (hasStartDate && hasCompletionTime) nextEnd = nextStart;
            else if (hasStartDate) nextEnd = nextStart;
            else nextStart = nextEnd;
        }

        const attrPatch = {};
        if (hasStartDate) attrPatch.startDate = nextStart;
        if (hasCompletionTime) attrPatch.completionTime = nextEnd;
        const repeatRule = __tmNormalizeTaskRepeatRule(task?.repeatRule || task?.repeat_rule || '', {
            startDate: nextStart || prevStart,
            completionTime: nextEnd || prevEnd,
        });
        if (repeatRule.enabled) {
            attrPatch.repeatState = __tmNormalizeTaskRepeatState({
                ...(task?.repeatState && typeof task.repeatState === 'object' ? task.repeatState : {}),
                lastInstanceStart: nextStart,
                lastInstanceDue: nextEnd,
            });
        }

        await __tmApplyTaskMetaPatchWithUndo(persistId, attrPatch, {
            source: 'calendar-dates',
            label: __tmBuildUndoLabelFromMetaPatch(attrPatch, '日期'),
            refresh: opts.refresh !== false,
            refreshCalendar: true,
            withFilters: true,
            hard: opts.hard === true,
        });
        return {
            id: persistId,
            startDate: nextStart,
            completionTime: nextEnd,
        };
    };

    function __tmGetTaskRepeatRule(taskLike, options = {}) {
        const task = (taskLike && typeof taskLike === 'object') ? taskLike : {};
        return __tmNormalizeTaskRepeatRule(task.repeatRule || task.repeat_rule || '', {
            startDate: task?.startDate,
            completionTime: task?.completionTime,
            ...((options && typeof options === 'object') ? options : {}),
        });
    }

    async function __tmResolveTaskForRepeat(taskId) {
        const requestedId = String(taskId || '').trim();
        if (!requestedId) return null;
        let task = state.flatTasks?.[requestedId] || state.pendingInsertedTasks?.[requestedId] || null;
        if (!task) {
            try { task = await __tmEnsureTaskInStateById(requestedId); } catch (e) { task = null; }
        }
        if (!task) {
            try { task = await __tmBuildTaskLikeFromBlockId(requestedId); } catch (e) { task = null; }
        }
        if (!task) return null;
        try { MetaStore.applyToTask(task); } catch (e) {}
        try { normalizeTaskFields(task, String(task.doc_name || task.docName || '').trim()); } catch (e) {}
        return task;
    }

    async function __tmApplyTaskRepeatRule(taskId, ruleInput, options = {}) {
        const task = await __tmResolveTaskForRepeat(taskId);
        if (!task?.id) throw new Error('未找到任务');
        const opts = (options && typeof options === 'object') ? options : {};
        const nextRule = __tmNormalizeTaskRepeatRule(ruleInput, {
            startDate: task?.startDate,
            completionTime: task?.completionTime,
        });
        const nextState = __tmNormalizeTaskRepeatState({
            ...(task?.repeatState && typeof task.repeatState === 'object' ? task.repeatState : {}),
            lastInstanceStart: __tmNormalizeDateOnly(task?.startDate || ''),
            lastInstanceDue: __tmNormalizeDateOnly(task?.completionTime || ''),
        });
        const patch = {
            repeatRule: nextRule,
            repeatState: nextState,
        };
        const result = await __tmApplyTaskMetaPatchWithUndo(task.id, patch, {
            source: String(opts.source || 'task-repeat').trim() || 'task-repeat',
            label: '循环规则',
            refresh: opts.refresh !== false,
            refreshCalendar: opts.refreshCalendar !== false,
            withFilters: opts.withFilters !== false,
            hard: opts.hard === true,
            recordUndo: opts.recordUndo !== false,
        });
        return {
            ...result,
            rule: nextRule,
            state: nextState,
            summary: __tmGetTaskRepeatSummary(nextRule, {
                startDate: task?.startDate,
                completionTime: task?.completionTime,
            }),
        };
    }

    async function __tmDeleteTaskRepeatHistoryEntry(taskId, completedAt, options = {}) {
        const task = await __tmResolveTaskForRepeat(taskId);
        if (!task?.id) throw new Error('未找到任务');
        const key = String(completedAt || '').trim();
        const currentHistory = __tmNormalizeTaskRepeatHistory(task?.repeatHistory || task?.repeat_history || '');
        const nextHistory = currentHistory.filter((item) => String(item?.completedAt || '').trim() !== key);
        if (nextHistory.length === currentHistory.length) return false;
        await __tmApplyTaskMetaPatchWithUndo(task.id, {
            repeatHistory: nextHistory,
        }, {
            source: String(options?.source || 'task-repeat-history-delete').trim() || 'task-repeat-history-delete',
            label: '删除循环记录',
            refresh: false,
            refreshCalendar: false,
            withFilters: true,
            hard: false,
            recordUndo: options?.recordUndo !== false,
        });
        __tmPurgeRecurringInstanceTasks(task.id, [key]);
        try {
            __tmRefreshViewsAfterTaskMutation({
                refresh: true,
                refreshCalendar: true,
                withFilters: true,
                hard: false,
            });
        } catch (e) {}
        return true;
    }

    const __tmRecurringAdvanceTimers = new Map();

    function __tmClearRecurringTaskAdvanceTimer(taskId) {
        const tid = String(taskId || '').trim();
        if (!tid) return false;
        const timer = __tmRecurringAdvanceTimers.get(tid);
        if (!timer) return false;
        try { clearTimeout(timer); } catch (e) {}
        __tmRecurringAdvanceTimers.delete(tid);
        return true;
    }

    async function __tmAdvanceRecurringTaskAfterCompletion(taskId, options = {}) {
        const opts = (options && typeof options === 'object') ? options : {};
        if (String(opts.source || '').trim() === 'task-repeat-advance') return false;
        const waited = await __tmWaitForGlobalUnlock(12000);
        if (!waited) return false;
        let task = await __tmResolveTaskForRepeat(taskId);
        try {
            const latestTaskId = await __tmResolveTaskIdFromAnyBlockId(String(task?.id || taskId || '').trim());
            if (latestTaskId && latestTaskId !== String(task?.id || '').trim()) {
                const latestTask = await __tmResolveTaskForRepeat(latestTaskId);
                if (latestTask?.id) task = latestTask;
            }
        } catch (e) {}
        if (!task?.id || !task.done) return false;
        const repeatRule = __tmGetTaskRepeatRule(task);
        if (!repeatRule.enabled || repeatRule.trigger !== 'complete' || repeatRule.type === 'none') return false;
        const completedAt = String(opts.completedAt || new Date().toISOString()).trim() || new Date().toISOString();
        const nextPatch = __tmBuildTaskRepeatAdvancePatch(task, repeatRule, { completedAt });
        if (!nextPatch) return false;
        const nextHistory = __tmNormalizeTaskRepeatHistory([
            {
                completedAt,
                sourceStart: __tmNormalizeDateOnly(task?.startDate || ''),
                sourceDue: __tmNormalizeDateOnly(task?.completionTime || ''),
                nextStart: __tmNormalizeDateOnly(nextPatch.startDate || ''),
                nextDue: __tmNormalizeDateOnly(nextPatch.completionTime || ''),
            },
            ...__tmNormalizeTaskRepeatHistory(task?.repeatHistory || task?.repeat_history || ''),
        ]);
        const historyHead = nextHistory[0] || null;
        nextPatch.repeatHistory = nextHistory;
        await __tmApplyTaskMetaPatchWithUndo(task.id, nextPatch, {
            source: 'task-repeat-advance',
            label: '循环推进',
            refresh: false,
            refreshCalendar: false,
            withFilters: true,
            hard: false,
            recordUndo: false,
        });
        try {
            task.startDate = String(nextPatch.startDate || '').trim();
            task.start_date = task.startDate;
            task.completionTime = String(nextPatch.completionTime || '').trim();
            task.completion_time = task.completionTime;
            task.repeatState = __tmNormalizeTaskRepeatState(nextPatch.repeatState);
            task.repeat_state = task.repeatState;
            task.repeatHistory = __tmNormalizeTaskRepeatHistory(nextPatch.repeatHistory);
            task.repeat_history = task.repeatHistory;
            if (state.flatTasks?.[task.id]) state.flatTasks[task.id] = task;
            if (state.pendingInsertedTasks?.[task.id]) {
                state.pendingInsertedTasks[task.id].startDate = task.startDate;
                state.pendingInsertedTasks[task.id].start_date = task.startDate;
                state.pendingInsertedTasks[task.id].completionTime = task.completionTime;
                state.pendingInsertedTasks[task.id].completion_time = task.completionTime;
                state.pendingInsertedTasks[task.id].repeatState = task.repeatState;
                state.pendingInsertedTasks[task.id].repeat_state = task.repeatState;
                state.pendingInsertedTasks[task.id].repeatHistory = task.repeatHistory;
                state.pendingInsertedTasks[task.id].repeat_history = task.repeatHistory;
            }
            try {
                MetaStore.set(task.id, {
                    startDate: task.startDate,
                    completionTime: task.completionTime,
                    repeatState: task.repeatState,
                    repeatHistory: task.repeatHistory,
                });
            } catch (e) {}
        } catch (e) {}
        if (historyHead && String(opts?.scheduleId || '').trim()) {
            try { await __tmReassignCompletedScheduleToRecurringInstance(String(opts.scheduleId || '').trim(), task, historyHead); } catch (e) {}
        }
        let resetTaskId = String(task.id || '').trim();
        try {
            const resolvedResetTaskId = await __tmResolveTaskIdFromAnyBlockId(resetTaskId);
            if (resolvedResetTaskId) resetTaskId = String(resolvedResetTaskId || '').trim() || resetTaskId;
        } catch (e) {}
        if (!resetTaskId) resetTaskId = String(task.id || '').trim();
        let resetDoneOk = false;
        try {
            await __tmSetDoneKernel(resetTaskId, false, null, {
                force: true,
                suppressHint: true,
                source: 'task-repeat-advance',
                recordUndo: false,
            });
        } catch (e) {}
        try {
            const latest = state.flatTasks?.[resetTaskId] || state.flatTasks?.[task.id] || null;
            resetDoneOk = !!latest && latest.done !== true;
        } catch (e) {}
        if (!resetDoneOk) {
            try {
                resetDoneOk = await __tmSetDoneByIdStateless(resetTaskId, false);
            } catch (e) {
                resetDoneOk = false;
            }
            if (resetDoneOk) {
                try { task.done = false; } catch (e) {}
                try {
                    if (state.flatTasks?.[resetTaskId]) state.flatTasks[resetTaskId].done = false;
                    if (state.flatTasks?.[task.id]) state.flatTasks[task.id].done = false;
                } catch (e) {}
                try {
                    if (!state.doneOverrides || typeof state.doneOverrides !== 'object') state.doneOverrides = {};
                    state.doneOverrides[String(resetTaskId || '').trim()] = false;
                    state.doneOverrides[String(task.id || '').trim()] = false;
                } catch (e) {}
                try { MetaStore.set(resetTaskId, { done: false }); } catch (e) {}
                try { MetaStore.set(task.id, { done: false }); } catch (e) {}
            }
        }
        if (!resetDoneOk) {
            try {
                hint('⚠ 循环推进后未能自动取消主任务完成，请手动取消勾选', 'warning');
            } catch (e) {}
            return false;
        }
        try {
            const calendarOnlyRefresh = String(opts?.source || '').trim() === 'calendar'
                && String(state.viewMode || '').trim() === 'calendar';
            __tmRefreshViewsAfterTaskMutation({
                refresh: true,
                refreshCalendar: true,
                withFilters: true,
                hard: false,
                calendarOnly: calendarOnlyRefresh,
            });
        } catch (e) {}
        try {
            const summary = __tmGetTaskRepeatSummary(repeatRule, {
                startDate: nextPatch.startDate,
                completionTime: nextPatch.completionTime,
            });
            hint(`🔁 已推进到下一次${summary ? `：${summary}` : ''}`, 'success');
        } catch (e) {}
        return true;
    }

    function __tmScheduleRecurringTaskAdvanceAfterCompletion(taskId, options = {}) {
        const tid = String(taskId || '').trim();
        if (!tid) return;
        const opts = (options && typeof options === 'object') ? options : {};
        __tmClearRecurringTaskAdvanceTimer(tid);
        try {
            const timer = setTimeout(() => {
                __tmRecurringAdvanceTimers.delete(tid);
                __tmAdvanceRecurringTaskAfterCompletion(tid, opts).catch(() => null);
            }, Math.max(120, Number(opts.delayMs) || 280));
            __tmRecurringAdvanceTimers.set(tid, timer);
        } catch (e) {}
    }

    function __tmBuildTaskRepeatDueAdvancePatch(taskLike, ruleInput, options = {}) {
        const task = (taskLike && typeof taskLike === 'object') ? taskLike : {};
        const rule = __tmNormalizeTaskRepeatRule(ruleInput, {
            startDate: task?.startDate,
            completionTime: task?.completionTime,
        });
        if (!rule.enabled || rule.trigger !== 'due' || rule.type === 'none') return null;
        const todayKey = __tmNormalizeDateOnly(options.todayKey || new Date());
        if (!todayKey) return null;
        let nextTask = {
            ...task,
            startDate: __tmNormalizeDateOnly(task?.startDate || ''),
            completionTime: __tmNormalizeDateOnly(task?.completionTime || ''),
            repeatState: __tmNormalizeTaskRepeatState(task?.repeatState),
        };
        let compareKey = __tmNormalizeDateOnly(nextTask?.completionTime || nextTask?.startDate || '');
        if (!compareKey || compareKey >= todayKey) return null;
        let advancedCount = 0;
        let guard = 0;
        while (compareKey && compareKey < todayKey && guard < 400) {
            const patch = __tmBuildTaskRepeatAdvancePatch(nextTask, rule, {
                advancedAt: String(options.advancedAt || new Date().toISOString()).trim() || new Date().toISOString(),
                completedAt: String(nextTask?.repeatState?.lastCompletedAt || '').trim(),
            });
            if (!patch) break;
            nextTask = {
                ...nextTask,
                startDate: __tmNormalizeDateOnly(patch.startDate || ''),
                completionTime: __tmNormalizeDateOnly(patch.completionTime || ''),
                repeatState: __tmNormalizeTaskRepeatState(patch.repeatState),
            };
            compareKey = __tmNormalizeDateOnly(nextTask?.completionTime || nextTask?.startDate || '');
            advancedCount += 1;
            guard += 1;
        }
        if (!advancedCount) return null;
        return {
            startDate: nextTask.startDate,
            completionTime: nextTask.completionTime,
            repeatState: nextTask.repeatState,
            __advancedCount: advancedCount,
        };
    }

    let __tmRecurringDueReconcilePromise = null;
    async function __tmReconcileRecurringTasksOnLoad(taskIdsInput, options = {}) {
        if (__tmRecurringDueReconcilePromise) return await __tmRecurringDueReconcilePromise;
        const taskIds = Array.from(new Set((Array.isArray(taskIdsInput) ? taskIdsInput : [])
            .map((id) => String(id || '').trim())
            .filter(Boolean)));
        if (!taskIds.length) return 0;
        const opts = (options && typeof options === 'object') ? options : {};
        const job = (async () => {
            let changed = 0;
            const todayKey = __tmNormalizeDateOnly(opts.todayKey || new Date());
            for (const taskId of taskIds) {
                const task = await __tmResolveTaskForRepeat(taskId);
                if (!task?.id || task.done) continue;
                const rule = __tmGetTaskRepeatRule(task);
                if (!rule.enabled || rule.trigger !== 'due' || rule.type === 'none') continue;
                const patch = __tmBuildTaskRepeatDueAdvancePatch(task, rule, { todayKey });
                if (!patch) continue;
                await __tmApplyTaskMetaPatchWithUndo(task.id, patch, {
                    source: 'task-repeat-due',
                    label: '循环推进',
                    refresh: false,
                    refreshCalendar: false,
                    withFilters: true,
                    hard: false,
                    recordUndo: false,
                    broadcast: true,
                });
                changed += 1;
            }
            return changed;
        })();
        __tmRecurringDueReconcilePromise = job;
        try {
            return await job;
        } finally {
            if (__tmRecurringDueReconcilePromise === job) __tmRecurringDueReconcilePromise = null;
        }
    }

    window.tmGetTaskRepeatRule = async function(taskId) {
        const task = await __tmResolveTaskForRepeat(taskId);
        if (!task?.id) return null;
        const rule = __tmGetTaskRepeatRule(task);
        return {
            ...rule,
            summary: __tmGetTaskRepeatSummary(rule, {
                startDate: task?.startDate,
                completionTime: task?.completionTime,
            }),
        };
    };

    window.tmSetTaskRepeatRule = async function(taskId, ruleInput = {}, options = {}) {
        return await __tmApplyTaskRepeatRule(taskId, ruleInput, options);
    };

    window.tmClearTaskRepeatRule = async function(taskId, options = {}) {
        return await __tmApplyTaskRepeatRule(taskId, { enabled: false, type: 'none' }, options);
    };

    window.tmEditTaskRepeatRule = async function(taskId, options = {}) {
        const task = await __tmResolveTaskForRepeat(taskId);
        if (!task?.id) {
            hint('⚠ 未找到任务', 'warning');
            return null;
        }
        const nextRule = await showTaskRepeatRuleDialog(task, {
            title: String(options?.title || '循环设置').trim() || '循环设置',
        });
        if (nextRule === null) return null;
        if (!nextRule.enabled || nextRule.type === 'none') {
            return await window.tmClearTaskRepeatRule(task.id, { source: 'task-repeat-dialog' });
        }
        return await window.tmSetTaskRepeatRule(task.id, {
            ...nextRule,
            anchorDate: task?.completionTime || task?.startDate || __tmNormalizeDateOnly(new Date()),
        }, { source: 'task-repeat-dialog' });
    };

    window.tmCalendarWarmDocsToGroupCache = async function() {
        const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
        const parts = [];
        for (const g of groups) {
            const gid = String(g?.id || '').trim();
            if (!gid) continue;
            const ds = __tmGetGroupSourceEntries(g).map((d) => {
                const did = String(d?.id || '').trim();
                if (!did) return '';
                return did + (d.kind === 'notebook' ? '#nb' : (d.recursive ? '*' : ''));
            }).filter(Boolean);
            parts.push(`${gid}:${ds.join(',')}`);
        }
        const key = parts.join('|');
        const prev = window.__tmCalendarDocsToGroupCache;
        if (prev && prev.key === key && prev.map instanceof Map) return true;

        const map = new Map();
        for (const g of groups) {
            const gid = String(g?.id || '').trim();
            if (!gid) continue;
            const entries = __tmGetGroupSourceEntries(g);
            for (const entry of entries) {
                await __tmExpandSourceEntryDocIds(entry, (did0) => {
                    const did = String(did0 || '').trim();
                    if (!did || map.has(did)) return;
                    map.set(did, gid);
                });
            }
        }
        window.__tmCalendarDocsToGroupCache = { key, map };
        return true;
    };

    let __tmCalendarSidebarDocItemsWarmPromise = null;

    function __tmBuildCalendarSidebarDocItemsCacheKey() {
        const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
        const groupParts = [];
        for (const g of groups) {
            const gid = String(g?.id || '').trim();
            if (!gid) continue;
            const ds = __tmGetGroupSourceEntries(g).map((d) => {
                const did = String(d?.id || '').trim();
                if (!did) return '';
                return did + (d.kind === 'notebook' ? '#nb' : (d.recursive ? '*' : ''));
            }).filter(Boolean);
            groupParts.push(`${gid}:${ds.join(',')}`);
        }
        const legacyIds = Array.isArray(SettingsStore.data.selectedDocIds) ? SettingsStore.data.selectedDocIds : [];
        const quickAddDocId = String(SettingsStore.data.newTaskDocId || '').trim();
        const treeTaskSig = (() => {
            const parts = [];
            (Array.isArray(state.taskTree) ? state.taskTree : []).forEach((doc) => {
                const id = String(doc?.id || '').trim();
                const taskCount = Array.isArray(doc?.tasks) ? doc.tasks.length : 0;
                if (!id || taskCount <= 0) return;
                parts.push(`${id}:${taskCount}`);
            });
            return parts.sort().join(',');
        })();
        const calendarCacheSig = (() => {
            const cache = window.__tmCalendarAllTasksCache;
            const parts = [];
            if (Array.isArray(cache?.tasks)) {
                const seen = new Set();
                cache.tasks.forEach((task) => {
                    const docId = String(task?.root_id || task?.docId || '').trim();
                    if (!docId || seen.has(docId)) return;
                    seen.add(docId);
                    parts.push(docId);
                });
            }
            return [
                String(cache?.key || '').trim(),
                Number(cache?.ts) || 0,
                parts.sort().join(',')
            ].join('|');
        })();
        return [
            groupParts.join('|'),
            `legacy:${legacyIds.map((id) => String(id || '').trim()).filter(Boolean).join(',')}`,
            `quick:${quickAddDocId}`,
            `mode:${__tmGetDocDisplayNameMode()}`,
            `docs:${Number(__tmAllDocumentsFetchedAt) || 0}`,
            `tree:${treeTaskSig}`,
            `calendar:${calendarCacheSig}`
        ].join('||');
    }

    function __tmBuildCalendarSidebarDocItemsName(docId, docMap) {
        const did = String(docId || '').trim();
        if (!did) return '未命名文档';
        const map = docMap instanceof Map ? docMap : new Map();
        const meta = map.get(did) || { id: did, name: did };
        const raw = String(meta?.name || meta?.content || did).trim() || did;
        try {
            return __tmGetDocDisplayName(meta, raw) || raw;
        } catch (e) {}
        return raw;
    }

    window.tmCalendarGetSidebarDocItems = function() {
        const cached = window.__tmCalendarSidebarDocItemsCache;
        if (!cached || !cached.data || typeof cached.data !== 'object') return null;
        return cached.data;
    };

    window.tmCalendarWarmSidebarDocItems = async function(options = {}) {
        const opts = (options && typeof options === 'object') ? options : {};
        const key = __tmBuildCalendarSidebarDocItemsCacheKey();
        const prev = window.__tmCalendarSidebarDocItemsCache;
        const cacheMaxAgeMs = 5000;
        if (!opts.force && prev && prev.key === key && prev.data && typeof prev.data === 'object' && (Date.now() - (Number(prev.ts) || 0) < cacheMaxAgeMs)) {
            return prev.data;
        }
        if (!opts.force && __tmCalendarSidebarDocItemsWarmPromise && __tmCalendarSidebarDocItemsWarmPromise.key === key) {
            return await __tmCalendarSidebarDocItemsWarmPromise.promise;
        }

        let tracked = null;
        const run = Promise.resolve().then(async () => {
            try { await window.tmCalendarWarmDocsToGroupCache?.(); } catch (e) {}
            try { await __tmEnsureAllDocumentsLoaded(false); } catch (e) {}

            const docsToGroup = window.__tmCalendarDocsToGroupCache?.map instanceof Map
                ? new Map(window.__tmCalendarDocsToGroupCache.map)
                : __tmGetCalendarDocsToGroupMapSync();
            const docMap = new Map();
            (Array.isArray(state.allDocuments) ? state.allDocuments : []).forEach((doc) => {
                const id = String(doc?.id || '').trim();
                if (!id || docMap.has(id)) return;
                docMap.set(id, doc);
            });
            (Array.isArray(state.taskTree) ? state.taskTree : []).forEach((doc) => {
                const id = String(doc?.id || '').trim();
                if (!id || docMap.has(id)) return;
                docMap.set(id, {
                    id,
                    name: String(doc?.name || '').trim() || id,
                    alias: String(doc?.alias || '').trim(),
                    icon: doc?.icon,
                });
            });
            const tasksMap = new Map();
            (Array.isArray(state.taskTree) ? state.taskTree : []).forEach((doc) => {
                const id = String(doc?.id || '').trim();
                if (!id || !Array.isArray(doc?.tasks) || doc.tasks.length <= 0) return;
                tasksMap.set(id, true);
            });
            (Array.isArray(window.__tmCalendarAllTasksCache?.tasks) ? window.__tmCalendarAllTasksCache.tasks : []).forEach((task) => {
                const docId = String(task?.root_id || task?.docId || '').trim();
                if (!docId) return;
                tasksMap.set(docId, true);
            });

            const calendarDocIds = {};
            const seenByCalendar = new Map();
            const pushDoc = (calendarId0, docId0) => {
                const calendarId = String(calendarId0 || '').trim();
                const docId = String(docId0 || '').trim();
                if (!calendarId || !docId) return;
                if (!Array.isArray(calendarDocIds[calendarId])) calendarDocIds[calendarId] = [];
                if (!seenByCalendar.has(calendarId)) seenByCalendar.set(calendarId, new Set());
                const seen = seenByCalendar.get(calendarId);
                if (seen.has(docId)) return;
                seen.add(docId);
                calendarDocIds[calendarId].push(docId);
            };

            docsToGroup.forEach((gid, did) => {
                const groupId = String(gid || '').trim();
                const docId = String(did || '').trim();
                if (!groupId || !docId) return;
                pushDoc(`group:${groupId}`, docId);
            });

            let allDocIds = [];
            try {
                allDocIds = await resolveDocIdsFromGroups({
                    groupId: 'all',
                    includeQuickAddDoc: true,
                });
            } catch (e) {
                allDocIds = [];
            }
            const candidateDocIds = new Set();
            docsToGroup.forEach((gid, did) => {
                const docId = String(did || '').trim();
                if (docId) candidateDocIds.add(docId);
            });
            (Array.isArray(allDocIds) ? allDocIds : []).forEach((docId0) => {
                const docId = String(docId0 || '').trim();
                if (docId) candidateDocIds.add(docId);
            });
            try {
                await __tmFillDocHasTasksMap(Array.from(candidateDocIds), tasksMap);
            } catch (e) {}

            (Array.isArray(allDocIds) ? allDocIds : []).forEach((docId0) => {
                const docId = String(docId0 || '').trim();
                if (!docId || docsToGroup.has(docId) || !tasksMap.has(docId)) return;
                pushDoc('default', docId);
            });
            Object.keys(calendarDocIds).forEach((calendarId) => {
                const ids = Array.isArray(calendarDocIds[calendarId]) ? calendarDocIds[calendarId] : [];
                calendarDocIds[calendarId] = ids.filter((docId) => tasksMap.has(String(docId || '').trim()));
            });

            const calendars = {};
            Object.keys(calendarDocIds).forEach((calendarId) => {
                const ids = Array.isArray(calendarDocIds[calendarId]) ? calendarDocIds[calendarId] : [];
                const docs = ids.map((docId) => ({
                    id: docId,
                    name: __tmBuildCalendarSidebarDocItemsName(docId, docMap)
                }));
                if (docs.length > 0) calendars[calendarId] = docs;
            });

            const data = { key, calendars };
            window.__tmCalendarSidebarDocItemsCache = { key, data, ts: Date.now() };
            return data;
        });

        tracked = run.finally(() => {
            if (__tmCalendarSidebarDocItemsWarmPromise === tracked) __tmCalendarSidebarDocItemsWarmPromise = null;
        });
        __tmCalendarSidebarDocItemsWarmPromise = { key, promise: tracked };
        return await tracked;
    };

    function __tmKanbanClearDragOver(modalEl) {
        const modal = modalEl instanceof Element ? modalEl : state.modal;
        if (!modal) return;
        try {
            const cols = modal.querySelectorAll('.tm-kanban-col.tm-kanban-col--dragover');
            cols.forEach(el => { try { el.classList.remove('tm-kanban-col--dragover'); } catch (e) {} });
        } catch (e) {}
    }

