            topbarControlShadowYOffsetPx: { min: 0, max: 24, fallback: 0 },
            topbarControlShadowBlurPx: { min: 0, max: 48, fallback: 0 },
            topbarControlShadowStrengthPct: { min: 0, max: 200, fallback: 100 },
