    function __tmSummaryDateFmt(d) {
        if (!(d instanceof Date) || Number.isNaN(d.getTime())) return '';
        const pad = (n) => String(n).padStart(2, '0');
        return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
    }

    function __tmSummaryRangeFromPreset(preset) {
        const p = String(preset || '').trim();
        const now = new Date();
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        if (p === 'today' || p === 'today_report') {
            const s = __tmSummaryDateFmt(today);
            return { start: s, end: s };
        }
        if (p === 'this_week' || p === 'this_week_report') {
            const day = (today.getDay() + 6) % 7;
            const s = new Date(today.getTime() - day * 86400000);
            const e = new Date(s.getTime() + 6 * 86400000);
            return { start: __tmSummaryDateFmt(s), end: __tmSummaryDateFmt(e) };
        }
        if (p === 'last_week' || p === 'last_week_report') {
            const day = (today.getDay() + 6) % 7;
            const thisWeekStart = new Date(today.getTime() - day * 86400000);
            const s = new Date(thisWeekStart.getTime() - 7 * 86400000);
            const e = new Date(thisWeekStart.getTime() - 86400000);
            return { start: __tmSummaryDateFmt(s), end: __tmSummaryDateFmt(e) };
        }
        if (p === 'this_month') {
            const s = new Date(today.getFullYear(), today.getMonth(), 1);
            const e = new Date(today.getFullYear(), today.getMonth() + 1, 0);
            return { start: __tmSummaryDateFmt(s), end: __tmSummaryDateFmt(e) };
        }
        if (p === 'last_month') {
            const s = new Date(today.getFullYear(), today.getMonth() - 1, 1);
            const e = new Date(today.getFullYear(), today.getMonth(), 0);
            return { start: __tmSummaryDateFmt(s), end: __tmSummaryDateFmt(e) };
        }
        return { start: '', end: '' };
    }

    async function __tmBuildSummaryDocToGroupMap() {
        const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
        const parts = [];
        for (const g of groups) {
            const gid = String(g?.id || '').trim();
            if (!gid) continue;
            const ds = __tmGetGroupSourceEntries(g).map((d) => {
                const did = String(d?.id || '').trim();
                if (!did) return '';
                return did + (d.kind === 'notebook' ? '#nb' : (d.recursive ? '*' : ''));
            }).filter(Boolean);
            parts.push(`${gid}:${ds.join(',')}`);
        }
        const key = parts.join('|');
        const prev = window.__tmSummaryDocToGroupCache;
        if (prev && prev.key === key && prev.map instanceof Map) return prev.map;

        const map = new Map();
        for (const g of groups) {
            const gid = String(g?.id || '').trim();
            if (!gid) continue;
            const entries = __tmGetGroupSourceEntries(g);
            for (const entry of entries) {
                await __tmExpandSourceEntryDocIds(entry, (did0) => {
                    const did = String(did0 || '').trim();
                    if (!did || map.has(did)) return;
                    map.set(did, gid);
                });
            }
        }
        window.__tmSummaryDocToGroupCache = { key, map };
        return map;
    }

    function __tmSummaryStatusName(task, statusMap) {
        if (task?.done) return '已完成';
        const sid = __tmResolveUndoneStatusValue(task?.customStatus);
        return statusMap.get(sid) || sid || '未完成';
    }

    function __tmSummaryPriorityText(priority) {
        const p = String(priority || '').trim();
        if (p === 'high') return '高';
        if (p === 'medium') return '中';
        if (p === 'low') return '低';
        return '无';
    }

    function __tmSummaryDateKeyFromTs(ts) {
        const n = Number(ts);
        if (!Number.isFinite(n) || n <= 0) return '';
        const d = new Date(n);
        if (Number.isNaN(d.getTime())) return '';
        const pad = (x) => String(x).padStart(2, '0');
        return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
    }

    function __tmSummaryTaskDate(task) {
        const ts = __tmParseTimeToTs(task?.updated || '');
        return __tmSummaryDateKeyFromTs(ts);
    }

    async function __tmSummaryResolveAllDocIds() {
        const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
        const set = new Set();
        for (const g of groups) {
            const entries = __tmGetGroupSourceEntries(g);
            for (const entry of entries) {
                await __tmExpandSourceEntryDocIds(entry, (did) => {
                    const id = String(did || '').trim();
                    if (id) set.add(id);
                });
            }
        }
        if (set.size === 0) {
            Object.values(state.flatTasks || {}).forEach((t) => {
                const docId = String(t?.docId || t?.root_id || '').trim();
                if (docId) set.add(docId);
            });
        }
        return Array.from(set);
    }

    async function __tmSummaryBuildDocNameMapByGroups(baseMap) {
        const out = (baseMap && typeof baseMap === 'object') ? { ...baseMap } : {};
        const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
        for (const g of groups) {
            const docEntries = __tmNormalizeGroupDocEntries(g);
            docEntries.forEach((doc) => {
                const id = String(doc?.id || '').trim();
                if (!id || out[id]) return;
                const fromAll = (Array.isArray(state.allDocuments) ? state.allDocuments : []).find((d) => String(d?.id || '').trim() === id);
                if (fromAll?.name) out[id] = String(fromAll.name).trim() || id;
            });
            const notebookId = String(g?.notebookId || '').trim();
            if (!notebookId) continue;
            try {
                const docs = await API.getNotebookDocuments(notebookId);
                (Array.isArray(docs) ? docs : []).forEach((doc) => {
                    const id = String(doc?.id || '').trim();
                    if (!id || out[id]) return;
                    out[id] = String(doc?.name || '').trim() || id;
                });
            } catch (e) {}
        }
        return out;
    }

    async function __tmSummaryBuildGroupDocIdsMap() {
        const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
        const out = {};
        for (const g of groups) {
            const gid = String(g?.id || '').trim();
            if (!gid) continue;
            const ids = [];
            const seen = new Set();
            const entries = __tmGetGroupSourceEntries(g);
            for (const entry of entries) {
                await __tmExpandSourceEntryDocIds(entry, (did) => {
                    const id = String(did || '').trim();
                    if (!id || seen.has(id)) return;
                    seen.add(id);
                    ids.push(id);
                });
            }
            out[gid] = ids;
        }
        return out;
    }

    async function __tmSummaryLoadTasksByDocs(docIds, options = {}) {
        const ids = Array.isArray(docIds) ? docIds.map(x => String(x || '').trim()).filter(Boolean) : [];
        if (!ids.length) return [];
        const limit = Math.max(2000, Number(SettingsStore.data.queryLimit) || 5000);
        let list = [];
        try {
            const res = await API.getTasksByDocuments(ids, limit, { doneOnly: false, ignoreExcludeCompleted: options?.ignoreExcludeCompleted === true });
            list = Array.isArray(res?.tasks) ? res.tasks : [];
        } catch (e) {
            list = [];
        }
        let h2Map = new Map();
        try {
            h2Map = await API.fetchH2Contexts(list.map(t => t?.id).filter(Boolean));
        } catch (e) {
            h2Map = new Map();
        }
        return list.map((task) => {
            if (!task || typeof task !== 'object') return null;
            const t = { ...task };
            let parsedDone = !!t.done;
            try {
                const parsed = API.parseTaskStatus(t.markdown);
                parsedDone = !!parsed.done;
                t.done = parsedDone;
                t.content = parsed.content;
            } catch (e) {}
            try { MetaStore.applyToTask?.(t); } catch (e) {}
            t.done = parsedDone;
            const docName = String(t.docName || '未命名文档');
            try { normalizeTaskFields(t, docName); } catch (e) {}
            const h2ctx = h2Map.get(t.id);
            if (h2ctx && typeof h2ctx === 'object') {
                t.h2 = String(h2ctx.content || '').trim();
                t.h2Id = String(h2ctx.id || '').trim();
            }
            return t;
        }).filter(Boolean);
    }

    async function __tmSummaryLoadTasksByDocFallback(docId, options = {}) {
        const id = String(docId || '').trim();
        if (!id) return [];
        const limit = Math.max(2000, Number(SettingsStore.data.queryLimit) || 5000);
        let list = [];
        try {
            const res = await API.getTasksByDocument(id, limit, { doneOnly: false, ignoreExcludeCompleted: options?.ignoreExcludeCompleted === true });
            list = Array.isArray(res?.tasks) ? res.tasks : [];
        } catch (e) {
            list = [];
        }
        let h2Map = new Map();
        try {
            h2Map = await API.fetchH2Contexts(list.map(t => t?.id).filter(Boolean));
        } catch (e) {
            h2Map = new Map();
        }
        return list.map((task) => {
            if (!task || typeof task !== 'object') return null;
            const t = { ...task };
            let parsedDone = !!t.done;
            try {
                const parsed = API.parseTaskStatus(t.markdown);
                parsedDone = !!parsed.done;
                t.done = parsedDone;
                t.content = parsed.content;
            } catch (e) {}
            try { MetaStore.applyToTask?.(t); } catch (e) {}
            t.done = parsedDone;
            const docName = String(t.docName || t.doc_name || '未命名文档');
            try { normalizeTaskFields(t, docName); } catch (e) {}
            const h2ctx = h2Map.get(t.id);
            if (h2ctx && typeof h2ctx === 'object') {
                t.h2 = String(h2ctx.content || '').trim();
                t.h2Id = String(h2ctx.id || '').trim();
            }
            return t;
        }).filter(Boolean);
    }

    function __tmSummaryCollectTasks(ctx, filter) {
        const out = [];
        const arr = Array.isArray(ctx.summaryTasks) ? ctx.summaryTasks : [];
        const docNameMap = ctx.docNameMap || {};
        const docToGroup = ctx.docToGroup || new Map();
        const groupDocIdsMap = (ctx.groupDocIdsMap && typeof ctx.groupDocIdsMap === 'object') ? ctx.groupDocIdsMap : {};
        const f = filter || {};
        const start = String(f.start || '').trim();
        const end = String(f.end || '').trim();
        const status = String(f.status || '__all__').trim();
        const priority = String(f.priority || '__all__').trim();
        const groupId = String(f.groupId || '__all__').trim();
        const docIdFilter = String(f.docId || '__all__').trim();
        const idMap = new Map();
        const levelMemo = new Map();

        arr.forEach((t) => {
            const id = String(t?.id || '').trim();
            if (id) idMap.set(id, t);
        });

        const resolveLevel = (task) => {
            const id = String(task?.id || '').trim();
            if (!id) return 0;
            if (levelMemo.has(id)) return levelMemo.get(id);
            const seen = new Set([id]);
            let level = 0;
            let pid = String(task?.parentTaskId || '').trim();
            while (pid && !seen.has(pid)) {
                seen.add(pid);
                const parent = idMap.get(pid);
                if (!parent) break;
                level += 1;
                pid = String(parent?.parentTaskId || '').trim();
            }
            levelMemo.set(id, level);
            return level;
        };

        arr.forEach((task) => {
            if (!task || !task.id) return;
            const docId = String(task.docId || task.root_id || '').trim();
            if (!docId) return;
            if (docIdFilter !== '__all__' && docId !== docIdFilter) return;
            const gid = String(docToGroup.get(docId) || '').trim();
            const groupDocIds = Array.isArray(groupDocIdsMap[groupId]) ? groupDocIdsMap[groupId] : [];
            if (groupId === '__ungrouped__') {
                if (gid) return;
            } else if (groupId !== '__all__') {
                if (!groupDocIds.includes(docId)) return;
            }

            const dateKey = __tmSummaryTaskDate(task);
            if (start && (!dateKey || dateKey < start)) return;
            if (end && (!dateKey || dateKey > end)) return;

            if (status === '__done__' && !task.done) return;
            if (status === '__undone__' && task.done) return;
            if (status !== '__all__' && status !== '__done__' && status !== '__undone__') {
                const sid = __tmResolveUndoneStatusValue(task.customStatus);
                if (status === 'done') {
                    if (!task.done && sid !== 'done') return;
                } else if (sid !== status) return;
            }

            const p = String(task.priority || '').trim() || 'none';
            if (priority !== '__all__' && p !== priority) return;

            out.push({
                id: String(task.id || '').trim(),
                content: String(task.content || '').trim() || '无内容',
                done: !!task.done,
                customStatus: __tmResolveUndoneStatusValue(task.customStatus),
                priority: p,
                dateKey,
                dueDate: String(task.completionTime || '').trim(),
                docId,
                docName: String(docNameMap[docId] || task.docName || '未命名文档'),
                h2Id: String(task.h2Id || '').trim(),
                h2Name: String(task.h2 || task.h2Name || '').trim() || '无二级标题',
                level: resolveLevel(task),
            });
        });

        out.sort((a, b) => {
            const da = String(a.dateKey || '');
            const db = String(b.dateKey || '');
            if (da !== db) return da < db ? -1 : 1;
            return String(a.content || '').localeCompare(String(b.content || ''), 'zh-Hans-CN');
        });
        return out;
    }

    function __tmSummaryGenerateMarkdown(tasks, filter, ctx) {
        const lines = [];
        const now = new Date().toISOString().replace('T', ' ').slice(0, 19);
        const statusMap = ctx.statusMap || new Map();
        const preset = String(filter.preset || 'all').trim();
        const isDailyReport = preset === 'today_report';
        const isWeeklyReport = preset === 'this_week_report' || preset === 'last_week_report';
        const groupName = ctx.groupNameMap?.[String(filter.groupId || '__all__')] || '全部分组';
        const docName = filter.docId === '__all__'
            ? (filter.groupId && filter.groupId !== '__all__' ? '当前分区全部文档' : '全部分区内文档')
            : (ctx.docNameMap?.[String(filter.docId || '')] || '指定文档');
        const statusName = String(filter.status || '__all__') === '__all__'
            ? '全部状态'
            : (String(filter.status) === '__done__' ? '已完成' : (String(filter.status) === '__undone__' ? '未完成' : (statusMap.get(String(filter.status || '')) || String(filter.status || ''))));
        const priorityName = String(filter.priority || '__all__') === '__all__' ? '全部优先级' : __tmSummaryPriorityText(filter.priority);
        const groupBy = String(filter.groupBy || 'status').trim() || 'status';
        const groupByName = groupBy === 'h2'
            ? '按二级标题'
            : (groupBy === 'priority' ? '按重要性' : (groupBy === 'doc' ? '按文档' : '按状态'));
        const fields = (filter.fields && typeof filter.fields === 'object') ? filter.fields : {};
        const showTaskName = fields.taskName !== false;
        const showDocName = fields.docName !== false;
        const showPriority = fields.priority !== false;
        const showStatus = fields.status !== false;
        const showDate = fields.date !== false;
        const rangeLabel = (filter.start || filter.end)
            ? `${filter.start || '最早'} ~ ${filter.end || '最晚'}`
            : '全部时间';

        lines.push(isDailyReport ? '# 今日日报' : (preset === 'this_week_report' ? '# 本周周报' : (preset === 'last_week_report' ? '# 上周周报' : '# 任务摘要')));
        lines.push('');
        lines.push(`> 生成时间：${now}`);
        lines.push(`> 筛选：${rangeLabel} | ${groupName} | ${docName} | ${statusName} | ${priorityName} | ${groupByName}`);
        lines.push('');

        if (!tasks.length) {
            lines.push('> 没有匹配到任务。');
            return lines.join('\n');
        }

        const todayKey = __tmSummaryDateFmt(new Date());
        const doneTasks = tasks.filter(t => t.done);
        const todoTasks = tasks.filter(t => !t.done);
        const overdueTasks = tasks.filter((t) => !t.done && String(t.dueDate || '').trim() && String(t.dueDate || '').trim() < todayKey);
        if (isDailyReport || isWeeklyReport) {
            const renderTaskLines = (arr) => arr.length
                ? arr.map((t) => `- [${t.done ? 'x' : ' '}] ${t.content}${t.docName ? `（${t.docName}）` : ''}`).join('\n')
                : '- 无';
            lines.push('## 完成情况');
            lines.push('');
            lines.push(renderTaskLines(doneTasks));
            lines.push('');
            lines.push('## 计划项');
            lines.push('');
            lines.push(renderTaskLines(todoTasks.slice(0, 30)));
            lines.push('');
            lines.push('## 逾期项');
            lines.push('');
            lines.push(renderTaskLines(overdueTasks));
            lines.push('');
        }

        const sectionMap = new Map();
        const sectionLabel = (t) => {
            if (groupBy === 'h2') return String(t.h2Name || '无二级标题');
            if (groupBy === 'priority') return `重要性：${__tmSummaryPriorityText(t.priority)}`;
            if (groupBy === 'doc') return String(t.docName || '未命名文档');
            return __tmSummaryStatusName(t, statusMap);
        };
        tasks.forEach((t) => {
            const key = sectionLabel(t);
            if (!sectionMap.has(key)) sectionMap.set(key, []);
            sectionMap.get(key).push(t);
        });

        const sectionOrder = Array.from(sectionMap.keys()).sort((a, b) => String(a).localeCompare(String(b), 'zh-Hans-CN'));
        sectionOrder.forEach((name) => {
            const arr = sectionMap.get(name) || [];
            lines.push(`## ${name}（${arr.length}）`);
            lines.push('');
            arr.forEach((t) => {
                const d = (showDate && t.dateKey) ? `[${t.dateKey}] ` : '';
                const pr = __tmSummaryPriorityText(t.priority);
                const checkbox = t.done ? '[x]' : '[ ]';
                const body = showTaskName ? t.content : '(任务)';
                const ext = [];
                const level = Math.max(0, Number(t.level) || 0);
                const indent = '  '.repeat(level);
                if (showDocName && groupBy !== 'doc') ext.push(t.docName);
                if (showPriority) ext.push(`优先级:${pr}`);
                if (showStatus) ext.push(__tmSummaryStatusName(t, statusMap));
                lines.push(`${indent}- ${checkbox} ${d}${body}${ext.length ? `（${ext.join('｜')}）` : ''}`);
            });
            lines.push('');
        });

        const doneCount = tasks.filter(t => t.done).length;
        lines.push('---');
        lines.push('');
        lines.push(`- 总计：${tasks.length}`);
        lines.push(`- 已完成：${doneCount}`);
        lines.push(`- 未完成：${tasks.length - doneCount}`);
        return lines.join('\n');
    }

    function __tmSummaryReadFilter(root) {
        const q = (sel) => root.querySelector(sel);
        const preset = String(q('[data-tm-summary="preset"]')?.value || 'all').trim();
        const startInput = q('[data-tm-summary="start"]');
        const endInput = q('[data-tm-summary="end"]');
        let start = String(startInput?.value || '').trim();
        let end = String(endInput?.value || '').trim();
        if (preset !== 'custom') {
            const r = __tmSummaryRangeFromPreset(preset);
            start = r.start;
            end = r.end;
            if (startInput) startInput.value = start;
            if (endInput) endInput.value = end;
        }
        return {
            preset,
            start: __tmNormalizeDateOnly(start),
            end: __tmNormalizeDateOnly(end),
            groupId: String(q('[data-tm-summary="group"]')?.value || '__all__').trim(),
            docId: String(q('[data-tm-summary="doc"]')?.value || '__all__').trim(),
            status: String(q('[data-tm-summary="status"]')?.value || '__all__').trim(),
            priority: String(q('[data-tm-summary="priority"]')?.value || '__all__').trim(),
            groupBy: String(q('[data-tm-summary="groupBy"]')?.value || 'status').trim(),
            fields: {
                taskName: q('[data-tm-summary="fieldTaskName"]')?.checked !== false,
                docName: q('[data-tm-summary="fieldDocName"]')?.checked !== false,
                priority: q('[data-tm-summary="fieldPriority"]')?.checked !== false,
                status: q('[data-tm-summary="fieldStatus"]')?.checked !== false,
                date: q('[data-tm-summary="fieldDate"]')?.checked !== false,
            },
        };
    }

    function __tmSummaryRefreshDocOptions(root, ctx) {
        const groupSel = root.querySelector('[data-tm-summary="group"]');
        const docSel = root.querySelector('[data-tm-summary="doc"]');
        if (!groupSel || !docSel) return;
        const prevDoc = String(docSel.value || '__all__').trim();
        const gid = String(groupSel.value || '__all__').trim();
        const docToGroup = ctx.docToGroup || new Map();
        const docTaskCount = (ctx.docTaskCount && typeof ctx.docTaskCount === 'object') ? ctx.docTaskCount : {};
        const groupDocIdsMap = (ctx.groupDocIdsMap && typeof ctx.groupDocIdsMap === 'object') ? ctx.groupDocIdsMap : {};
        const allLabel = gid === '__all__' ? '全部分区内文档' : (gid === '__ungrouped__' ? '未分组全部文档' : '当前分区全部文档');
        const options = [{ id: '__all__', name: allLabel }];
        if (gid !== '__all__' && gid !== '__ungrouped__') {
            const ids = Array.isArray(groupDocIdsMap[gid]) ? groupDocIdsMap[gid] : [];
            ids.forEach((docId) => {
                const id = String(docId || '').trim();
                if (!id) return;
                const name = String((ctx.docNameMap || {})[id] || id);
                options.push({ id, name });
            });
        } else {
            Object.entries(ctx.docNameMap || {}).forEach(([docId, name]) => {
                if (!Number(docTaskCount[String(docId)] || 0)) return;
                const g = String(docToGroup.get(String(docId)) || '').trim();
                if (gid === '__all__' || (gid === '__ungrouped__' ? !g : g === gid)) {
                    options.push({ id: String(docId), name: String(name || docId) });
                }
            });
        }
        docSel.innerHTML = options
            .filter((it, idx, arr) => arr.findIndex((x) => String(x.id) === String(it.id)) === idx)
            .sort((a, b) => String(a.name).localeCompare(String(b.name), 'zh-Hans-CN'))
            .map((it) => `<option value="${esc(it.id)}">${esc(it.name)}</option>`)
            .join('');
        docSel.value = options.some(it => it.id === prevDoc) ? prevDoc : '__all__';
    }

    async function __tmSummaryEnsureTasksForFilter(ctx, filter) {
        if (!ctx || typeof ctx !== 'object') return;
        const f = (filter && typeof filter === 'object') ? filter : {};
        const groupDocIdsMap = (ctx.groupDocIdsMap && typeof ctx.groupDocIdsMap === 'object') ? ctx.groupDocIdsMap : {};
        let targetDocIds = [];
        const docId = String(f.docId || '__all__').trim();
        const groupId = String(f.groupId || '__all__').trim();
        if (docId && docId !== '__all__') {
            targetDocIds = [docId];
        } else if (groupId && groupId !== '__all__' && groupId !== '__ungrouped__') {
            targetDocIds = Array.isArray(groupDocIdsMap[groupId]) ? groupDocIdsMap[groupId] : [];
        } else {
            return;
        }
        const ids = Array.from(new Set(targetDocIds.map((id) => String(id || '').trim()).filter(Boolean)));
        if (!ids.length) return;

        let tasks = await __tmSummaryLoadTasksByDocs(ids);
        const hitDocIds = new Set(tasks.map((t) => String(t?.docId || t?.root_id || '').trim()).filter(Boolean));
        const missingDocIds = ids.filter((id) => !hitDocIds.has(id));
        if (missingDocIds.length > 0) {
            for (const missingId of missingDocIds) {
                const extra = await __tmSummaryLoadTasksByDocFallback(missingId);
                if (extra.length > 0) tasks = tasks.concat(extra);
            }
        }
        const prev = Array.isArray(ctx.summaryTasks) ? ctx.summaryTasks : [];
        const merged = new Map();
        prev.forEach((t) => {
            const id = String(t?.id || '').trim();
            if (id) merged.set(id, t);
        });
        tasks.forEach((t) => {
            const id = String(t?.id || '').trim();
            if (id) merged.set(id, t);
            const did = String(t?.docId || t?.root_id || '').trim();
            if (did) {
                ctx.docNameMap = (ctx.docNameMap && typeof ctx.docNameMap === 'object') ? ctx.docNameMap : {};
                if (!ctx.docNameMap[did]) ctx.docNameMap[did] = String(t?.docName || '').trim() || did;
            }
        });
        ctx.summaryTasks = Array.from(merged.values());
        const nextCount = {};
        (ctx.summaryTasks || []).forEach((t) => {
            const did = String(t?.docId || t?.root_id || '').trim();
            if (!did) return;
            nextCount[did] = Number(nextCount[did] || 0) + 1;
        });
        ctx.docTaskCount = nextCount;
    }

    function __tmSummaryUpdatePreview(root, ctx) {
        const filter = __tmSummaryReadFilter(root);
        const tasks = __tmSummaryCollectTasks(ctx, filter);
        const md = __tmSummaryGenerateMarkdown(tasks, filter, ctx);
        const textarea = root.querySelector('[data-tm-summary="preview"]');
        if (textarea) textarea.value = md;
    }

    function __tmCloseSummaryModal() {
        state.__summaryUnstack?.();
        state.__summaryUnstack = null;
        if (!state.summaryModal) return;
        try { state.summaryModal.remove(); } catch (e) {}
        state.summaryModal = null;
    }

    window.tmShowSummaryModal = async function() {
        try { __tmHideMobileMenu(); } catch (e) {}
        try { tmCloseDesktopMenu(); } catch (e) {}
        __tmCloseSummaryModal();

        const docNameMap = {};
        (Array.isArray(state.taskTree) ? state.taskTree : []).forEach((d) => {
            const id = String(d?.id || '').trim();
            if (id) docNameMap[id] = String(d?.name || '').trim() || id;
        });
        (Array.isArray(state.allDocuments) ? state.allDocuments : []).forEach((d) => {
            const id = String(d?.id || '').trim();
            if (id && !docNameMap[id]) docNameMap[id] = String(d?.name || '').trim() || id;
        });
        Object.values(state.flatTasks || {}).forEach((t) => {
            const docId = String(t?.docId || t?.root_id || '').trim();
            if (!docId) return;
            if (!docNameMap[docId]) docNameMap[docId] = String(t?.docName || '').trim() || docId;
        });
        Object.assign(docNameMap, await __tmSummaryBuildDocNameMapByGroups(docNameMap));

        const statusOptions = Array.isArray(SettingsStore.data.customStatusOptions) ? SettingsStore.data.customStatusOptions : [];
        const statusMap = new Map();
        statusOptions.forEach((o) => {
            const id = String(o?.id || '').trim();
            if (!id) return;
            statusMap.set(id, String(o?.name || id));
        });

        const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
        const groupNameMap = { '__all__': '全部分组', '__ungrouped__': '未分组' };
        groups.forEach((g) => {
            const gid = String(g?.id || '').trim();
            if (gid) groupNameMap[gid] = __tmResolveDocGroupName(g);
        });

        const docToGroup = await __tmBuildSummaryDocToGroupMap();
        const groupDocIdsMap = await __tmSummaryBuildGroupDocIdsMap();
        const allDocIds = await __tmSummaryResolveAllDocIds();
        const summaryTasks = await __tmSummaryLoadTasksByDocs(allDocIds);
        const docTaskCount = {};
        summaryTasks.forEach((t) => {
            const docId = String(t?.docId || t?.root_id || '').trim();
            if (!docId) return;
            docTaskCount[docId] = Number(docTaskCount[docId] || 0) + 1;
            if (!docNameMap[docId]) docNameMap[docId] = String(t?.docName || '').trim() || docId;
        });
        const groupOptions = [
            { id: '__all__', name: '全部分组' },
            ...groups.map((g) => ({ id: String(g?.id || '').trim(), name: __tmResolveDocGroupName(g) })).filter(g => g.id),
            { id: '__ungrouped__', name: '未分组' }
        ];
        const statusSelectOptions = [
            { id: '__all__', name: '全部状态' },
            { id: '__done__', name: '已完成' },
            { id: '__undone__', name: '未完成' },
            ...Array.from(statusMap.keys()).map((id) => ({ id, name: statusMap.get(id) || id }))
        ];

        state.summaryModal = document.createElement('div');
        state.summaryModal.className = 'tm-modal';
        state.summaryModal.style.cssText = 'z-index: 200001;';
        const box = document.createElement('div');
        box.className = 'tm-box';
        box.style.cssText = 'width:min(960px,95vw);height:min(88vh,860px);display:flex;flex-direction:column;';
        box.innerHTML = `
            <div class="tm-header" style="padding:12px 16px;border-bottom:1px solid var(--tm-border-color);">
                <div style="font-size:16px;font-weight:600;">📝 任务摘要</div>
                <button class="tm-btn tm-btn-gray" data-tm-summary-action="close" style="padding:4px 8px;font-size:12px;">✕</button>
            </div>
            <div class="tm-body" style="padding:12px 16px;display:flex;flex-direction:column;gap:10px;overflow:auto;">
                <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;">
                    <select class="tm-rule-select" data-tm-summary="preset" style="min-width:110px;">
                        <option value="all">全部时间</option>
                        <option value="today_report">今日日报</option>
                        <option value="this_week_report">本周周报</option>
                        <option value="last_week_report">上周周报</option>
                        <option value="today">今天</option>
                        <option value="this_week" selected>本周</option>
                        <option value="last_week">上周</option>
                        <option value="this_month">本月</option>
                        <option value="last_month">上月</option>
                        <option value="custom">自定义</option>
                    </select>
                    <input class="tm-input" type="date" data-tm-summary="start" style="width:140px;">
                    <span style="color:var(--tm-secondary-text);">~</span>
                    <input class="tm-input" type="date" data-tm-summary="end" style="width:140px;">
                    <select class="tm-rule-select" data-tm-summary="group" style="min-width:140px;">
                        ${groupOptions.map(g => `<option value="${esc(g.id)}">${esc(g.name)}</option>`).join('')}
                    </select>
                    <select class="tm-rule-select" data-tm-summary="doc" style="min-width:160px;"></select>
                    <select class="tm-rule-select" data-tm-summary="status" style="min-width:130px;">
                        ${statusSelectOptions.map(s => `<option value="${esc(s.id)}">${esc(s.name)}</option>`).join('')}
                    </select>
                    <select class="tm-rule-select" data-tm-summary="priority" style="min-width:120px;">
                        <option value="__all__">全部重要性</option>
                        <option value="high">高</option>
                        <option value="medium">中</option>
                        <option value="low">低</option>
                        <option value="none">无</option>
                    </select>
                    <select class="tm-rule-select" data-tm-summary="groupBy" style="min-width:130px;">
                        <option value="status">按状态分组</option>
                        <option value="priority">按重要性分组</option>
                        <option value="doc">按文档分组</option>
                        <option value="h2">按二级标题分组</option>
                    </select>
                </div>
                <div style="display:flex;gap:10px;flex-wrap:wrap;align-items:center;color:var(--tm-secondary-text);font-size:12px;">
                    <span>显示字段:</span>
                    <label style="display:inline-flex;align-items:center;gap:4px;"><input type="checkbox" data-tm-summary="fieldTaskName" checked>任务名称</label>
                    <label style="display:inline-flex;align-items:center;gap:4px;"><input type="checkbox" data-tm-summary="fieldDocName">文档名称</label>
                    <label style="display:inline-flex;align-items:center;gap:4px;"><input type="checkbox" data-tm-summary="fieldPriority">优先级</label>
                    <label style="display:inline-flex;align-items:center;gap:4px;"><input type="checkbox" data-tm-summary="fieldStatus">状态</label>
                    <label style="display:inline-flex;align-items:center;gap:4px;"><input type="checkbox" data-tm-summary="fieldDate">日期</label>
                </div>
                <textarea data-tm-summary="preview" style="width:100%;height:100%;min-height:420px;box-sizing:border-box;padding:12px;font-family:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace;font-size:13px;line-height:1.55;background:var(--tm-input-bg);color:var(--tm-text-color);border:1px solid var(--tm-input-border);border-radius:8px;resize:vertical;"></textarea>
            </div>
            <div class="tm-header" style="padding:12px 16px;border-top:1px solid var(--tm-border-color);justify-content:flex-end;gap:10px;">
                <button class="tm-btn tm-btn-secondary" data-tm-summary-action="refresh" style="padding:8px 16px;">生成</button>
                <button class="tm-btn tm-btn-primary" data-tm-summary-action="copy" style="padding:8px 16px;">复制</button>
                <button class="tm-btn tm-btn-primary" data-tm-summary-action="export" style="padding:8px 16px;">导出</button>
            </div>
        `;
        state.summaryModal.appendChild(box);
        document.body.appendChild(state.summaryModal);
        state.__summaryUnstack = __tmModalStackBind(() => __tmCloseSummaryModal());

        const root = state.summaryModal;
        const ctx = { docNameMap, docTaskCount, docToGroup, groupDocIdsMap, statusMap, groupNameMap, summaryTasks };
        __tmSummaryRefreshDocOptions(root, ctx);
        await __tmSummaryEnsureTasksForFilter(ctx, __tmSummaryReadFilter(root));
        __tmSummaryUpdatePreview(root, ctx);

        root.addEventListener('change', async (e) => {
            const target = e.target;
            if (!(target instanceof Element)) return;
            const key = String(target.getAttribute('data-tm-summary') || '').trim();
            if (!key) return;
            if (key === 'group') __tmSummaryRefreshDocOptions(root, ctx);
            const filter = __tmSummaryReadFilter(root);
            await __tmSummaryEnsureTasksForFilter(ctx, filter);
            __tmSummaryUpdatePreview(root, ctx);
        });

        root.addEventListener('click', async (e) => {
            const target = e.target?.closest?.('[data-tm-summary-action]');
            if (!target) return;
            const action = String(target.getAttribute('data-tm-summary-action') || '').trim();
            if (action === 'close') {
                __tmCloseSummaryModal();
                return;
            }
            if (action === 'refresh') {
                await __tmSummaryEnsureTasksForFilter(ctx, __tmSummaryReadFilter(root));
                __tmSummaryUpdatePreview(root, ctx);
                hint('✅ 已生成摘要', 'success');
                return;
            }
            if (action === 'copy') {
                const text = String(root.querySelector('[data-tm-summary="preview"]')?.value || '');
                if (!text.trim()) {
                    hint('⚠️ 没有可复制内容', 'warning');
                    return;
                }
                let ok = false;
                try {
                    if (navigator?.clipboard?.writeText) {
                        await navigator.clipboard.writeText(text);
                        ok = true;
                    }
                } catch (e2) {}
                if (!ok) {
                    try {
                        const ta = root.querySelector('[data-tm-summary="preview"]');
                        ta?.focus?.();
                        ta?.select?.();
                        ok = document.execCommand('copy');
                    } catch (e2) {}
                }
                hint(ok ? '✅ 已复制摘要 Markdown' : '❌ 复制失败', ok ? 'success' : 'error');
                return;
            }
            if (action === 'export') {
                const text = String(root.querySelector('[data-tm-summary="preview"]')?.value || '');
                if (!text.trim()) {
                    hint('⚠️ 没有可导出的内容', 'warning');
                    return;
                }
                const filter = __tmSummaryReadFilter(root);
                const preset = String(filter.preset || 'summary').trim();
                const map = {
                    today_report: 'today-report',
                    this_week_report: 'this-week-report',
                    last_week_report: 'last-week-report',
                };
                const name = `${map[preset] || 'task-summary'}-${__tmSummaryDateFmt(new Date())}.md`;
                const a = document.createElement('a');
                a.href = URL.createObjectURL(new Blob([text], { type: 'text/markdown;charset=utf-8' }));
                a.download = name;
                document.body.appendChild(a);
                a.click();
                setTimeout(() => {
                    try { URL.revokeObjectURL(a.href); } catch (e2) {}
                    try { a.remove(); } catch (e2) {}
                }, 0);
                hint('✅ 已导出 Markdown', 'success');
            }
        });
    };

    function __tmExcelSanitizeFileName(name) {
        const raw = String(name || '').trim();
        const safe = raw.replace(/[\\/:*?"<>|]+/g, '_').replace(/\s+/g, ' ').trim();
        return safe || '任务管理器_表格导出';
    }

    function __tmExcelDateStamp() {
        const now = new Date();
        const pad = (n) => String(n).padStart(2, '0');
        return `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
    }

    function __tmExcelGetNoHeadingLabel() {
        const headingLevel = String(SettingsStore.data.taskHeadingLevel || 'h2').trim() || 'h2';
        const headingLabelMap = { h1: '一级标题', h2: '二级标题', h3: '三级标题', h4: '四级标题', h5: '五级标题', h6: '六级标题' };
        return `无${headingLabelMap[headingLevel] || '标题'}`;
    }

    function __tmResolveXlsxRuntime() {
        const candidates = [
            globalThis.XLSX,
            (typeof window !== 'undefined' ? window.XLSX : null),
            globalThis.exports,
            globalThis.module?.exports,
            (typeof window !== 'undefined' ? window.exports : null),
            (typeof window !== 'undefined' ? window.module?.exports : null),
        ];
        for (const candidate of candidates) {
            if (candidate && candidate.utils && (typeof candidate.writeFile === 'function' || typeof candidate.writeFileXLSX === 'function')) {
                try {
                    if (!globalThis.XLSX) globalThis.XLSX = candidate;
                    if (typeof window !== 'undefined' && !window.XLSX) window.XLSX = candidate;
                } catch (e) {}
                return candidate;
            }
        }
        return null;
    }

    async function __tmEnsureXlsxRuntimeLoaded() {
        let runtime = __tmResolveXlsxRuntime();
        if (runtime) return runtime;
        const loader = globalThis.__taskHorizonEnsureXlsxModuleLoaded;
        if (typeof loader === 'function') {
            try { await loader(); } catch (e) {}
        }
        runtime = __tmResolveXlsxRuntime();
        return runtime || null;
    }

    function __tmExcelResolveStatusName(task) {
        const currentStatus = String(task?.customStatus || task?.status || 'todo').trim() || 'todo';
        const statusOptions = Array.isArray(SettingsStore.data.customStatusOptions) ? SettingsStore.data.customStatusOptions : [];
        const statusOption = statusOptions.find((item) => String(item?.id || '').trim() === currentStatus);
        return String(statusOption?.name || currentStatus || '').trim();
    }

    function __tmExcelParseDateCell(value) {
        const normalized = __tmFormatTaskTime(value);
        if (!/^\d{4}-\d{2}-\d{2}$/.test(normalized)) return null;
        const parts = normalized.split('-').map((item) => Number(item));
        const year = Number(parts[0]);
        const month = Number(parts[1]);
        const day = Number(parts[2]);
        if (!Number.isFinite(year) || !Number.isFinite(month) || !Number.isFinite(day)) return null;
        const parsed = new Date(year, month - 1, day, 12, 0, 0, 0);
        return Number.isNaN(parsed.getTime()) ? null : parsed;
    }

    function __tmExcelGetVisibleRootTask(task, taskMap) {
        let current = task;
        const seen = new Set();
        while (current) {
            const currentId = String(current?.id || '').trim();
            const parentId = String(current?.parentTaskId || '').trim();
            if (!parentId || seen.has(parentId)) return current;
            seen.add(parentId);
            const parent = taskMap.get(parentId);
            if (!parent) return current;
            current = parent;
            if (!currentId) return current;
        }
        return task;
    }

    function __tmGetTaskRemainingTimeInfo(task, options = {}) {
        const DAY_MS = 24 * 60 * 60 * 1000;
        const parseToLocalDayBoundaryTs = (value, boundary = 'start') => {
            const normalized = __tmNormalizeDateOnly(value);
            if (normalized && /^\d{4}-\d{2}-\d{2}$/.test(normalized)) {
                const match = /^(\d{4})-(\d{2})-(\d{2})$/.exec(normalized);
                if (match) {
                    const dt = boundary === 'end'
                        ? new Date(Number(match[1]), Number(match[2]) - 1, Number(match[3]), 23, 59, 0, 0)
                        : new Date(Number(match[1]), Number(match[2]) - 1, Number(match[3]), 0, 0, 0, 0);
                    const ts = dt.getTime();
                    return Number.isFinite(ts) ? ts : 0;
                }
            }
            const parsedTs = __tmParseTimeToTs(value);
            if (!Number.isFinite(parsedTs) || parsedTs <= 0) return 0;
            const parsed = new Date(parsedTs);
            const dt = boundary === 'end'
                ? new Date(parsed.getFullYear(), parsed.getMonth(), parsed.getDate(), 23, 59, 0, 0)
                : new Date(parsed.getFullYear(), parsed.getMonth(), parsed.getDate(), 0, 0, 0, 0);
            const ts = dt.getTime();
            return Number.isFinite(ts) ? ts : 0;
        };
        const nowTs = Number.isFinite(Number(options?.nowTs)) ? Number(options.nowTs) : Date.now();
        const nowDate = new Date(nowTs);
        const todayStartTs = Number.isFinite(Number(options?.todayStartTs))
            ? Number(options.todayStartTs)
            : new Date(nowDate.getFullYear(), nowDate.getMonth(), nowDate.getDate(), 0, 0, 0, 0).getTime();
        const calcDayDiff = (targetDayStartTs) => {
            if (!Number.isFinite(targetDayStartTs) || targetDayStartTs <= 0) return Infinity;
            return Math.round((targetDayStartTs - todayStartTs) / DAY_MS);
        };
        const makeInfo = (label, color, sortPrefix, emphasis = false) => ({
            label: String(label || '').trim() || '待定',
            color: String(color || 'var(--tm-secondary-text)').trim() || 'var(--tm-secondary-text)',
            sortPrefix: String(sortPrefix || '8').trim() || '8',
            emphasis: !!emphasis,
        });
        const colors = {
            overdue: __tmIsDarkMode()
                ? (__tmNormalizeHexColor(SettingsStore.data.timeGroupOverdueColorDark, '#ff6b6b') || '#ff6b6b')
                : (__tmNormalizeHexColor(SettingsStore.data.timeGroupOverdueColorLight, '#d93025') || '#d93025'),
            active: '#5fc25f',
            activeStrong: '#05ba05',
            waiting: '#999999',
            pending: '#8e69c9',
        };

        const startStartTs = parseToLocalDayBoundaryTs(task?.startDate, 'start');
        const startEndTs = parseToLocalDayBoundaryTs(task?.startDate, 'end');
        const endStartTs = parseToLocalDayBoundaryTs(task?.completionTime, 'start');
        const endEndTs = parseToLocalDayBoundaryTs(task?.completionTime, 'end');
        const hasStart = Number.isFinite(startStartTs) && startStartTs > 0;
        const hasEnd = Number.isFinite(endEndTs) && endEndTs > 0;

        if (hasEnd) {
            if (hasStart && nowTs < startStartTs) {
                const daysUntilStart = calcDayDiff(startStartTs);
                if (daysUntilStart <= 0) return makeInfo('开始', colors.active, '2', true);
                if (daysUntilStart === 1) return makeInfo('明天→', colors.waiting, '4');
                if (daysUntilStart === 2) return makeInfo('后天→', colors.waiting, '5');
                if (daysUntilStart <= 7) return makeInfo(`${daysUntilStart}天后→`, colors.waiting, '6');
                return makeInfo(`${daysUntilStart}天后→`, colors.waiting, '7');
            }
            const remainingDays = calcDayDiff(endStartTs);
            if (remainingDays < 0 || nowTs > endEndTs) return makeInfo('过期', colors.overdue, '1', true);
            if (remainingDays === 0) return makeInfo('今天', colors.activeStrong, '1', true);
            if (remainingDays <= 7) return makeInfo(`余${remainingDays}天`, colors.active, '1', true);
            return makeInfo(`余${remainingDays}天`, colors.active, '1');
        }

        if (hasStart) {
            if (nowTs > startEndTs) return makeInfo('开始', colors.active, '2', true);
            const daysUntilStart = calcDayDiff(startStartTs);
            if (daysUntilStart <= 0) return makeInfo('今天', colors.activeStrong, '1', true);
            if (daysUntilStart === 1) return makeInfo('明天→', colors.waiting, '4');
            if (daysUntilStart === 2) return makeInfo('后天→', colors.waiting, '5');
            if (daysUntilStart <= 7) return makeInfo(`${daysUntilStart}天后→`, colors.waiting, '6');
            return makeInfo(`${daysUntilStart}天后→`, colors.waiting, '7');
        }

        return makeInfo('待定', colors.pending, '8');
    }

    function __tmRenderTaskRemainingTimeHtml(task, options = {}) {
        const info = __tmGetTaskRemainingTimeInfo(task, options);
        const weight = info.emphasis ? '700' : '500';
        return `<span style="display:none;">${esc(info.sortPrefix)}</span><span style="color:${esc(info.color)};font-weight:${weight};">${esc(info.label)}</span>`;
    }

    function __tmGetTaskRemainingTimeLabel(task, options = {}) {
        return __tmGetTaskRemainingTimeInfo(task, options).label;
    }

    function __tmExcelGetTimeGroupLabel(task) {
        const info = __tmGetTaskTimePriorityInfo(task);
        const diffDays = Number(info?.diffDays);
        if (!Number.isFinite(diffDays)) return '待定';
        if (diffDays < 0) return '已过期';
        if (diffDays === 0) return '今天';
        if (diffDays === 1) return '明天';
        if (diffDays === 2) return '后天';
        return `余${diffDays}天`;
    }

    function __tmExcelGetQuadrantGroupLabel(task) {
        const quadrantRules = (SettingsStore.data.quadrantConfig && SettingsStore.data.quadrantConfig.rules) || [];
        const priority = String(task?.priority || '').toLowerCase();
        const importance = (priority === 'a' || priority === '高' || priority === 'high')
            ? 'high'
            : ((priority === 'b' || priority === '中' || priority === 'medium')
                ? 'medium'
                : ((priority === 'c' || priority === '低' || priority === 'low') ? 'low' : 'none'));
        const diffDays = Number(__tmGetTaskTimePriorityInfo(task)?.diffDays);
        const timeRange = !Number.isFinite(diffDays)
            ? 'nodate'
            : (diffDays < 0 ? 'overdue' : (diffDays <= 7 ? 'within7days' : (diffDays <= 15 ? 'within15days' : (diffDays <= 30 ? 'within30days' : 'beyond30days'))));
        for (const rule of quadrantRules) {
            const importanceMatch = Array.isArray(rule?.importance) && rule.importance.includes(importance);
            let timeRangeMatch = Array.isArray(rule?.timeRanges) && rule.timeRanges.includes(timeRange);
            if (!timeRangeMatch && Array.isArray(rule?.timeRanges)) {
                for (const range of rule.timeRanges) {
                    if (!String(range || '').startsWith('beyond') || range === 'beyond30days') continue;
                    const days = parseInt(String(range).replace('beyond', '').replace('days', ''), 10);
                    if (!Number.isNaN(days) && diffDays > days) {
                        timeRangeMatch = true;
                        break;
                    }
                }
            }
            if (importanceMatch && timeRangeMatch) return String(rule?.name || '').trim();
        }
        return '';
    }

    function __tmExcelGetGroupLabel(task, rootTask) {
        const root = rootTask || task;
        if (!root) return '';
        if (state.groupByDocName) {
            const labels = [String(root.docName || root.rawDocName || '').trim() || '未命名文档'];
            if (SettingsStore.data.docH2SubgroupEnabled !== false) {
                const bucket = __tmGetDocHeadingBucket(root, __tmExcelGetNoHeadingLabel());
                const headingLabel = String(bucket?.label || '').trim();
                if (headingLabel) labels.push(headingLabel);
            }
            return labels.filter(Boolean).join(' / ');
        }
        if (state.groupByTime) return __tmExcelGetTimeGroupLabel(root);
        if (state.quadrantEnabled) return __tmExcelGetQuadrantGroupLabel(root);
        if (state.groupByTaskName) return String(root.content || '').trim();
        return root?.pinned ? '置顶' : '';
    }

    function __tmExcelGetExportColumnDefs() {
        const headingLevel = String(SettingsStore.data.taskHeadingLevel || 'h2').trim() || 'h2';
        const headingLabels = { h1: '一级标题', h2: '二级标题', h3: '三级标题', h4: '四级标题', h5: '五级标题', h6: '六级标题' };
        const seenColumnKeys = new Set();
        const columnOrder = [];
        const appendColumnKeys = (keys) => {
            (Array.isArray(keys) ? keys : []).forEach((key) => {
                const colKey = String(key || '').trim();
                if (!colKey || seenColumnKeys.has(colKey)) return;
                seenColumnKeys.add(colKey);
                columnOrder.push(colKey);
            });
        };
        appendColumnKeys(Array.isArray(SettingsStore.data.columnOrder) ? SettingsStore.data.columnOrder : []);
        appendColumnKeys(__tmGetDefaultColumnOrder());
        const widthMap = (SettingsStore.data.columnWidths && typeof SettingsStore.data.columnWidths === 'object') ? SettingsStore.data.columnWidths : {};
        const pxToWch = (px, fallback) => {
            const n = Number(px);
            if (!Number.isFinite(n) || n <= 0) return fallback;
            return Math.max(8, Math.min(80, Math.round(n / 8)));
        };
        const defs = {
            pinned: {
                key: 'pinned',
                label: '置顶',
                wch: 6,
                value: (task) => task?.pinned ? '是' : ''
            },
            content: {
                key: 'content',
                label: '任务内容',
                wch: pxToWch(widthMap.content, 36),
                value: (task) => String(task?.content || '').trim()
            },
            status: {
                key: 'status',
                label: '状态',
                wch: pxToWch(widthMap.status, 12),
                value: (task) => __tmExcelResolveStatusName(task)
            },
            score: {
                key: 'score',
                label: '优先级分',
                wch: pxToWch(widthMap.score, 12),
                value: (task) => {
                    const raw = Number(task?.priorityScore);
                    if (Number.isFinite(raw)) return Math.round(raw);
                    try {
                        const computed = Number(__tmComputePriorityScore(task));
                        return Number.isFinite(computed) ? Math.round(computed) : '';
                    } catch (e) {
                        return '';
                    }
                }
            },
            doc: {
                key: 'doc',
                label: '文档',
                wch: pxToWch(widthMap.doc, 22),
                value: (task) => String(task?.docName || task?.rawDocName || '').trim()
            },
            h2: {
                key: 'h2',
                label: headingLabels[headingLevel] || '标题',
                wch: pxToWch(widthMap.h2, 22),
                value: (task) => __tmNormalizeHeadingText(task?.h2)
            },
            priority: {
                key: 'priority',
                label: '重要性',
                wch: pxToWch(widthMap.priority, 10),
                value: (task) => String(__tmGetPriorityJiraInfo(task?.priority)?.label || '').trim()
            },
            startDate: {
                key: 'startDate',
                label: '开始日期',
                kind: 'date',
                wch: pxToWch(widthMap.startDate, 14),
                value: (task) => String(task?.startDate || '').trim()
            },
            completionTime: {
                key: 'completionTime',
                label: '完成日期',
                kind: 'date',
                wch: pxToWch(widthMap.completionTime, 14),
                value: (task) => String(task?.completionTime || '').trim()
            },
            remainingTime: {
                key: 'remainingTime',
                label: '剩余时间',
                wch: pxToWch(widthMap.remainingTime, 14),
                value: (task) => __tmGetTaskRemainingTimeLabel(task)
            },
            duration: {
                key: 'duration',
                label: '时长',
                wch: pxToWch(widthMap.duration, 12),
                value: (task) => String(task?.duration || '').trim()
            },
            spent: {
                key: 'spent',
                label: '耗时',
                wch: pxToWch(widthMap.spent, 12),
                value: (task) => {
                    const mode = String(SettingsStore.data.tomatoSpentAttrMode || 'minutes').trim() || 'minutes';
                    return (SettingsStore.data.enableTomatoIntegration && mode === 'hours')
                        ? String(__tmFormatSpentHours(__tmParseNumber(task?.tomatoHours)) || '').trim()
                        : String(__tmFormatSpentMinutes(__tmGetTaskSpentMinutes(task)) || '').trim();
                }
            },
            remark: {
                key: 'remark',
                label: '备注',
                wch: pxToWch(widthMap.remark, 30),
                value: (task) => String(task?.remark || '').trim()
            }
        };
        __tmGetCustomFieldDefs().forEach((field) => {
            const fieldId = String(field?.id || '').trim();
            const colKey = __tmBuildCustomFieldColumnKey(fieldId);
            if (!fieldId || !colKey) return;
            const fieldType = String(field?.type || '').trim();
            defs[colKey] = {
                key: colKey,
                label: String(field?.name || fieldId).trim() || fieldId,
                wch: pxToWch(widthMap[colKey], fieldType === 'multi' ? 24 : (fieldType === 'text' ? 28 : 18)),
                value: (task) => fieldType === 'text'
                    ? String(__tmNormalizeCustomFieldValue(field, __tmGetTaskCustomFieldValue(task, fieldId)) || '').trim()
                    : __tmResolveCustomFieldSelectedOptions(field, __tmGetTaskCustomFieldValue(task, fieldId))
                        .map((option) => String(option?.name || option?.id || '').trim())
                        .filter(Boolean)
                        .join(', ')
            };
        });
        return columnOrder.map((key) => defs[key]).filter(Boolean);
    }

    function __tmBuildCurrentTableExcelExportModel() {
        const filtered = Array.isArray(state.filteredTasks) ? state.filteredTasks.slice() : [];
        if (filtered.length === 0) return { columns: [], rows: [] };
        const taskMap = new Map(filtered.map((task) => [String(task?.id || '').trim(), task]).filter(([id]) => !!id));
        const depthMemo = new Map();
        const getDepth = (task) => {
            const id = String(task?.id || '').trim();
            if (!id) return 0;
            if (depthMemo.has(id)) return depthMemo.get(id);
            const parentId = String(task?.parentTaskId || '').trim();
            if (!parentId || !taskMap.has(parentId)) {
                depthMemo.set(id, 0);
                return 0;
            }
            const depth = Math.max(0, Math.min(32, getDepth(taskMap.get(parentId)) + 1));
            depthMemo.set(id, depth);
            return depth;
        };
        const prevCollapsedTaskIds = state.collapsedTaskIds instanceof Set ? new Set(state.collapsedTaskIds) : new Set();
        const prevCollapsedGroups = state.collapsedGroups instanceof Set ? new Set(state.collapsedGroups) : new Set();
        let orderedTaskRows = [];
        try {
            state.collapsedTaskIds = new Set();
            state.collapsedGroups = new Set();
            orderedTaskRows = (__tmBuildTaskRowModel() || []).filter((row) => row && row.type === 'task' && row.id);
        } catch (e) {
            orderedTaskRows = filtered.map((task) => ({
                type: 'task',
                id: String(task?.id || '').trim(),
                depth: getDepth(task),
            }));
        } finally {
            state.collapsedTaskIds = prevCollapsedTaskIds;
            state.collapsedGroups = prevCollapsedGroups;
        }
        const exportedTaskIdSet = new Set();
        orderedTaskRows = orderedTaskRows.filter((row) => {
            const id = String(row?.id || '').trim();
            if (!id || exportedTaskIdSet.has(id)) return false;
            exportedTaskIdSet.add(id);
            return true;
        });
        const fixedColumns = [
            { key: '__group', label: '当前分组', wch: 10, value: (_, ctx) => ctx.groupLabel || '' },
            { key: '__depth', label: '层级', wch: 6, value: (_, ctx) => ctx.depth },
            { key: '__done', label: '完成状态', wch: 10, value: (task) => task?.done ? '已完成' : '未完成' },
        ];
        const visibleColumns = __tmExcelGetExportColumnDefs();
        const rows = orderedTaskRows.map((row) => {
            const id = String(row?.id || '').trim();
            const task = taskMap.get(id) || state.flatTasks?.[id] || null;
            if (!task) return null;
            const parentTaskId = String(task?.parentTaskId || '').trim();
            const rootTask = __tmExcelGetVisibleRootTask(task, taskMap) || task;
            return {
                id,
                task,
                depth: Math.max(0, Number(row?.depth) || getDepth(task)),
                groupLabel: __tmExcelGetGroupLabel(task, rootTask),
                parentTaskId,
            };
        }).filter(Boolean);
        return {
            columns: fixedColumns.concat(visibleColumns),
            rows,
        };
    }

    window.tmExportCurrentTableExcel = async function() {
        if (String(state.viewMode || '').trim() !== 'list') {
            hint('⚠️ 仅表格视图支持导出 Excel', 'warning');
            return;
        }
        const cachedXlsx = __tmResolveXlsxRuntime();
        if (!cachedXlsx) hint('⏳ 正在准备 Excel 导出组件...', 'info');
        const XLSX = cachedXlsx || await __tmEnsureXlsxRuntimeLoaded();
        if (!XLSX || !XLSX.utils) {
            hint('❌ Excel 导出组件未加载', 'error');
            return;
        }
        const model = __tmBuildCurrentTableExcelExportModel();
        if (!Array.isArray(model.rows) || model.rows.length === 0) {
            hint('⚠️ 当前没有可导出的任务', 'warning');
            return;
        }
        const columns = Array.isArray(model.columns) ? model.columns : [];
        if (!columns.length) {
            hint('❌ 导出列配置为空', 'error');
            return;
        }
        const aoa = [columns.map((col) => String(col?.label || '').trim())];
        model.rows.forEach((row) => {
            aoa.push(columns.map((col) => {
                const raw = typeof col?.value === 'function' ? col.value(row.task, row) : '';
                if (col?.kind === 'date') {
                    const dt = __tmExcelParseDateCell(raw);
                    return dt || (raw ? String(raw) : '');
                }
                return raw == null ? '' : raw;
            }));
        });
        const ws = XLSX.utils.aoa_to_sheet(aoa);
        ws['!cols'] = columns.map((col) => ({ wch: Math.max(8, Number(col?.wch) || 12) }));
        ws['!rows'] = aoa.map((_, idx) => {
            if (idx === 0) return { level: 0 };
            const depth = Number(model.rows[idx - 1]?.depth) || 0;
            return { level: Math.max(0, Math.min(7, depth)) };
        });
        ws['!outline'] = { above: true };
        if (ws['!ref']) ws['!autofilter'] = { ref: ws['!ref'] };
        columns.forEach((col, colIndex) => {
            if (col?.kind !== 'date') return;
            for (let rowIndex = 1; rowIndex < aoa.length; rowIndex += 1) {
                const cellRef = XLSX.utils.encode_cell({ r: rowIndex, c: colIndex });
                const cell = ws[cellRef];
                if (!cell || (cell.t !== 'd' && cell.t !== 'n')) continue;
                cell.z = 'yyyy-mm-dd';
            }
        });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, '任务导出');
        const filename = __tmExcelSanitizeFileName(`任务管理器_表格导出_${__tmExcelDateStamp()}.xlsx`);
        if (typeof XLSX.writeFileXLSX === 'function') XLSX.writeFileXLSX(wb, filename, { compression: true, cellStyles: true });
        else XLSX.writeFile(wb, filename, { bookType: 'xlsx', compression: true, cellStyles: true });
        hint(`✅ 已导出 Excel（${model.rows.length} 条任务）`, 'success');
    };

    // 新增：导出当前分组任务
    window.exportCurrentGroup = async function() {
        // 从当前DOM中获取当前选中的分组ID
        const groupSelect = document.getElementById('groupSelector');
        const currentId = groupSelect ? groupSelect.value : (SettingsStore.data.currentGroupId || 'all');
        
        if (currentId === 'all') {
            hint('⚠️ 请先选择一个分组进行导出', 'error');
            return;
        }

        // 直接从 taskTree 获取当前页签显示的所有文档和任务
        // taskTree 包含了分组开启"包含子文档"后解析的所有子文档
        const docNames = {};
        const flatTasks = state.flatTasks || {};

        if (!Array.isArray(state.taskTree) || state.taskTree.length === 0) {
            hint('⚠️ 当前没有显示的文档', 'error');
            return;
        }

        // 遍历 taskTree 中当前显示的所有文档，获取文档名称
        state.taskTree.forEach(doc => {
            const docId = String(doc?.id || '').trim();
            if (!docId) return;
            docNames[docId] = doc.name || '未命名文档';
        });

        // 直接从 flatTasks 获取所有任务（包括子任务）
        const tasksByDoc = {};
        
        // 首先获取所有顶级任务（没有 parentTaskId 的）
        Object.values(flatTasks).forEach(task => {
            if (!task || !task.id) return;
            if (task.parentTaskId) return; // 先跳过子任务，稍后处理
            
            const docId = String(task.docId || task.root_id || '').trim();
            if (!docId || !docNames[docId]) return; // 只处理在当前分组的文档
            
            if (!tasksByDoc[docId]) {
                tasksByDoc[docId] = [];
            }
            
            // 添加顶级任务，设置二级标题信息
            const h2Id = task.h2Id || '';
            let h2Name = task.h2 || '';
            if (!h2Name && h2Id) {
                const h2Task = flatTasks[h2Id];
                if (h2Task) h2Name = h2Task.content || '';
            }
            
            tasksByDoc[docId].push({
                ...task,
                h2Id: h2Id,
                h2Name: h2Name,
                level: 0
            });
            
            // 递归收集所有子任务
            const collectChildren = (parentTask, parentH2Id, parentH2Name) => {
                const children = parentTask.children || [];
                children.forEach(child => {
                    if (child && child.id) {
                        // 子任务的h2Id使用父级的
                        tasksByDoc[docId].push({
                            ...child,
                            h2Id: parentH2Id,
                            h2Name: parentH2Name,
                            level: 1
                        });
                        // 递归收集更深层的子任务
                        if (child.children && child.children.length > 0) {
                            collectChildren(child, parentH2Id, parentH2Name);
                        }
                    }
                });
            };
            
            if (task.children && task.children.length > 0) {
                collectChildren(task, h2Id, h2Name);
            }
        });

        // 检查是否有任务
        let totalTasks = 0;
        Object.values(tasksByDoc).forEach(tasks => {
            totalTasks += tasks.length;
        });

        if (totalTasks === 0) {
            hint('⚠️ 当前分组没有任务可导出', 'error');
            return;
        }

        // 获取当前分组名称
        const groups = SettingsStore.data.docGroups || [];
        const group = groups.find(g => g.id === currentId);
        const groupName = group ? __tmResolveDocGroupName(group) : '当前分组';

        // 显示导出设置对话框
        __tmShowExportDialog(groupName, tasksByDoc, docNames);
    };

    // 导出对话框函数
    function __tmShowExportDialog(groupName, tasksByDoc, docNames) {
        // 关闭现有的导出对话框
        if (state.exportModal) {
            try { state.exportModal.remove(); } catch (e) {}
            state.exportModal = null;
        }

        state.exportModal = document.createElement('div');
        state.exportModal.className = 'tm-modal';
        state.exportModal.style.cssText = 'z-index: 200000;';

        const dialog = document.createElement('div');
        dialog.className = 'tm-box';
        dialog.style.cssText = 'width: 480px; max-width: 90vw; height: auto; flex: none;';

        dialog.innerHTML = `
            <div class="tm-header" style="padding: 16px 20px; border-bottom: 1px solid var(--tm-border-color); flex-shrink: 0;">
                <div style="font-size: 16px; font-weight: 600;">导出任务 - ${esc(groupName)}</div>
                <button class="tm-btn tm-btn-gray" data-tm-action="closeExportDialog" style="padding: 4px 8px; font-size: 12px;">✕</button>
            </div>
            <div class="tm-body" style="padding: 20px; flex: 1; overflow-y: auto;">
                <div style="margin-bottom: 16px;">
                    <div style="font-size: 13px; font-weight: 600; margin-bottom: 8px;">导出格式</div>
                    <label style="display: flex; align-items: center; gap: 8px; margin-bottom: 8px; cursor: pointer;">
                        <input type="radio" name="exportFormat" value="markdown" checked>
                        <span style="font-size: 13px;">Markdown (推荐 AI 阅读)</span>
                    </label>
                    <label style="display: flex; align-items: center; gap: 8px; margin-bottom: 8px; cursor: pointer;">
                        <input type="radio" name="exportFormat" value="json">
                        <span style="font-size: 13px;">JSON (结构化数据)</span>
                    </label>
                </div>
                <div style="margin-bottom: 16px;">
                    <div style="font-size: 13px; font-weight: 600; margin-bottom: 8px;">文件名</div>
                    <input type="text" id="exportFilename" value="${esc(groupName)}_任务导出" 
                           style="width: 100%; padding: 8px 12px; border: 1px solid var(--tm-input-border); border-radius: 6px; background: var(--tm-input-bg); color: var(--tm-text-color); font-size: 13px; box-sizing: border-box;">
                </div>
                <div style="margin-bottom: 16px;">
                    <label style="display: flex; align-items: center; gap: 8px; cursor: pointer;">
                        <input type="checkbox" id="exportIncludeDone" checked>
                        <span style="font-size: 13px;">包含已完成任务</span>
                    </label>
                </div>
                <div style="font-size: 12px; color: var(--tm-secondary-text);">
                    共 ${Object.keys(tasksByDoc).length} 个文档，${Object.values(tasksByDoc).reduce((sum, tasks) => sum + tasks.length, 0)} 个任务
                </div>
            </div>
            <div class="tm-header" style="padding: 16px 20px; border-top: 1px solid var(--tm-border-color); justify-content: flex-end; gap: 10px; flex-shrink: 0;">
                <button class="tm-btn tm-btn-secondary" data-tm-action="closeExportDialog" style="padding: 8px 16px;">取消</button>
                <button class="tm-btn tm-btn-primary" data-tm-action="confirmExport" style="padding: 8px 16px;">导出</button>
            </div>
        `;

        state.exportModal.appendChild(dialog);
        document.body.appendChild(state.exportModal);

        // 绑定事件
        const root = state.exportModal;
        root.addEventListener('click', async (e) => {
            const target = e.target?.closest?.('[data-tm-action]');
            if (!target) return;

            const action = String(target.dataset.tmAction || '');
            if (action === 'closeExportDialog') {
                try { state.exportModal.remove(); } catch (e) {}
                state.exportModal = null;
            } else if (action === 'confirmExport') {
                const format = document.querySelector('input[name="exportFormat"]:checked')?.value || 'markdown';
                const filename = document.getElementById('exportFilename')?.value || groupName;
                const includeDone = document.getElementById('exportIncludeDone')?.checked !== false;

                // 执行导出
                __tmDoExport(groupName, tasksByDoc, docNames, format, filename, includeDone);

                try { state.exportModal.remove(); } catch (e) {}
                state.exportModal = null;
            }
        });
    }

    // 执行导出
    function __tmDoExport(groupName, tasksByDoc, docNames, format, filename, includeDone) {
        let content = '';
        let mimeType = 'text/plain';
        let extension = 'txt';

        if (format === 'markdown') {
            content = __tmGenerateMarkdownExport(groupName, tasksByDoc, docNames, includeDone);
            mimeType = 'text/markdown';
            extension = 'md';
        } else {
            content = __tmGenerateJSONExport(tasksByDoc, docNames, includeDone);
            mimeType = 'application/json';
            extension = 'json';
        }

        // 下载文件
        const blob = new Blob([content], { type: mimeType + ';charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${filename}.${extension}`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);

        hint('✅ 任务导出成功', 'success');
    }

    // 生成 Markdown 格式导出
    function __tmGenerateMarkdownExport(groupName, tasksByDoc, docNames, includeDone) {
        const lines = [];
        const now = new Date().toISOString().split('T')[0];

        lines.push(`# ${groupName} - 任务导出`);
        lines.push('');
        lines.push(`> 导出时间：${now}`);
        lines.push('');

        // 按文档分组
        Object.entries(tasksByDoc).forEach(([docId, tasks]) => {
            // 过滤任务
            let filteredTasks = tasks;
            if (!includeDone) {
                filteredTasks = tasks.filter(t => !t.done);
            }

            if (filteredTasks.length === 0) return;

            const docName = docNames[docId] || '未命名文档';
            lines.push(`## 📄 ${docName}`);
            lines.push('');

            // 按二级文档分组
            const tasksByH2 = {};
            filteredTasks.forEach(task => {
                const h2Key = task.h2Id || '__no_h2__';
                const h2Name = task.h2Name || '无二级标题';
                if (!tasksByH2[h2Key]) {
                    tasksByH2[h2Key] = {
                        name: h2Name,
                        tasks: []
                    };
                }
                tasksByH2[h2Key].tasks.push(task);
            });

            // 输出任务
            Object.values(tasksByH2).forEach(h2Group => {
                if (h2Group.name !== '无二级标题') {
                    lines.push(`### ${h2Group.name}`);
                    lines.push('');
                }

                h2Group.tasks.forEach(task => {
                    const checkbox = task.done ? '[x]' : '[ ]';
                    
                    // 根据层级计算缩进
                    const level = task.level || 0;
                    const indent = '  '.repeat(level + 1); // 顶级任务2空格，子任务4空格
                    
                    // 任务内容行
                    let line = `${indent}- ${checkbox} ${task.content || '无内容'}`;

                    // 添加标签信息
                    const tags = [];
                    if (task.priority) {
                        const priorityText = task.priority === 'high' ? '高' : task.priority === 'medium' ? '中' : task.priority === 'low' ? '低' : task.priority;
                        tags.push(`**优先级：${priorityText}**`);
                    }
                    if (task.startDate) {
                        tags.push(`📅 开始：${task.startDate}`);
                    }
                    if (task.completionTime) {
                        tags.push(`🎯 截止：${task.completionTime}`);
                    }
                    if (task.done && task.completionTime) {
                        tags.push(`✨ 已完成：${task.completionTime}`);
                    }
                    if (task.status) {
                        tags.push(`📌 状态：${task.status}`);
                    }

                    if (tags.length > 0) {
                        line += ` ${tags.join(' | ')}`;
                    }

                    lines.push(line);

                    // 添加备注（如果存在）
                    if (task.remark) {
                        lines.push(`${indent}  > 备注：${task.remark}`);
                    }
                });

                lines.push('');
            });
        });

        // 添加汇总信息
        const totalTasks = Object.values(tasksByDoc).reduce((sum, tasks) => sum + tasks.length, 0);
        const doneTasks = Object.values(tasksByDoc).reduce((sum, tasks) => sum + tasks.filter(t => t.done).length, 0);
        const pendingTasks = totalTasks - doneTasks;

        lines.push('---');
        lines.push('');
        lines.push('## 📊 汇总统计');
        lines.push('');
        lines.push(`- 总任务数：${totalTasks}`);
        lines.push(`- 已完成：${doneTasks}`);
        lines.push(`- 待完成：${pendingTasks}`);
        lines.push(`- 完成率：${totalTasks > 0 ? Math.round(doneTasks / totalTasks * 100) : 0}%`);
        lines.push('');

        return lines.join('\n');
    }

    // 生成 JSON 格式导出
    function __tmGenerateJSONExport(tasksByDoc, docNames, includeDone) {
        const exportData = {
            exportTime: new Date().toISOString(),
            documents: []
        };

        Object.entries(tasksByDoc).forEach(([docId, tasks]) => {
            let filteredTasks = tasks;
            if (!includeDone) {
                filteredTasks = tasks.filter(t => !t.done);
            }

            if (filteredTasks.length === 0) return;

            const docData = {
                docId: docId,
                docName: docNames[docId] || '未命名文档',
                tasks: filteredTasks.map(task => ({
                    content: task.content || '',
                    done: !!task.done,
                    priority: task.priority || null,
                    status: task.status || null,
                    startDate: task.startDate || null,
                    completionTime: task.completionTime || null,
                    duration: task.duration || null,
                    remark: task.remark || null,
                    h2Id: task.h2Id || null,
                    h2Name: task.h2Name || null,
                    id: task.id || null
                }))
            };

            exportData.documents.push(docData);
        });

        // 添加统计信息
        const totalTasks = exportData.documents.reduce((sum, doc) => sum + doc.tasks.length, 0);
        const doneTasks = exportData.documents.reduce((sum, doc) => sum + doc.tasks.filter(t => t.done).length, 0);
        exportData.stats = {
            total: totalTasks,
            done: doneTasks,
            pending: totalTasks - doneTasks,
            completionRate: totalTasks > 0 ? Math.round(doneTasks / totalTasks * 100) : 0
        };

        return JSON.stringify(exportData, null, 2);
    };

    // 新增：清空当前分组文档
    window.clearCurrentGroupDocs = async function() {
        if (!confirm('确定要清空当前分组的所有文档吗？')) return;
        
        const currentId = SettingsStore.data.currentGroupId;
        if (currentId === 'all') return;
        
        const groups = SettingsStore.data.docGroups || [];
        const group = groups.find(g => g.id === currentId);
        if (group) {
            group.docs = [];
            group.excludedDocIds = [];
            delete group.notebookId;
            await SettingsStore.updateDocGroups(groups);
            showSettings();
        }
    };

    // 新增：从分组移除文档
    window.removeDocFromGroup = async function(index) {
        const currentId = SettingsStore.data.currentGroupId;
        if (currentId === 'all') return;
        
        const groups = SettingsStore.data.docGroups || [];
        const group = groups.find(g => g.id === currentId);
        if (group && group.docs) {
            const removed = group.docs.splice(index, 1)[0];
            const removedDocId = String((typeof removed === 'object' ? removed?.id : removed) || '').trim();
            if (removedDocId) {
                group.excludedDocIds = __tmGetGroupExcludedDocIds(group).filter((id) => id !== removedDocId);
            }
            await SettingsStore.updateDocGroups(groups);
            showSettings();
        }
    };

    window.removeExcludedDocFromCurrentGroup = async function(docId) {
        const currentId = String(SettingsStore.data.currentGroupId || 'all').trim() || 'all';
        const result = await __tmSetDocExcludedForGroup(docId, false, currentId);
        if (!result?.changed) {
            hint('⚠ 该文档不在排除列表中', 'warning');
            return;
        }
        hint('✅ 已从排除列表移出，文档会重新显示', 'success');
    };

    window.removeDocFromAll = async function(docId) {
        const id = String(docId || '').trim();
        if (!id) return;

        let changed = false;

        try {
            const legacy = Array.isArray(SettingsStore.data.selectedDocIds) ? SettingsStore.data.selectedDocIds : [];
            const nextLegacy = legacy.filter(x => String(x) !== id);
            if (nextLegacy.length !== legacy.length) {
                SettingsStore.data.selectedDocIds = nextLegacy;
                changed = true;
            }
        } catch (e) {}

        try {
            const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
            let groupsChanged = false;
            groups.forEach(g => {
                if (!g || !Array.isArray(g.docs)) return;
                const before = g.docs.length;
                g.docs = g.docs.filter(d => String((typeof d === 'object' ? d?.id : d) || '') !== id);
                const excludedBefore = __tmGetGroupExcludedDocIds(g);
                g.excludedDocIds = excludedBefore.filter((item) => item !== id);
                if (g.excludedDocIds.length !== excludedBefore.length) groupsChanged = true;
                if (g.docs.length !== before) groupsChanged = true;
            });
            if (groupsChanged) {
                SettingsStore.data.docGroups = groups;
                changed = true;
            }
        } catch (e) {}

        try {
            const excludedAll = __tmGetAllDocsExcludedDocIds();
            const nextExcludedAll = excludedAll.filter((item) => item !== id);
            if (nextExcludedAll.length !== excludedAll.length) {
                SettingsStore.data.allDocsExcludedDocIds = nextExcludedAll;
                changed = true;
            }
        } catch (e) {}

        try {
            const pinMap = (SettingsStore.data.docPinnedByGroup && typeof SettingsStore.data.docPinnedByGroup === 'object')
                ? SettingsStore.data.docPinnedByGroup
                : {};
            let pinChanged = false;
            Object.keys(pinMap).forEach((gid) => {
                const arr = Array.isArray(pinMap[gid]) ? pinMap[gid] : [];
                const next = arr.map(x => String(x || '').trim()).filter(Boolean).filter(x => x !== id);
                if (next.length !== arr.length) {
                    pinMap[gid] = next;
                    pinChanged = true;
                }
            });
            if (pinChanged) {
                SettingsStore.data.docPinnedByGroup = pinMap;
                changed = true;
            }
        } catch (e) {}

        try {
            if (String(SettingsStore.data.defaultDocId || '').trim() === id) {
                SettingsStore.data.defaultDocId = '';
                changed = true;
            }
        } catch (e) {}

        if (!changed) {
            hint('⚠ 未找到该文档', 'warning');
            return;
        }

        await SettingsStore.save();
        state.selectedDocIds = SettingsStore.data.selectedDocIds;
        showSettings();
    };

    // 手动添加文档ID（增强版）
    window.addManualDoc = async function() {
        const input = document.getElementById('manualDocId');
        const recursiveCheck = document.getElementById('recursiveCheck');
        const docId = input.value.trim();
        const isRecursive = recursiveCheck ? recursiveCheck.checked : false;

        if (!docId) {
            hint('⚠ 请输入文档ID', 'warning');
            return;
        }

        // 验证ID格式（思源笔记ID格式：数字-字母数字组合）
        if (!/^[0-9]+-[a-zA-Z0-9]+$/.test(docId)) {
            hint('⚠ 文档ID格式不正确，格式应为：数字-字母数字组合', 'warning');
            return;
        }

        const currentGroupId = SettingsStore.data.currentGroupId || 'all';
        
        if (currentGroupId === 'all') {
            // 添加到旧版列表（不支持递归标志，或者我们需要升级旧版列表结构）
            // 为了兼容，我们在 "全部" 模式下只操作 selectedDocIds
            if (isRecursive) {
                hint('⚠ "全部文档"模式下不支持递归选项，请先创建或选择一个分组', 'warning');
                return;
            }
            if (SettingsStore.data.selectedDocIds.includes(docId)) {
                hint('⚠ 该文档已被添加', 'warning');
                return;
            }
            await SettingsStore.addDocId(docId);
        } else {
            // 添加到当前分组
            const groups = SettingsStore.data.docGroups || [];
            const group = groups.find(g => g.id === currentGroupId);
            if (group) {
                if (!group.docs) group.docs = [];
                // 检查重复
                if (group.docs.some(d => d.id === docId)) {
                    hint('⚠ 该文档已在当前分组中', 'warning');
                    return;
                }
                group.docs.push({ id: docId, recursive: isRecursive });
                await SettingsStore.updateDocGroups(groups);
            }
        }

        // 尝试获取文档名称
        fetchDocMeta(docId).then((docMeta) => {
            if (docMeta?.name) {
                state.allDocuments.push({ id: docId, name: docMeta.name, alias: '', icon: __tmNormalizeDocIconValue(docMeta.icon), path: '', taskCount: 0 });
            }
            showSettings(); // 重新渲染设置界面
        });

        input.value = '';
        if (recursiveCheck) recursiveCheck.checked = false;
        hint('✅ 已添加文档', 'success');
    };

    async function __tmAddDocsToGroup(docIdsInput, groupId, options = {}) {
        const docIds = __tmNormalizeDocIdsForGroupInput(docIdsInput);
        const targetGroupId = String(groupId || '').trim();
        if (!docIds.length) {
            hint('⚠ 未找到可添加的文档', 'warning');
            return { added: 0, existed: 0, group: null };
        }
        if (!targetGroupId) {
            hint('⚠ 请选择目标分组', 'warning');
            return { added: 0, existed: 0, group: null };
        }

        const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
        const group = groups.find((item) => String(item?.id || '').trim() === targetGroupId);
        if (!group) {
            hint('⚠ 目标分组不存在', 'warning');
            return { added: 0, existed: 0, group: null };
        }

        if (!Array.isArray(group.docs)) group.docs = [];
        let added = 0;
        let existed = 0;
        docIds.forEach((docId) => {
            const exists = group.docs.some((item) => String((typeof item === 'object' ? item?.id : item) || '').trim() === docId);
            if (exists) {
                existed += 1;
                return;
            }
            group.docs.push({ id: docId, recursive: false });
            added += 1;
        });

        if (!added) {
            const groupName = __tmResolveDocGroupName(group);
            hint(docIds.length > 1 ? `⚠ 所选文档已都在分组“${groupName}”中` : `⚠ 该文档已在分组“${groupName}”中`, 'warning');
            return { added: 0, existed, group };
        }

        await SettingsStore.updateDocGroups(groups);

        await Promise.allSettled(docIds.map(async (docId) => {
            const docMeta = await fetchDocMeta(docId);
            if (!docMeta?.name) return;
            if (!Array.isArray(state.allDocuments)) state.allDocuments = [];
            const exists = state.allDocuments.some((item) => String(item?.id || '').trim() === docId);
            if (!exists) state.allDocuments.push({ id: docId, name: docMeta.name, alias: '', icon: __tmNormalizeDocIconValue(docMeta.icon), path: '', taskCount: 0 });
        }));

        try {
            const currentGroupId = String(SettingsStore.data.currentGroupId || 'all').trim() || 'all';
            if (currentGroupId === targetGroupId || currentGroupId === 'all' || options.forceRefresh) {
                await loadSelectedDocuments();
                render();
                if (state.settingsModal) showSettings();
            }
        } catch (e) {}

        return { added, existed, group };
    }

    window.tmOpenAddDocToGroupDialog = async function(docIdsInput, options = {}) {
        const docIds = __tmNormalizeDocIdsForGroupInput(docIdsInput);
        if (!docIds.length) {
            hint('⚠ 未找到当前文档', 'warning');
            return;
        }

        const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
        if (!groups.length) {
            hint('⚠ 请先在任务管理器中创建文档分组', 'warning');
            return;
        }

        const currentGroupId = String(SettingsStore.data.currentGroupId || '').trim();
        const defaultGroupId = groups.some((item) => String(item?.id || '').trim() === currentGroupId)
            ? currentGroupId
            : String(groups[0]?.id || '').trim();
        const selectOptions = groups.map((group) => ({
            value: String(group?.id || '').trim(),
            label: __tmResolveDocGroupName(group)
        })).filter((item) => item.value);
        if (!selectOptions.length) {
            hint('⚠ 当前没有可用的文档分组', 'warning');
            return;
        }

        let title = '添加到任务管理器分组';
        if (docIds.length > 1) {
            title = `添加 ${docIds.length} 个文档到任务管理器分组`;
        }

        const selectedGroupId = await showSelectPrompt(title, selectOptions, defaultGroupId);
        if (!selectedGroupId) return;

        const result = await __tmAddDocsToGroup(docIds, selectedGroupId, options);
        if (!result?.group || !result.added) return;

        const groupName = __tmResolveDocGroupName(result.group);
        if (result.existed > 0) {
            hint(`✅ 已添加 ${result.added} 个文档到“${groupName}”，${result.existed} 个已存在`, 'success');
            return;
        }
        hint(docIds.length > 1 ? `✅ 已将 ${result.added} 个文档添加到“${groupName}”` : `✅ 已添加到分组“${groupName}”`, 'success');
    };

    window.tmOpenAddOtherBlocksToGroupDialog = async function(blockIdsInput, options = {}) {
        const blockIds = __tmNormalizeOtherBlockRefs(Array.isArray(blockIdsInput) ? blockIdsInput : [blockIdsInput]).map((item) => item.id);
        if (!blockIds.length) {
            hint('⚠ 未找到当前块', 'warning');
            return;
        }

        const groups = Array.isArray(SettingsStore.data.docGroups) ? SettingsStore.data.docGroups : [];
        if (!groups.length) {
            hint('⚠ 请先在任务管理器中创建文档分组', 'warning');
            return;
        }

        const currentGroupId = __tmResolveOtherBlockGroupId();
        const defaultGroupId = groups.some((item) => String(item?.id || '').trim() === currentGroupId)
            ? currentGroupId
            : String(groups[0]?.id || '').trim();
        const selectOptions = groups.map((group) => ({
            value: String(group?.id || '').trim(),
            label: __tmResolveDocGroupName(group)
        })).filter((item) => item.value);
        if (!selectOptions.length) {
            hint('⚠ 当前没有可用的文档分组', 'warning');
            return;
        }

        const title = blockIds.length > 1 ? `添加 ${blockIds.length} 个块到其他块页签` : '添加到其他块页签';
        const selectedGroupId = await showSelectPrompt(title, selectOptions, defaultGroupId);
        if (!selectedGroupId) return;

        const result = await __tmAddOtherBlocksToCollection(blockIds, selectedGroupId, options);
        if (!result?.group || !result.added) return;

        const groupName = __tmResolveDocGroupName(result.group);
        if (result.existed > 0) {
            hint(blockIds.length > 1
                ? `✅ 已添加 ${result.added} 个块到“${groupName}”，${result.existed} 个已存在`
                : `✅ 已添加到“${groupName}”，该分组中已有 ${result.existed} 个重复块`, 'success');
            return;
        }
        hint(blockIds.length > 1 ? `✅ 已将 ${result.added} 个块添加到“${groupName}”` : `✅ 已添加到“${groupName}”`, 'success');
    };

    window.tmAutoAddOtherBlocksToCurrentGroup = async function(blockIdsInput, options = {}) {
        const blockIds = __tmNormalizeOtherBlockRefs(Array.isArray(blockIdsInput) ? blockIdsInput : [blockIdsInput]).map((item) => item.id);
        if (!blockIds.length) return { added: 0, existed: 0, invalid: 0, group: null, reason: 'empty' };
        const targetGroupId = __tmResolveAutoOtherBlockTargetGroupId(options?.groupId);
        if (!targetGroupId) {
            return { added: 0, existed: 0, invalid: 0, group: null, reason: 'no-group' };
        }
        return await __tmAddOtherBlocksToCollection(blockIds, targetGroupId, {
            ...options,
            silent: options?.silent !== false,
            forceRefresh: options?.forceRefresh !== false,
        });
    };

    // 根据ID获取文档元数据
    async function fetchDocMeta(docId) {
        try {
            const sql = `SELECT content, hpath, ial FROM blocks WHERE id = '${docId}' AND type = 'd' LIMIT 1`;
            const res = await API.call('/api/query/sql', { stmt: sql });
            if (res.code === 0 && res.data && res.data.length > 0) {
                const row = res.data[0] || {};
                return {
                    name: row.content || '未命名文档',
                    icon: __tmNormalizeDocIconValue(__tmReadIalAttrValue(row.ial, 'icon'))
                };
            }
        } catch (e) {
        }
        return null;
    }

