        SettingsStore.data.docGroups = groups.map((item) => __tmNormalizeDocGroupConfig(item, SettingsStore.data.docDefaultColorScheme)).filter(Boolean);
        __tmCalendarDocWindowCache.clear();
        await SettingsStore.save();
