        try { ev?.preventDefault?.(); } catch (e) {}
        const m = String(mode || '').trim().toLowerCase();
        const next = m === 'heading';
        const prev = SettingsStore.data.kanbanHeadingGroupMode === true;
        if (next === prev) return;
