    window.tmSetWhiteboardLayoutModeFromMobileMenu = async function(mode, ev) {
        try { ev?.stopPropagation?.(); } catch (e) {}
        try { ev?.preventDefault?.(); } catch (e) {}
        if (String(state.viewMode || '').trim() !== 'whiteboard') return;
        const next = __tmNormalizeWhiteboardAllTabsLayoutMode(mode);
        const prev = __tmGetWhiteboardAllTabsLayoutMode();
        const activeDocId = String(state.activeDocId || 'all').trim() || 'all';
        const needSwitchAllTabs = activeDocId !== 'all';
        if (!needSwitchAllTabs && next === prev) {
            try { window.tmHideMobileMenu?.(); } catch (e) {}
            return;
        }
        if (needSwitchAllTabs) {
            await window.tmSwitchDoc('all');
            if (next === prev) {
                try { hint(next === 'stream' ? '✅ 已切换到卡片流' : '✅ 已切换到白板', 'success'); } catch (e) {}
                try { window.tmHideMobileMenu?.(); } catch (e) {}
                return;
            }
        }
        await window.tmSetWhiteboardAllTabsLayoutMode(next, ev);
    };

    window.tmWhiteboardAllTabsDocDragStart = function(ev, docId) {
        if (!__tmIsWhiteboardAllTabsStreamMode()) return;
        const id = String(docId || '').trim();
        if (!id) return;
        state.whiteboardAllTabsDocDragId = id;
        try {
            if (ev?.dataTransfer) {
                ev.dataTransfer.effectAllowed = 'move';
                ev.dataTransfer.setData('text/plain', id);
            }
        } catch (e) {}
        __tmClearWhiteboardAllTabsDocDragMarkers();
        try {
            const card = ev?.target instanceof Element ? ev.target.closest('.tm-whiteboard-stream-doc[data-doc-id]') : null;
            card?.classList?.add?.('tm-whiteboard-stream-doc--dragging');
        } catch (e) {}
    };

    window.tmWhiteboardAllTabsDocDragEnd = function() {
        state.whiteboardAllTabsDocDragId = '';
        __tmClearWhiteboardAllTabsDocDragMarkers();
    };

    window.tmWhiteboardAllTabsDocDragOver = function(ev, docId) {
        if (!__tmIsWhiteboardAllTabsStreamMode()) return;
        const sourceId = String(state.whiteboardAllTabsDocDragId || '').trim();
        const targetId = String(docId || '').trim();
        if (!sourceId || !targetId || sourceId === targetId) return;
        try { ev?.preventDefault?.(); } catch (e) {}
        try { if (ev?.dataTransfer) ev.dataTransfer.dropEffect = 'move'; } catch (e) {}
        const card = ev?.target instanceof Element ? ev.target.closest('.tm-whiteboard-stream-doc[data-doc-id]') : null;
        if (!(card instanceof HTMLElement)) return;
        const rect = card.getBoundingClientRect();
        const pos = (Number(ev?.clientY) - rect.top) > (rect.height / 2) ? 'after' : 'before';
        __tmClearWhiteboardAllTabsDocDragMarkers();
        card.classList.add(pos === 'after' ? 'tm-whiteboard-stream-doc--drag-after' : 'tm-whiteboard-stream-doc--drag-before');
        try {
            const sourceCard = state.modal?.querySelector?.(`.tm-whiteboard-stream-doc[data-doc-id="${CSS.escape(sourceId)}"]`);
            sourceCard?.classList?.add?.('tm-whiteboard-stream-doc--dragging');
        } catch (e) {}
    };

    window.tmWhiteboardAllTabsDocDrop = async function(ev, docId) {
        if (!__tmIsWhiteboardAllTabsStreamMode()) return;
        try { ev?.preventDefault?.(); } catch (e) {}
        try { ev?.stopPropagation?.(); } catch (e) {}
        const sourceId = String(state.whiteboardAllTabsDocDragId || '').trim()
            || String(ev?.dataTransfer?.getData?.('text/plain') || '').trim();
        const targetId = String(docId || '').trim();
        if (!sourceId || !targetId || sourceId === targetId) {
            __tmClearWhiteboardAllTabsDocDragMarkers();
            return;
        }
        const visibleIds = Array.from(new Set((Array.isArray(state.whiteboardAllTabsVisibleDocIds) ? state.whiteboardAllTabsVisibleDocIds : []).map((id) => String(id || '').trim()).filter(Boolean)));
        if (!visibleIds.includes(sourceId) || !visibleIds.includes(targetId)) {
            __tmClearWhiteboardAllTabsDocDragMarkers();
            return;
        }
        const card = ev?.target instanceof Element ? ev.target.closest('.tm-whiteboard-stream-doc[data-doc-id]') : null;
        let insertAfter = false;
        if (card instanceof HTMLElement) {
            const rect = card.getBoundingClientRect();
            insertAfter = (Number(ev?.clientY) - rect.top) > (rect.height / 2);
        }
        const nextVisible = visibleIds.filter((id) => id !== sourceId);
        const targetIndex = nextVisible.indexOf(targetId);
        const insertIndex = targetIndex < 0 ? nextVisible.length : Math.max(0, Math.min(nextVisible.length, targetIndex + (insertAfter ? 1 : 0)));
        nextVisible.splice(insertIndex, 0, sourceId);
        const groupId = String(SettingsStore.data.currentGroupId || 'all').trim() || 'all';
        const storedIds = Array.isArray(__tmGetWhiteboardAllTabsDocOrderByGroupMap()[groupId])
            ? __tmGetWhiteboardAllTabsDocOrderByGroupMap()[groupId]
            : [];
        const baseIds = Array.isArray(state.whiteboardAllTabsBaseDocIds) ? state.whiteboardAllTabsBaseDocIds : [];
        const remainder = [];
        const pushRemainder = (id0) => {
            const id = String(id0 || '').trim();
            if (!id || nextVisible.includes(id) || remainder.includes(id)) return;
            remainder.push(id);
        };
        storedIds.forEach(pushRemainder);
        baseIds.forEach(pushRemainder);
        state.whiteboardAllTabsVisibleDocIds = nextVisible.slice();
        __tmSetWhiteboardAllTabsDocOrder(groupId, nextVisible.concat(remainder));
        state.whiteboardAllTabsDocDragId = '';
        __tmClearWhiteboardAllTabsDocDragMarkers();
        try { await SettingsStore.save(); } catch (e) {}
        render();
    };

    window.tmToggleGroupCollapse = async function(groupKey, ev) {
        try {
            ev?.stopPropagation?.();
            ev?.preventDefault?.();
        } catch (e) {}
        const isChecklist = String(state.viewMode || '').trim() === 'checklist';
        const isCalendarSidebarChecklist = __tmHasCalendarSidebarChecklist(state.modal);

        const k0 = String(groupKey || '').trim();
        const action = state.collapsedGroups.has(k0) ? 'expand' : 'collapse';
        const mode = __tmGetCollapseAnimMode();
        const flipOpts = { kind: 'group', key: k0, action, lite: mode === 'lite' };
        let skipAnim = mode === 'none';
        try {
            const tbody = __tmGetActiveTbody(state.modal);
            const n = __tmCountAffectedRowsForCollapse(tbody, flipOpts, 161);
            if (n > 240) skipAnim = true;
            else if (n > 120 && !skipAnim) flipOpts.lite = true;
        } catch (e) {}
        if (!skipAnim) {
            try { __tmPrepareFlipAnimation(flipOpts); } catch (e) {}
        } else {
            try { __tmResetFlipState(state.modal); } catch (e) {}
        }
        
        if (state.collapsedGroups.has(groupKey)) state.collapsedGroups.delete(groupKey);
        else state.collapsedGroups.add(groupKey);

        SettingsStore.data.collapsedGroups = [...state.collapsedGroups];
        // 直接同步到本地存储，不等待云端同步，避免延迟
        try { Storage.set('tm_collapsed_groups', SettingsStore.data.collapsedGroups); } catch (e) {}
        const persistCollapsedGroups = () => {
            try {
                const p = SettingsStore.save();
                if (p && typeof p.catch === 'function') p.catch(() => null);
            } catch (e) {}
        };
        if (isChecklist) {
            persistCollapsedGroups();
            __tmRenderChecklistPreserveScroll();
            return;
        }
        if (isCalendarSidebarChecklist) {
            persistCollapsedGroups();
            __tmRefreshCalendarSidebarChecklistPreserveScroll();
            return;
        }
        try { __tmUpdateToggleGlyphInDom({ kind: 'group', key: k0, action }); } catch (e) {}
        if (action === 'collapse') {
            if (state.modal && __tmApplyVisibilityFromState(state.modal)) {
                persistCollapsedGroups();
                if (!skipAnim) {
                    try { queueMicrotask(() => { try { __tmRunFlipAnimation(state.modal); } catch (e) {} }); } catch (e) {}
                }
                return;
            }
            persistCollapsedGroups();
            __tmScheduleCollapseRerender();
            return;
        }
        persistCollapsedGroups();
        __tmScheduleCollapseRerender();
    };

    window.tmToggleCollapse = async function(id, ev) {
        try {
            ev?.stopPropagation?.();
            ev?.preventDefault?.();
        } catch (e) {}
        const isChecklist = String(state.viewMode || '').trim() === 'checklist';
        const isCalendarSidebarChecklist = __tmHasCalendarSidebarChecklist(state.modal);
        const isListView = String(state.viewMode || '').trim() === 'list';
        const key = String(id || '');
        if (!key) return;

        const action = state.collapsedTaskIds.has(key) ? 'expand' : 'collapse';
        const useFastListCollapse = !isChecklist && isListView && action === 'collapse';
        const mode = useFastListCollapse ? 'none' : __tmGetCollapseAnimMode();
        const flipOpts = { kind: 'task', key, action, lite: mode === 'lite' };
        let skipAnim = mode === 'none' || useFastListCollapse;
        if (!useFastListCollapse) {
            try {
                const tbody = __tmGetActiveTbody(state.modal);
                const n = __tmCountAffectedRowsForCollapse(tbody, flipOpts, 161);
                if (n > 240) skipAnim = true;
                else if (n > 120 && !skipAnim) flipOpts.lite = true;
            } catch (e) {}
        }
        if (!skipAnim) {
            try { __tmPrepareFlipAnimation(flipOpts); } catch (e) {}
        } else {
            try { __tmResetFlipState(state.modal); } catch (e) {}
        }
        if (state.collapsedTaskIds.has(key)) state.collapsedTaskIds.delete(key);
        else state.collapsedTaskIds.add(key);

        // 直接同步到本地存储，不等待云端同步，避免延迟
        SettingsStore.data.collapsedTaskIds = [...state.collapsedTaskIds];
        try { Storage.set('tm_collapsed_task_ids', SettingsStore.data.collapsedTaskIds); } catch (e) {}
        const persistCollapsedTasks = () => {
            try {
                const p = SettingsStore.save();
                if (p && typeof p.catch === 'function') p.catch(() => null);
            } catch (e) {}
        };
        if (isChecklist) {
            persistCollapsedTasks();
            __tmRenderChecklistPreserveScroll();
            return;
        }
        if (isCalendarSidebarChecklist) {
            persistCollapsedTasks();
            __tmRefreshCalendarSidebarChecklistPreserveScroll();
            return;
        }
        try { __tmUpdateToggleGlyphInDom({ kind: 'task', key, action }); } catch (e) {}
        if (action === 'collapse') {
            if (useFastListCollapse && state.modal && __tmTryCollapseTaskBranchInList(state.modal, key)) {
                persistCollapsedTasks();
                return;
            }
            if (state.modal && __tmApplyVisibilityFromState(state.modal)) {
                persistCollapsedTasks();
                if (!skipAnim) {
                    try { queueMicrotask(() => { try { __tmRunFlipAnimation(state.modal); } catch (e) {} }); } catch (e) {}
                }
                return;
            }
            persistCollapsedTasks();
            __tmScheduleCollapseRerender();
            return;
        }
        persistCollapsedTasks();
        __tmScheduleCollapseRerender();
    };

    function __tmCollectVisibleGroupKeysFromDom() {
        const modal = state.modal;
        if (!(modal instanceof HTMLElement)) return [];
        const keys = new Set();
        modal.querySelectorAll?.('[data-group-key]').forEach((el) => {
            const key = String(el?.getAttribute?.('data-group-key') || '').trim();
            if (key) keys.add(key);
        });
        return Array.from(keys);
    }

    window.tmCollapseAllTasks = async function() {
        if (state.viewMode === 'kanban' || state.viewMode === 'whiteboard') {
            const filtered = Array.isArray(state.filteredTasks) ? state.filteredTasks : [];
            const collapsed = __tmKanbanGetCollapsedSet();
            filtered.forEach(t => {
                const id = String(t?.id || '').trim();
                if (!id) return;
                const kids = Array.isArray(t?.children) ? t.children : [];
                if (!kids.length) return;
                // 子任务可能因为已完成列等原因不在同列显示，但父任务仍应纳入“全部折叠”。
                collapsed.add(id);
            });
            __tmKanbanPersistCollapsed();
            render();
            return;
        }
        const filteredSet = new Set(state.filteredTasks.map(t => t.id));
        const next = new Set(state.collapsedTaskIds || []);
        const applyCollapse = (list) => {
            list.forEach(t => {
                const hasVisibleChild = (t.children || []).some(c => filteredSet.has(c.id));
                if (filteredSet.has(t.id) && hasVisibleChild) {
                    next.add(String(t.id));
                }
                if (t.children && t.children.length > 0) applyCollapse(t.children);
            });
        };
        state.taskTree.forEach(doc => {
            if (state.activeDocId !== 'all' && doc.id !== state.activeDocId) return;
            applyCollapse(doc.tasks || []);
        });
        state.collapsedTaskIds = next;
        SettingsStore.data.collapsedTaskIds = [...next];
        try { Storage.set('tm_collapsed_task_ids', SettingsStore.data.collapsedTaskIds); } catch (e) {}
        if (SettingsStore.data.collapseAllIncludesGroups) {
            const nextGroups = new Set(state.collapsedGroups || []);
            __tmCollectVisibleGroupKeysFromDom().forEach((key) => nextGroups.add(key));
            state.collapsedGroups = nextGroups;
            SettingsStore.data.collapsedGroups = [...nextGroups];
            try { Storage.set('tm_collapsed_groups', SettingsStore.data.collapsedGroups); } catch (e) {}
        }
        try { __tmResetFlipState(state.modal); } catch (e) {}
        if (!(state.modal && __tmApplyVisibilityFromState(state.modal))) {
            if (!__tmRerenderCollapseInPlace()) render();
        }
        await SettingsStore.save();
    };

    window.tmExpandAllTasks = async function() {
        if (state.viewMode === 'kanban' || state.viewMode === 'whiteboard') {
            __tmKanbanGetCollapsedSet().clear();
            __tmKanbanPersistCollapsed();
            render();
            return;
        }
        state.collapsedTaskIds = new Set();
        SettingsStore.data.collapsedTaskIds = [];
        try { Storage.set('tm_collapsed_task_ids', []); } catch (e) {}
        if (SettingsStore.data.collapseAllIncludesGroups) {
            const visibleGroupKeys = new Set(__tmCollectVisibleGroupKeysFromDom());
            const nextGroups = new Set(Array.from(state.collapsedGroups || []).filter((key) => !visibleGroupKeys.has(String(key || '').trim())));
            state.collapsedGroups = nextGroups;
            SettingsStore.data.collapsedGroups = [...nextGroups];
            try { Storage.set('tm_collapsed_groups', SettingsStore.data.collapsedGroups); } catch (e) {}
        }
        try { __tmResetFlipState(state.modal); } catch (e) {}
        if (!__tmRerenderCollapseInPlace()) render();
        await SettingsStore.save();
    };

    window.closeSettings = function() {
        state.__settingsUnstack?.();
        state.__settingsUnstack = null;
        if (state.settingsModal) {
            state.settingsModal.remove();
            state.settingsModal = null;
        }
        state.settingsSectionJump = null;
    };

    window.tmUpdateAiEnabled = async function(enabled) {
        SettingsStore.data.aiEnabled = !!enabled;
        await SettingsStore.save();
        showSettings();
    };
    window.tmUpdateAiProvider = async function(value) {
        SettingsStore.data.aiProvider = String(value || '').trim() === 'deepseek' ? 'deepseek' : 'minimax';
        await SettingsStore.save();
        showSettings();
    };
    window.tmUpdateAiApiKey = async function(value) {
        const provider = String(SettingsStore.data.aiProvider || '').trim() === 'deepseek' ? 'deepseek' : 'minimax';
        if (provider === 'deepseek') SettingsStore.data.aiDeepSeekApiKey = String(value || '').trim();
        else SettingsStore.data.aiMiniMaxApiKey = String(value || '').trim();
        await SettingsStore.save();
    };
    window.tmUpdateAiBaseUrl = async function(value) {
        const provider = String(SettingsStore.data.aiProvider || '').trim() === 'deepseek' ? 'deepseek' : 'minimax';
        const next = String(value || '').trim() || (provider === 'deepseek' ? 'https://api.deepseek.com' : 'https://api.minimaxi.com/anthropic');
        if (provider === 'deepseek') SettingsStore.data.aiDeepSeekBaseUrl = next.replace(/\/+$/, '');
        else SettingsStore.data.aiMiniMaxBaseUrl = next.replace(/\/+$/, '');
        await SettingsStore.save();
    };
    window.tmUpdateAiModel = async function(value) {
        const provider = String(SettingsStore.data.aiProvider || '').trim() === 'deepseek' ? 'deepseek' : 'minimax';
        if (provider === 'deepseek') SettingsStore.data.aiDeepSeekModel = String(value || '').trim() || 'deepseek-chat';
        else SettingsStore.data.aiMiniMaxModel = String(value || '').trim() || 'MiniMax-M2.5';
        await SettingsStore.save();
    };
    window.tmUpdateAiTemperature = async function(value) {
        const n = Number(value);
        SettingsStore.data.aiMiniMaxTemperature = Number.isFinite(n) ? Math.max(0, Math.min(1.5, n)) : 0.2;
        await SettingsStore.save();
    };
    window.tmUpdateAiMaxTokens = async function(value) {
        const n = Number(value);
        SettingsStore.data.aiMiniMaxMaxTokens = Number.isFinite(n) ? Math.max(256, Math.min(8192, Math.round(n))) : 1600;
        await SettingsStore.save();
    };
    window.tmUpdateAiTimeoutMs = async function(value) {
        const n = Number(value);
        SettingsStore.data.aiMiniMaxTimeoutMs = Number.isFinite(n) ? Math.max(5000, Math.min(180000, Math.round(n))) : 30000;
        await SettingsStore.save();
    };
    window.tmUpdateAiDefaultContextMode = async function(value) {
        SettingsStore.data.aiDefaultContextMode = String(value || '').trim() === 'fulltext' ? 'fulltext' : 'nearby';
        await SettingsStore.save();
    };
    window.tmUpdateAiScheduleWindows = async function(value) {
        const list = String(value || '').split(/\r?\n/).map(v => String(v || '').trim()).filter(Boolean);
        SettingsStore.data.aiScheduleWindows = list.length ? list : ['09:00-18:00'];
        await SettingsStore.save();
    };
    window.tmAiTestConnection = async function() {
        const ready = await __tmEnsureAiRuntimeLoaded();
        const fn = ready ? globalThis.__tmAI?.testConnection : null;
        if (typeof fn !== 'function') {
            hint('⚠ AI 模块尚未加载完成', 'warning');
            return;
        }
        try {
            await fn();
        } catch (e) {}
    };

    window.saveSettings = async function() {
        // 同步到 SettingsStore 并保存到本地插件存储
        SettingsStore.data.selectedDocIds = state.selectedDocIds;
        SettingsStore.data.queryLimit = state.queryLimit;
        SettingsStore.data.showCompletionTime = state.showCompletionTime;
        SettingsStore.data.groupByDocName = state.groupByDocName;
        SettingsStore.data.groupByTime = state.groupByTime;
        await SettingsStore.save();
        hint('✅ 设置已保存', 'success');
        render();
        closeSettings();
    };

    // 全局点击监听器，用于点击窗口外关闭
    __tmGlobalClickHandler = (e) => {
        // 关闭主模态框
        if (state.modal && e.target === state.modal) {
            tmClose();
        }
        // 关闭设置模态框
        if (state.settingsModal && e.target === state.settingsModal) {
            closeSettings();
        }
        // 关闭规则管理模态框
        if (state.rulesModal && e.target === state.rulesModal) {
            closeRulesManager();
        }
        // 关闭提示框
        const promptModal = document.querySelector('.tm-prompt-modal');
        if (promptModal && e.target === promptModal) {
            // 取消操作
            promptModal.remove();
            if (window._tmPromptResolve) {
                window._tmPromptResolve(null);
                window._tmPromptResolve = null;
            }
        }
    };
    window.addEventListener('click', __tmGlobalClickHandler);

    // 初始化
    /**
     * 在移动端文档顶栏右上角添加任务管理按钮
     * 复用单例按钮，避免文档重新加载时反复销毁/重建图标
     */
    let breadcrumbTimer = null;
    let breadcrumbTries = 0;

    function __tmRemoveBreadcrumbButton(options = {}) {
        const destroy = !!options.destroy;
        try {
            if (breadcrumbTimer != null) {
                clearTimeout(breadcrumbTimer);
                breadcrumbTimer = null;
            }
        } catch (e) {}
        breadcrumbTries = 0;
        try {
            if (__tmBreadcrumbBtnEl?.parentElement) __tmBreadcrumbBtnEl.parentElement.removeChild(__tmBreadcrumbBtnEl);
        } catch (e) {}
        try {
            document.querySelectorAll('.tm-breadcrumb-btn').forEach((btn) => {
                if (__tmBreadcrumbBtnEl && btn === __tmBreadcrumbBtnEl) return;
                try { btn.remove(); } catch (e2) {}
            });
        } catch (e) {}
        if (destroy) __tmBreadcrumbBtnEl = null;
    }

    function __tmSyncBreadcrumbButtonVisual(btn) {
        if (!(btn instanceof HTMLElement)) return;
        try {
            const title = __tmGetDocTopbarButtonTitle();
            btn.title = title;
            btn.setAttribute('aria-label', title);
        } catch (e) {}
    }

    function __tmEnsureBreadcrumbButtonElement() {
        if (__tmBreadcrumbBtnEl instanceof HTMLButtonElement) {
            __tmSyncBreadcrumbButtonVisual(__tmBreadcrumbBtnEl);
            return __tmBreadcrumbBtnEl;
        }

        const tmBtn = document.createElement('button');
        tmBtn.type = 'button';
        tmBtn.className = 'block__icon fn__flex-center ariaLabel tm-breadcrumb-btn';
        tmBtn.innerHTML = '<svg aria-hidden="true"><use href="#iconTaskHorizon" xlink:href="#iconTaskHorizon"></use></svg>';
        tmBtn.style.cssText = `
            margin: 0 4px;
            flex-shrink: 0;
            z-index: 10;
        `;

        tmBtn.onclick = (e) => {
            e.preventDefault();
            e.stopPropagation();
            if (tmBtn.__tmLongPressFired) {
                tmBtn.__tmLongPressFired = false;
                return;
            }
            try {
                const meta = __tmGetDocTopbarButtonPressActionMeta();
                meta.shortRun?.();
            } catch (e2) {}
        };

        try {
            let pressTimer = null;
            const startHandler = () => {
                tmBtn.__tmLongPressFired = false;
                try { state.__tmPluginIconLongPressing = true; } catch (e) {}
                if (pressTimer) clearTimeout(pressTimer);
                pressTimer = setTimeout(() => {
                    tmBtn.__tmLongPressFired = true;
                    try {
                        const meta = __tmGetDocTopbarButtonPressActionMeta();
                        meta.longRun?.();
                    } catch (e) {}
                }, 450);
            };
            const cancelHandler = () => {
                if (pressTimer) clearTimeout(pressTimer);
                pressTimer = null;
                try { state.__tmPluginIconLongPressing = false; } catch (e) {}
            };
            const endHandler = (e) => {
                if (pressTimer) clearTimeout(pressTimer);
                pressTimer = null;
                try { state.__tmPluginIconLongPressing = false; } catch (e) {}
                if (tmBtn.__tmLongPressFired) {
                    try { e.preventDefault(); } catch (e2) {}
                    try { e.stopPropagation(); } catch (e2) {}
                }
            };

            tmBtn.addEventListener('touchstart', startHandler, { passive: true });
            tmBtn.addEventListener('touchmove', cancelHandler, { passive: true });
            tmBtn.addEventListener('touchend', endHandler, { passive: false });
            tmBtn.addEventListener('mousedown', startHandler);
            tmBtn.addEventListener('mouseleave', cancelHandler);
            tmBtn.addEventListener('mouseup', endHandler);
        } catch (e) {}

        __tmBreadcrumbBtnEl = tmBtn;
        __tmSyncBreadcrumbButtonVisual(tmBtn);
        return tmBtn;
    }

    function __tmGetLiveBreadcrumbButtonElement() {
        try {
            if (__tmBreadcrumbBtnEl instanceof HTMLButtonElement && document.body.contains(__tmBreadcrumbBtnEl)) {
                return __tmBreadcrumbBtnEl;
            }
        } catch (e) {}
        try {
            const existing = document.querySelector('.tm-breadcrumb-btn');
            if (existing instanceof HTMLButtonElement && document.body.contains(existing)) {
                __tmBreadcrumbBtnEl = existing;
                __tmSyncBreadcrumbButtonVisual(existing);
                return existing;
            }
        } catch (e) {}
        return null;
    }

    function __tmGetBreadcrumbButtonIn(breadcrumb) {
        if (!(breadcrumb instanceof HTMLElement)) return null;
        try {
            const btn = breadcrumb.querySelector('.tm-breadcrumb-btn');
            if (btn instanceof HTMLButtonElement) return btn;
        } catch (e) {}
        return null;
    }

    function __tmFindTomatoBreadcrumbAnchor(breadcrumb) {
        if (!(breadcrumb instanceof HTMLElement)) return null;
        const selectors = [
            '#tomato-breadcrumb-btn',
            '[id*="tomato"][class*="breadcrumb"]',
            '[class*="tomato"][class*="breadcrumb"]',
            '[aria-label*="番茄"]',
            '[title*="番茄"]',
            '[aria-label*="Tomato"]',
            '[title*="Tomato"]',
        ];
        for (const selector of selectors) {
            try {
                const el = breadcrumb.querySelector(selector);
                if (el instanceof HTMLElement) return el;
            } catch (e) {}
        }
        try {
            const children = Array.from(breadcrumb.children || []);
            return children.find((el) => {
                if (!(el instanceof HTMLElement) || el.classList.contains('tm-breadcrumb-btn')) return false;
                const text = String(el.getAttribute('aria-label') || el.getAttribute('title') || el.textContent || '').trim();
                if (!text) return false;
                return /番茄|tomato/i.test(text);
            }) || null;
        } catch (e) {}
        return null;
    }

    function __tmPlaceBreadcrumbButton(breadcrumb, tmBtn) {
        if (!(breadcrumb instanceof HTMLElement) || !(tmBtn instanceof HTMLElement)) return false;
        try {
            const tomatoAnchor = __tmFindTomatoBreadcrumbAnchor(breadcrumb);
            if (tomatoAnchor instanceof HTMLElement && tomatoAnchor !== tmBtn) {
                if (tmBtn.parentElement !== breadcrumb || tmBtn.nextElementSibling !== tomatoAnchor) {
                    breadcrumb.insertBefore(tmBtn, tomatoAnchor);
                }
                return true;
            }
            if (tmBtn.parentElement !== breadcrumb) {
                breadcrumb.appendChild(tmBtn);
            } else if (breadcrumb.lastElementChild !== tmBtn) {
                breadcrumb.appendChild(tmBtn);
            }
            return true;
        } catch (e) {
            return false;
        }
    }

    function addBreadcrumbButton() {
        if (!__tmShouldShowDocTopbarButton()) {
            __tmRemoveBreadcrumbButton();
            return;
        }
        if (breadcrumbTimer != null) return;

        const scheduleTry = (delayMs) => {
            if (breadcrumbTimer != null) return;
            const d = Math.max(0, Number(delayMs) || 0);
            breadcrumbTimer = setTimeout(() => {
                breadcrumbTimer = null;
                tryAddButton();
            }, d);
        };

        const tryAddButton = () => {
            const breadcrumb = document.querySelector('.protyle-breadcrumb');
            if (!(breadcrumb instanceof HTMLElement)) {
                breadcrumbTries += 1;
                if (breadcrumbTries <= 60) scheduleTry(500);
                return;
            }
            const currentBtn = __tmGetBreadcrumbButtonIn(breadcrumb);
            if (currentBtn instanceof HTMLButtonElement) {
                __tmBreadcrumbBtnEl = currentBtn;
                __tmSyncBreadcrumbButtonVisual(currentBtn);
                try {
                    document.querySelectorAll('.tm-breadcrumb-btn').forEach((btn) => {
                        if (btn === currentBtn) return;
                        try { btn.remove(); } catch (e2) {}
                    });
                } catch (e) {}
                __tmPlaceBreadcrumbButton(breadcrumb, currentBtn);
                breadcrumbTries = 0;
                return;
            }

            try {
                document.querySelectorAll('.tm-breadcrumb-btn').forEach((btn) => {
                    try { btn.remove(); } catch (e2) {}
                });
            } catch (e) {}
            __tmBreadcrumbBtnEl = null;

            const tmBtn = __tmEnsureBreadcrumbButtonElement();
            __tmSyncBreadcrumbButtonVisual(tmBtn);
            __tmPlaceBreadcrumbButton(breadcrumb, tmBtn);
            breadcrumbTries = 0;
        };

        tryAddButton();
    }

    /**
     * 注册顶栏图标
     */
    function __tmSetUseIcon(root, iconId) {
        if (!root) return false;
        const use = root.querySelector?.('use');
        if (!use) return false;
        const href = `#${iconId}`;
        try { use.setAttribute('href', href); } catch (e) {}
        try { use.setAttribute('xlink:href', href); } catch (e) {}
        try { use.setAttributeNS('http://www.w3.org/1999/xlink', 'href', href); } catch (e) {}
        return true;
    }

    function __tmElementContainsTaskHorizonIcon(el) {
        if (!(el instanceof Element)) return false;
        try {
            return !!el.querySelector?.('use[href="#iconTaskHorizon"], use[xlink\\:href="#iconTaskHorizon"]');
        } catch (e) {
            return false;
        }
    }

    function __tmIsTaskHorizonTabHeaderEl(el) {
        if (!(el instanceof Element)) return false;
        const tabId = String(globalThis.__taskHorizonCustomTabId || '').trim();
        try {
            if (tabId && (String(el.getAttribute?.('data-id') || '').trim() === tabId || String(el.getAttribute?.('data-key') || '').trim() === tabId)) {
                return true;
            }
        } catch (e) {}
        if (__tmElementContainsTaskHorizonIcon(el)) return true;
        return false;
    }

    function __tmIsTaskHorizonCustomModel(model) {
        if (!model || typeof model !== 'object') return false;
        const tabType = String(globalThis.__taskHorizonTabType || 'task-horizon').trim();
        const tabId = String(globalThis.__taskHorizonCustomTabId || '').trim();
        try {
            if (tabType && String(model.type || '').trim() === tabType) return true;
        } catch (e) {}
        try {
            if (tabId && String(model?.tab?.id || '').trim() === tabId) return true;
        } catch (e) {}
        try {
            if (__tmIsTaskHorizonTabHeaderEl(model?.headElement)) return true;
        } catch (e) {}
        try {
            const element = model?.element;
            if (element instanceof HTMLElement) {
                if (tabId && (String(element.getAttribute?.('data-id') || '').trim() === tabId || String(element.getAttribute?.('data-key') || '').trim() === tabId)) {
                    return true;
                }
                if (__tmIsTabRootElement(element) || element.querySelector?.('.tm-tab-root')) return true;
                if (__tmMountEl && (element === __tmMountEl || element.contains?.(__tmMountEl))) return true;
                if (globalThis.__taskHorizonTabElement instanceof HTMLElement && (element === globalThis.__taskHorizonTabElement || element.contains?.(globalThis.__taskHorizonTabElement))) {
                    return true;
                }
            }
        } catch (e) {}
        return false;
    }

    function __tmPatchTaskHorizonTabIcon() {
        const iconId = 'iconTaskHorizon';
        const tabId = String(globalThis.__taskHorizonCustomTabId || '').trim();
        if (!tabId) return false;
        const uses = Array.from(document.querySelectorAll('use[href], use[xlink\\:href]'));
        let ok = false;
        for (const use of uses) {
            try {
                const href = use.getAttribute('href') || use.getAttribute('xlink:href') || '';
                if (!href.includes('iconList') && !href.includes(iconId)) continue;
                const owner = use.closest?.(`[data-id="${tabId}"], [data-key="${tabId}"]`) || use.closest?.('.layout-tab-bar__item, [data-id], [data-key], li, button, div');
                if (!owner) continue;
                if (__tmIsTaskHorizonTabHeaderEl(owner)) {
                    const root = owner.closest?.(`[data-id="${tabId}"], [data-key="${tabId}"]`) || owner;
                    if (__tmSetUseIcon(root, iconId)) ok = true;
                }
            } catch (e) {}
        }
        return ok;
    }

    function __tmFocusExistingTaskHorizonTab() {
        try {
            const tabId = globalThis.__taskHorizonCustomTabId;
            if (!tabId) return false;
            try {
                const tab = __tmFindExistingTaskManagerTab?.();
                if (tab && window.siyuan?.layout?.centerLayout?.switchTab) {
                    window.siyuan.layout.centerLayout.switchTab(tab);
                    return true;
                }
            } catch (e) {}

            const els = Array.from(document.querySelectorAll(`[data-id="${tabId}"], [data-key="${tabId}"]`));
            if (els.length === 0) return false;
            const el = els.find(x => x && x.querySelector && x.querySelector('.tm-tab-root')) || els[0];
            try {
                el.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true }));
            } catch (e) {
                try { el.click(); } catch (e2) {}
            }
            return true;
        } catch (e) {}
        return false;
    }

    let __tmEnsureTabPromise = null;

    function __tmBindTopBarClickCapture(topBarEl) {
        const el = __tmResolveManagedTopBarEntry(topBarEl || __tmTopBarEl);
        if (!el) return;
        if (__tmTopBarEl && __tmTopBarEl !== el && __tmTopBarClickCaptureHandler) {
            try { __tmTopBarEl.removeEventListener('click', __tmTopBarClickCaptureHandler, true); } catch (e) {}
        }
        __tmTopBarEl = el;
        if (!__tmTopBarClickCaptureHandler) {
            __tmTopBarClickCaptureHandler = (e) => {
                if (__tmTopBarClickInFlight) return;
                __tmTopBarClickInFlight = true;
                try {
                    try { e.preventDefault?.(); } catch (e2) {}
                    try { e.stopImmediatePropagation?.(); } catch (e2) {}
                    try { e.stopPropagation?.(); } catch (e2) {}
                    const isDesktopTabHost = !__tmIsRuntimeMobileClient() && !__tmIsDockHost();
                    if (isDesktopTabHost) {
                        Promise.resolve().then(async () => {
                            try { await __tmEnsureTabOpened(1800); } catch (e2) {}
                            try { await openManager({ preserveViewMode: true, skipEnsureTabOpened: true }); } catch (e2) {}
                        }).catch(() => null);
                    } else {
                        try { __tmOpenManagerFromTopbarEntry(); } catch (e2) {}
                    }
                } finally {
                    setTimeout(() => { __tmTopBarClickInFlight = false; }, 0);
                }
            };
        }
        try { el.addEventListener('click', __tmTopBarClickCaptureHandler, true); } catch (e) {}
    }

    function __tmIsMobileTopBarRegistrationHost() {
        try {
            return !!(__tmIsRuntimeMobileClient() && !__tmIsDockHost());
        } catch (e) {
            return false;
        }
    }

    function __tmGetManagedTopBarLookupSelector() {
        return __tmIsMobileTopBarRegistrationHost()
            ? '[aria-label="任务管理器"], [aria-label="任务管理"], [title="任务管理器"], [title="任务管理"]'
            : '[aria-label="任务管理器"], [aria-label="任务管理"]';
    }

    function __tmIsManagedTopBarEntry(el) {
        if (!(el instanceof Element)) return false;
        if (__tmTopBarEl instanceof Element && el === __tmTopBarEl) return true;
        const label = String(
            __tmIsMobileTopBarRegistrationHost()
                ? (el.getAttribute?.('aria-label') || el.getAttribute?.('title') || '')
                : (el.getAttribute?.('aria-label') || '')
        ).trim();
        if (label !== '任务管理器' && label !== '任务管理') return false;
        if (el.closest?.('.layout-tab-bar, .layout-tab-bar__item, .layout-tab-container, .layout-tab-bar .item, .fn__flex-column[data-type="wnd"], .tm-modal')) return false;
        if (__tmElementContainsTaskHorizonIcon(el)) return true;
        if (el.closest?.('#toolbar, .toolbar, .toolbar__item, .topbar, .b3-menu, .b3-menu__item')) return true;
        if (el.closest?.('#toolbar, .toolbar, .toolbar__item, .topbar')) return true;
        try {
            const owner = el.closest?.('[id], [class]') || el;
            const ownerId = String(owner?.id || '').trim();
            const ownerCls = String(owner?.className?.baseVal || owner?.className || '').trim();
            return /(toolbar|topbar|menu)/i.test(`${ownerId} ${ownerCls}`);
        } catch (e) {}
        return false;
    }

    function __tmResolveManagedTopBarEntry(sourceEl) {
        if (sourceEl instanceof Element) {
            if (__tmIsManagedTopBarEntry(sourceEl)) return sourceEl;
            try {
                const nested = sourceEl.querySelector?.(__tmGetManagedTopBarLookupSelector());
                if (nested instanceof Element && __tmIsManagedTopBarEntry(nested)) return nested;
            } catch (e) {}
        }
        try {
            return Array.from(document.querySelectorAll(__tmGetManagedTopBarLookupSelector()))
                .find((el) => __tmIsManagedTopBarEntry(el)) || null;
        } catch (e) {}
        return null;
    }

    function __tmGetTopBarEntries() {
        try {
            const seen = new Set();
            const entries = [];
            const currentTopBar = __tmResolveManagedTopBarEntry(__tmTopBarEl);
            if (currentTopBar instanceof Element && document.body.contains(currentTopBar)) {
                entries.push(currentTopBar);
                seen.add(currentTopBar);
            }
            Array.from(document.querySelectorAll(__tmGetManagedTopBarLookupSelector())).forEach((el) => {
                if (!(el instanceof Element) || seen.has(el) || !__tmIsManagedTopBarEntry(el)) return;
                seen.add(el);
                entries.push(el);
            });
            return entries;
        } catch (e) {
            return [];
        }
    }

    function __tmDeduplicateTopBarEntries(allowRemoval = __tmIsMobileTopBarRegistrationHost()) {
        const entries = __tmGetTopBarEntries();
        if (!entries.length) return null;
        const keeper = (__tmTopBarEl instanceof Element && entries.includes(__tmTopBarEl))
            ? __tmTopBarEl
            : entries[0];
        if (allowRemoval) {
            entries.forEach((el) => {
                if (!(el instanceof Element) || el === keeper) return;
                try { el.remove(); } catch (e) {}
            });
        }
        return keeper instanceof Element ? keeper : null;
    }

    function __tmRemoveTopBarIcon(options = {}) {
        const shouldRemoveDom = options?.removeDom ?? __tmIsMobileTopBarRegistrationHost();
        try {
            const currentTopBar = __tmResolveManagedTopBarEntry(__tmTopBarEl);
            if (currentTopBar && __tmTopBarClickCaptureHandler) {
                try { currentTopBar.removeEventListener('click', __tmTopBarClickCaptureHandler, true); } catch (e) {}
            }
        } catch (e) {}
        try {
            if (__tmTopBarDocumentCaptureHandler) {
                try { document.removeEventListener('click', __tmTopBarDocumentCaptureHandler, true); } catch (e2) {}
                __tmTopBarDocumentCaptureHandler = null;
            }
        } catch (e) {}
        if (shouldRemoveDom) {
            try {
                const entries = __tmGetTopBarEntries();
                entries.forEach((el) => { try { el.remove(); } catch (e) {} });
            } catch (e) {}
        }
        try { delete globalThis[__TM_MOBILE_TOPBAR_REGISTERED_KEY]; } catch (e) {}
        __tmTopBarEl = null;
        __tmTopBarAdded = false;
    }

    function addTopBarIcon() {
        if (!__tmShouldShowWindowTopbarIcon()) {
            __tmRemoveTopBarIcon();
            return;
        }
        const isMobileTopBarHost = __tmIsMobileTopBarRegistrationHost();
        if (isMobileTopBarHost && globalThis[__TM_MOBILE_TOPBAR_REGISTERED_KEY]) {
            __tmTopBarAdded = true;
            try { __tmBindMobileTopBarDocumentCapture(); } catch (e) {}
            try {
                const exists = __tmDeduplicateTopBarEntries(true);
                if (exists) __tmBindTopBarClickCapture(exists);
            } catch (e) {}
            return;
        }
        if (__tmTopBarAdded) {
            if (isMobileTopBarHost) {
                try { __tmBindMobileTopBarDocumentCapture(); } catch (e) {}
                try {
                    const exists = __tmDeduplicateTopBarEntries(true);
                    if (exists) __tmBindTopBarClickCapture(exists);
                } catch (e) {}
                return;
            }
            try {
                const exists = __tmDeduplicateTopBarEntries(false);
                if (exists) {
                    __tmSetUseIcon(exists, 'iconTaskHorizon');
                    __tmBindTopBarClickCapture(exists);
                    return;
                }
            } catch (e) {}
            __tmTopBarAdded = false;
            __tmTopBarEl = null;
        }
        // 尝试通过全局插件实例添加
        const pluginInstance = globalThis.__taskHorizonPluginInstance || globalThis.__tomatoPluginInstance;
        if (pluginInstance && typeof pluginInstance.addTopBar === 'function') {
            // 检查是否已添加（避免重复）
            // addTopBar 通常由插件管理，我们这里只是尝试调用
            // 如果已经添加过，思源可能会处理，或者我们可以检查 DOM
            // 但是 addTopBar 没有 ID 参数，不好检查。
            // 我们可以检查 aria-label 或 title
            const exists = __tmDeduplicateTopBarEntries(isMobileTopBarHost);
            if (exists) {
                __tmSetUseIcon(exists, 'iconTaskHorizon');
                if (isMobileTopBarHost) {
                    try { __tmBindMobileTopBarDocumentCapture(); } catch (e) {}
                }
                try { __tmBindTopBarClickCapture(exists); } catch (e) {}
                __tmTopBarAdded = true;
                if (isMobileTopBarHost) {
                    try { globalThis[__TM_MOBILE_TOPBAR_REGISTERED_KEY] = true; } catch (e) {}
                }
                return;
            }

            const topBarEl = pluginInstance.addTopBar({
                icon: "iconTaskHorizon",
                title: "任务管理器",
                position: "right",
                callback: () => {
                    try { __tmOpenManagerFromTopbarEntry(); } catch (e) {}
                }
            });
            if (isMobileTopBarHost) {
                try { __tmBindMobileTopBarDocumentCapture(); } catch (e) {}
            }
            try { __tmBindTopBarClickCapture(topBarEl || __tmDeduplicateTopBarEntries(isMobileTopBarHost)); } catch (e) {}
            __tmTopBarAdded = true;
            if (isMobileTopBarHost) {
                try { globalThis[__TM_MOBILE_TOPBAR_REGISTERED_KEY] = true; } catch (e) {}
            }
            setTimeout(() => {
                try {
                    const exists = __tmDeduplicateTopBarEntries(isMobileTopBarHost);
                    try { __tmSetUseIcon(exists, 'iconTaskHorizon'); } catch (e2) {}
                    try { if (exists) __tmBindTopBarClickCapture(exists); } catch (e2) {}
                } catch (e) {}
            }, 0);
        } else {
        }
    }

    function __tmRefreshShellEntrances() {
        try {
            if (__tmShouldShowDocTopbarButton()) addBreadcrumbButton();
            else __tmRemoveBreadcrumbButton();
        } catch (e) {}
        try {
            if (__tmShouldShowWindowTopbarIcon()) addTopBarIcon();
            else __tmRemoveTopBarIcon();
        } catch (e) {}
    }

    function __tmNodeTouchesShellEntrances(node) {
        if (!(node instanceof Element)) return false;
        if (node.closest?.('.tm-modal')) return false;
        if (node.matches?.('.protyle-breadcrumb, [aria-label="任务管理器"], [aria-label="任务管理"]')) return true;
        if (node.querySelector?.('.protyle-breadcrumb, [aria-label="任务管理器"], [aria-label="任务管理"]')) return true;
        try {
            const cls = String(node.className?.baseVal || node.className || '').trim();
            if (/(^|\b)(protyle|breadcrumb|toolbar|topbar|layout__wnd)(\b|$)/i.test(cls)) return true;
        } catch (e) {}
        return false;
    }

    function __tmMutationTouchesShellEntrances(mutation) {
        const target = mutation?.target;
        if (target instanceof Element) {
            if (target.closest?.('.tm-modal')) return false;
            if (__tmNodeTouchesShellEntrances(target)) return true;
        }
        const nodes = [
            ...(Array.isArray(mutation?.addedNodes) ? mutation.addedNodes : Array.from(mutation?.addedNodes || [])),
            ...(Array.isArray(mutation?.removedNodes) ? mutation.removedNodes : Array.from(mutation?.removedNodes || [])),
        ];
        return nodes.some((node) => __tmNodeTouchesShellEntrances(node));
    }

    function __tmScheduleShellEntrancesRefresh() {
        if (__tmShellEntrancesRefreshRaf != null) return;
        try {
            __tmShellEntrancesRefreshRaf = requestAnimationFrame(() => {
                __tmShellEntrancesRefreshRaf = null;
                __tmRefreshShellEntrances();
            });
        } catch (e) {
            __tmRefreshShellEntrances();
        }
    }

    function __tmFindExistingTaskHorizonCustomModel() {
        try {
            const inst = globalThis.__taskHorizonPluginInstance;
            if (inst && typeof inst.getOpenedTab === 'function') {
                const opened = inst.getOpenedTab();
                if (opened && typeof opened === 'object') {
                    const customs = [];
                    Object.values(opened).forEach((arr) => {
                        if (Array.isArray(arr)) arr.forEach((c) => customs.push(c));
                    });
                    for (const c of customs) {
                        if (__tmIsTaskHorizonCustomModel(c)) return c;
                    }
                }
            }
        } catch (e) {}
        try {
            if (window.siyuan && typeof window.siyuan.getAllModels === 'function') {
                const models = window.siyuan.getAllModels();
                const list = Array.isArray(models?.custom) ? models.custom : [];
                for (const c of list) {
                    if (__tmIsTaskHorizonCustomModel(c)) return c;
                }
            }
        } catch (e) {}
        return null;
    }

    async function __tmWaitForTaskHorizonTabRoot(maxWaitMs = 1800) {
        const startedAt = Date.now();
        while (Date.now() - startedAt < Math.max(200, Number(maxWaitMs) || 1800)) {
            try {
                const custom = __tmFindExistingTaskHorizonCustomModel();
                const fromCustom = custom?.element instanceof HTMLElement ? custom.element : null;
                if (fromCustom && document.body.contains(fromCustom)) {
                    return fromCustom;
                }
            } catch (e) {}
            try {
                const tabId = String(globalThis.__taskHorizonCustomTabId || '').trim();
                if (tabId) {
                    const root = document.querySelector(`[data-id="${tabId}"] .tm-tab-root, [data-key="${tabId}"] .tm-tab-root`);
                    if (root instanceof HTMLElement && document.body.contains(root)) {
                        return root;
                    }
                }
            } catch (e) {}
            try {
                const best = __tmFindBestTabRoot?.();
                if (best instanceof HTMLElement && document.body.contains(best)) {
                    return best;
                }
            } catch (e) {}
            await new Promise(r => setTimeout(r, 50));
        }
        return null;
    }

    /**
     * 监听面包屑栏变化
     */
    function observeBreadcrumb() {
        if (window.__tmTaskHorizonBreadcrumbObserver) {
            __tmRefreshShellEntrances();
            return;
        }
        // 先尝试添加一次
        __tmRefreshShellEntrances();

        // 使用 MutationObserver 监听面包屑栏变化
        if (__tmBreadcrumbObserver) {
            try { __tmBreadcrumbObserver.disconnect(); } catch (e) {}
            __tmBreadcrumbObserver = null;
        }
        const observer = new MutationObserver((mutations) => {
            const list = Array.isArray(mutations) ? mutations : [];
            const onlyTaskHorizonModalMutations = list.length > 0 && list.every((mutation) => {
                const target = mutation?.target;
                if (target instanceof Element && target.closest?.('.tm-modal')) return true;
                const nodes = [
                    ...(Array.isArray(mutation?.addedNodes) ? mutation.addedNodes : Array.from(mutation?.addedNodes || [])),
                    ...(Array.isArray(mutation?.removedNodes) ? mutation.removedNodes : Array.from(mutation?.removedNodes || [])),
                ];
                if (!nodes.length) return false;
                return nodes.every((node) => {
                    if (!(node instanceof Element)) return true;
                    if (node.matches?.('.tm-modal')) return true;
                    if (node.closest?.('.tm-modal')) return true;
                    if (node.querySelector?.('.tm-modal')) return true;
                    return false;
                });
            });
            if (onlyTaskHorizonModalMutations) return;
            if (!list.some((mutation) => __tmMutationTouchesShellEntrances(mutation))) return;
            __tmScheduleShellEntrancesRefresh();
        });

        // 监听整个文档的子节点变化
        observer.observe(document.body, {
            childList: true,
            subtree: true
        });
        __tmBreadcrumbObserver = observer;
        try { window.__tmTaskHorizonBreadcrumbObserver = observer; } catch (e) {}
        
        // 额外监听顶栏图标注入（如果插件实例加载较晚）
        if (__tmShouldShowWindowTopbarIcon()) __tmTopBarTimer = setTimeout(addTopBarIcon, 1000);
    }

    function __tmBindDocGroupMenuEntry() {
        const eb = globalThis.__taskHorizonPluginInstance?.eventBus || window.siyuan?.eventBus;
        if (!eb || typeof eb.on !== 'function') return;
        __tmDocMenuEventBus = eb;

        if (__tmEditorTitleIconMenuHandler && typeof eb.off === 'function') {
            try { eb.off('click-editortitleicon', __tmEditorTitleIconMenuHandler); } catch (e) {}
            __tmEditorTitleIconMenuHandler = null;
        }
        if (__tmDocTreeMenuHandler && typeof eb.off === 'function') {
            try { eb.off('open-menu-doctree', __tmDocTreeMenuHandler); } catch (e) {}
            __tmDocTreeMenuHandler = null;
        }
        if (__tmContentMenuHandler && typeof eb.off === 'function') {
            try { eb.off('open-menu-content', __tmContentMenuHandler); } catch (e) {}
            __tmContentMenuHandler = null;
        }
        if (__tmBlockIconMenuHandler && typeof eb.off === 'function') {
            try { eb.off('click-blockicon', __tmBlockIconMenuHandler); } catch (e) {}
            __tmBlockIconMenuHandler = null;
        }

        __tmEditorTitleIconMenuHandler = (event) => {
            const detail = event?.detail || {};
            const menu = detail.menu;
            if (!menu || typeof menu.addItem !== 'function') return;
            const docId = String(detail?.data?.id || detail?.protyle?.block?.rootID || '').trim();
            if (!docId) return;
            menu.addItem({
                icon: 'iconTaskHorizon',
                label: '添加到任务管理器分组',
                click: () => {
                    try { window.tmOpenAddDocToGroupDialog?.(docId); } catch (e) {}
                }
            });
            menu.addItem({
                icon: 'iconTaskHorizon',
                label: '添加到其他块页签',
                click: async () => {
                    try {
                        await window.tmOpenAddOtherBlocksToGroupDialog?.([docId]);
                    } catch (e) {
                        hint(`❌ 添加失败: ${e.message}`, 'error');
                    }
                }
            });
            if (__tmIsAiFeatureEnabled()) {
                menu.addItem({
                    icon: 'iconTaskHorizon',
                    label: 'AI SMART 分析',
                    click: () => {
                        try { window.tmAiAnalyzeDocumentSmart?.(docId); } catch (e) {}
                    }
                });
                menu.addItem({
                    icon: 'iconTaskHorizon',
                    label: 'AI 日程排期',
                    click: () => {
                        try { window.tmAiPlanDocumentSchedule?.(docId); } catch (e) {}
                    }
                });
            }
            menu.addItem({
                icon: 'iconTaskHorizon',
                label: '语义识别完成日期',
                click: () => {
                    try { window.tmAiSemanticCompletionPreview?.(docId); } catch (e) {}
                }
            });
        };

        __tmDocTreeMenuHandler = (event) => {
            const detail = event?.detail || {};
            const menu = detail.menu;
            if (!menu || typeof menu.addItem !== 'function') return;
            const type = String(detail?.type || '').trim();
            if (type !== 'doc' && type !== 'docs') return;
            const docIds = __tmTryCollectDocIdsFromElements(detail?.elements);
            if (!docIds.length) return;
            menu.addItem({
                icon: 'iconTaskHorizon',
                label: docIds.length > 1 ? '添加所选文档到任务管理器分组' : '添加到任务管理器分组',
                click: () => {
                    try { window.tmOpenAddDocToGroupDialog?.(docIds); } catch (e) {}
                }
            });
            if (__tmIsAiFeatureEnabled() && docIds.length === 1) {
                const docId = String(docIds[0] || '').trim();
                if (docId) {
                    menu.addItem({
                        icon: 'iconTaskHorizon',
                        label: 'AI SMART 分析',
                        click: () => {
                            try { window.tmAiAnalyzeDocumentSmart?.(docId); } catch (e) {}
                        }
                    });
                    menu.addItem({
                        icon: 'iconTaskHorizon',
                        label: 'AI 日程排期',
                        click: () => {
                            try { window.tmAiPlanDocumentSchedule?.(docId); } catch (e) {}
                        }
                    });
                    menu.addItem({
                        icon: 'iconTaskHorizon',
                        label: '语义识别完成日期',
                        click: () => {
                            try { window.tmAiSemanticCompletionPreview?.(docId); } catch (e) {}
                        }
                    });
                }
            }
        };

        __tmBlockIconMenuHandler = (event) => {
            const detail = event?.detail || {};
            const menu = detail.menu;
            if (!menu || typeof menu.addItem !== 'function') return;
            const rawBlockElements = [];
            if (detail?.blockElement) rawBlockElements.push(detail.blockElement);
            if (detail?.element) rawBlockElements.push(detail.element);
            try { rawBlockElements.push(...Array.from(detail?.blockElements || [])); } catch (e) {}
            __tmAddMoveBlockToDailyNoteMenuItem(menu, __tmCollectBlockIdsFromElements(rawBlockElements), {
                protyle: detail?.protyle || null
            });
            const scheduleBlockIds = __tmCollectBlockIdsFromElements(rawBlockElements);
            if (
                scheduleBlockIds.length === 1
                && globalThis.__tmCalendar
                && (typeof globalThis.__tmCalendar.openScheduleEditor === 'function' || typeof globalThis.__tmCalendar.openScheduleEditorByTaskId === 'function')
            ) {
                const scheduleBlockId = String(scheduleBlockIds[0] || '').trim();
                const scheduleBlockElement = rawBlockElements.find((item) => __tmResolveAnyBlockIdFromElement(item) === scheduleBlockId) || rawBlockElements[0] || null;
                if (scheduleBlockId) {
                    menu.addItem({
                        icon: 'iconTaskHorizon',
                        label: '编辑日程',
                        click: async () => {
                            await __tmOpenScheduleEditorForBlock(scheduleBlockId, scheduleBlockElement);
                        }
                    });
                }
            }
            const blockIds = __tmCollectOtherBlockIdsFromElements(rawBlockElements);
            if (!blockIds.length) return;
            menu.addItem({
                icon: 'iconTaskHorizon',
                label: blockIds.length > 1 ? '添加所选块到其他块页签' : '添加到其他块页签',
                click: async () => {
                    try {
                        await window.tmOpenAddOtherBlocksToGroupDialog?.(blockIds);
                    } catch (e) {
                        hint(`❌ 添加失败: ${e.message}`, 'error');
                    }
                }
            });
        };

        __tmContentMenuHandler = (event) => {
            const detail = event?.detail || {};
            const menu = detail.menu;
            if (!menu || typeof menu.addItem !== 'function') return;
            const fallbackBlockId = String(__tmGetRecentBlockMenuContext()?.blockId || '').trim();
            const blockIds = __tmCollectSelectedBlockIdsFromProtyle(detail?.protyle || null, fallbackBlockId);
            __tmAddMoveBlockToDailyNoteMenuItem(menu, blockIds, {
                protyle: detail?.protyle || null
            });
        };

        eb.on('click-editortitleicon', __tmEditorTitleIconMenuHandler);
        eb.on('open-menu-doctree', __tmDocTreeMenuHandler);
        eb.on('open-menu-content', __tmContentMenuHandler);
        eb.on('click-blockicon', __tmBlockIconMenuHandler);
    }

    function __tmBindNativeDocMenuEntry() {
        try {
            document.removeEventListener('contextmenu', __tmNativeDocMenuCaptureHandler, true);
            document.removeEventListener('mousedown', __tmNativeDocMenuCaptureHandler, true);
            document.removeEventListener('click', __tmNativeDocMenuCaptureHandler, true);
        } catch (e) {}

        __tmNativeDocMenuCaptureHandler = (e) => {
            try { __tmRememberTitleMenuContext(e?.target); } catch (e2) {}
            try { __tmRememberBlockMenuContext(e?.target, e); } catch (e2) {}
        };
        try { document.addEventListener('contextmenu', __tmNativeDocMenuCaptureHandler, true); } catch (e) {}
        try { document.addEventListener('mousedown', __tmNativeDocMenuCaptureHandler, true); } catch (e) {}
        try { document.addEventListener('click', __tmNativeDocMenuCaptureHandler, true); } catch (e) {}

        try { __tmDocMenuObserver?.disconnect?.(); } catch (e) {}
        __tmDocMenuObserver = new MutationObserver(() => {
            try {
                const menuItems = document.querySelector('#commonMenu .b3-menu__items');
                if (!menuItems) return;
                const titleMenu = menuItems.closest?.('[data-name="titleMenu"]') || document.querySelector('#commonMenu [data-name="titleMenu"]');
                if (titleMenu) {
                    if (menuItems.querySelector('.tm-doc-group-menu-item')) return;
                    const now = Date.now();
                    const isRecent = __tmLastRightClickedTitleProtyle && __tmLastRightClickedTitleProtyle.isConnected && (now - (Number(__tmLastRightClickedTitleAtMs) || 0) < 3000);
                    const targetProtyle = (isRecent ? __tmLastRightClickedTitleProtyle : null) || __tmFindActiveProtyle?.() || null;
                    const docId = __tmGetDocIdFromProtyle(targetProtyle);
                    if (!docId) return;
                    const menuItem = __tmCreateNativeMenuItem('添加到任务管理器分组', async () => {
                        await window.tmOpenAddDocToGroupDialog?.(docId);
                    });
                    __tmInsertMenuItem(menuItems, menuItem);
                    if (__tmIsAiFeatureEnabled()) {
                        const smartItem = __tmCreateNativeMenuItem('AI SMART 分析', async () => {
                            await window.tmAiAnalyzeDocumentSmart?.(docId);
                        });
                        __tmInsertMenuItem(menuItems, smartItem);
                        const scheduleItem = __tmCreateNativeMenuItem('AI 日程排期', async () => {
                            await window.tmAiPlanDocumentSchedule?.(docId);
                        });
                        __tmInsertMenuItem(menuItems, scheduleItem);
                    }
                    const semanticItem = __tmCreateNativeMenuItem('语义识别完成日期', async () => {
                        await window.tmAiSemanticCompletionPreview?.(docId);
                    });
                    __tmInsertMenuItem(menuItems, semanticItem);
                    return;
                }
                if (menuItems.querySelector('.tm-block-schedule-menu-item')) return;
                const blockCtx = __tmGetRecentBlockMenuContext();
                if (!blockCtx?.blockId) return;
                const scheduleItem = __tmCreateNativeMenuItem('编辑日程', async () => {
                    await __tmOpenScheduleEditorForBlock(blockCtx.blockId, blockCtx.blockElement);
                }, 'tm-block-schedule-menu-item');
                __tmInsertMenuItem(menuItems, scheduleItem);
                __tmLastRightClickedBlockAtMs = 0;
            } catch (e) {}
        });
        try {
            __tmDocMenuObserver.observe(document.body, { childList: true, subtree: true });
        } catch (e) {}
    }

    const __TM_NATIVE_DOC_CHECKBOX_SYNC_DELAY_MS = 260;

    function __tmFindNativeDocTaskListItem(target) {
        try {
            const node = target instanceof Element ? target : target?.parentElement || null;
            if (!node || !node.closest) return null;
            if ((node.matches?.('[data-type="NodeListItem"]') || node.matches?.('.li[data-node-id]')) && node.querySelector?.('.protyle-action--task')) {
                return node;
            }
            const toggle = node.closest('.protyle-action--task');
            if (!(toggle instanceof Element)) return null;
            if (!toggle.closest('.protyle')) return null;
            const listItem = toggle.closest('[data-type="NodeListItem"], .li[data-node-id]');
            if (!(listItem instanceof Element)) return null;
            if (!listItem.querySelector('.protyle-action--task')) return null;
            return listItem;
        } catch (e) {
            return null;
        }
    }

    function __tmResolveNativeDocTaskBlockId(target) {
        try {
            const listItem = __tmFindNativeDocTaskListItem(target);
            if (!(listItem instanceof Element)) return '';
            return String(__tmResolveAnyBlockIdFromElement(listItem) || '').trim();
        } catch (e) {
            return '';
        }
    }

    function __tmResolveNativeDocTaskToggleBlockId(target) {
        try {
            const node = target instanceof Element ? target : target?.parentElement || null;
            if (!(node instanceof Element) || !node.closest) return '';
            const toggle = node.matches?.('.protyle-action--task') ? node : node.closest('.protyle-action--task');
            if (!(toggle instanceof Element) || !toggle.closest('.protyle')) return '';
            return __tmResolveNativeDocTaskBlockId(toggle);
        } catch (e) {
            return '';
        }
    }

    function __tmReadNativeDocTaskDoneFromListItem(listItem) {
        try {
            if (!(listItem instanceof Element)) return null;
            if (listItem.classList?.contains?.('protyle-task--done')) return true;
            const useEl = listItem.querySelector('.protyle-action--task use');
            const href = String(useEl?.getAttribute?.('xlink:href') || useEl?.getAttribute?.('href') || '').trim();
            if (href === '#iconCheck') return true;
            if (href === '#iconUncheck') return false;
            const checkboxInput = listItem.querySelector('input[type="checkbox"]');
            if (checkboxInput instanceof HTMLInputElement) return !!checkboxInput.checked;
            return null;
        } catch (e) {
            return null;
        }
    }

    function __tmReadNativeDocTaskDoneFromDom(blockId) {
        const rawId = String(blockId || '').trim();
        if (!rawId) return null;
        const selectors = [
            `[data-type="NodeListItem"][data-node-id="${rawId}"]`,
            `.li[data-node-id="${rawId}"]`,
            `[data-id="${rawId}"][data-type="NodeListItem"]`,
            `[data-id="${rawId}"].li`,
        ];
        for (const selector of selectors) {
            let listItem = null;
            try { listItem = document.querySelector(selector); } catch (e) { listItem = null; }
            if (!(listItem instanceof Element)) continue;
            return __tmReadNativeDocTaskDoneFromListItem(listItem);
        }
        return null;
    }

    function __tmReadNativeDocCheckboxIconDoneState(target) {
        try {
            const el = target instanceof Element ? target : null;
            if (!(el instanceof Element)) return null;
            const href = String(el.getAttribute('xlink:href') || el.getAttribute('href') || '').trim();
            if (href === '#iconCheck') return true;
            if (href === '#iconUncheck') return false;
            return null;
        } catch (e) {
            return null;
        }
    }

    function __tmFindNativeDocTaskListItemsByIds(blockIds) {
        const ids = Array.from(new Set((Array.isArray(blockIds) ? blockIds : [blockIds]).map((item) => String(item || '').trim()).filter(Boolean)));
        const out = [];
        const seen = new Set();
        ids.forEach((rawId) => {
            const selectors = [
                `[data-type="NodeListItem"][data-node-id="${rawId}"]`,
                `.li[data-node-id="${rawId}"]`,
                `[data-id="${rawId}"][data-type="NodeListItem"]`,
                `[data-id="${rawId}"].li`,
            ];
            selectors.forEach((selector) => {
                let listItem = null;
                try { listItem = document.querySelector(selector); } catch (e) { listItem = null; }
                if (!(listItem instanceof Element)) return;
                const itemId = __tmResolveAnyBlockIdFromElement(listItem) || rawId;
                if (!itemId || seen.has(itemId)) return;
                seen.add(itemId);
                out.push(listItem);
            });
        });
        return out;
    }

    function __tmMirrorNativeDocTaskStatusAttr(blockIds, customStatus) {
        const ids = Array.from(new Set((Array.isArray(blockIds) ? blockIds : [blockIds]).map((item) => String(item || '').trim()).filter(Boolean)));
        const nextStatus = String(customStatus || '').trim();
        if (!ids.length) return false;
        const listItems = __tmFindNativeDocTaskListItemsByIds(ids);
        if (!listItems.length) return false;
        let changed = false;
        listItems.forEach((listItem) => {
            const beforeStatus = String(listItem.getAttribute('custom-status') || '').trim();
            try {
                if (nextStatus) listItem.setAttribute('custom-status', nextStatus);
                else listItem.removeAttribute('custom-status');
            } catch (e) {}
            const afterStatus = String(listItem.getAttribute('custom-status') || '').trim();
            if (beforeStatus !== afterStatus) changed = true;
        });
        return changed;
    }

    function __tmBumpNativeDocCheckboxReconcileVersion(blockId) {
        const rawId = String(blockId || '').trim();
        if (!rawId) return 0;
        const nextVersion = (Number(__tmNativeDocCheckboxReconcileVersions.get(rawId)) || 0) + 1;
        __tmNativeDocCheckboxReconcileVersions.set(rawId, nextVersion);
        return nextVersion;
    }

    function __tmIsNativeDocCheckboxReconcileVersionCurrent(blockId, version) {
        const rawId = String(blockId || '').trim();
        if (!rawId) return false;
        return (Number(__tmNativeDocCheckboxReconcileVersions.get(rawId)) || 0) === (Number(version) || 0);
    }

    function __tmClearNativeDocCheckboxReconcileTimers(blockId) {
        const rawId = String(blockId || '').trim();
        if (!rawId) return;
        try {
            const timers = __tmNativeDocCheckboxReconcileTimers.get(rawId);
            if (Array.isArray(timers)) timers.forEach((timer) => clearTimeout(timer));
        } catch (e) {}
        try { __tmNativeDocCheckboxReconcileTimers.delete(rawId); } catch (e) {}
    }

    function __tmMirrorDocCheckboxStatusPatch(taskId, patch) {
        const tid = String(taskId || '').trim();
        if (!tid || !patch || typeof patch !== 'object') return;
        const value = String(patch.customStatus || '').trim();
        if (!value) return;
        try {
            const task = state.flatTasks?.[tid];
            if (task && typeof task === 'object') {
                task.customStatus = value;
                task.custom_status = value;
            }
        } catch (e) {}
        try {
            const pending = state.pendingInsertedTasks?.[tid];
            if (pending && typeof pending === 'object') {
                pending.customStatus = value;
                pending.custom_status = value;
            }
        } catch (e) {}
    }

    async function __tmReadDocCheckboxBlockAttrs(blockId) {
        const rawId = String(blockId || '').trim();
        if (!rawId) return null;
        let attrTargetId = rawId;
        try {
            const resolvedAttrId = await __tmResolveTaskAttrHostIdFromAnyBlockId(rawId);
            if (resolvedAttrId) attrTargetId = resolvedAttrId;
        } catch (e) {}
        try {
            const res = await API.call('/api/attr/getBlockAttrs', { id: attrTargetId });
            if (!(res && res.code === 0 && res.data && typeof res.data === 'object')) return null;
            const attrs = res.data;
            return String(attrs['custom-status'] || '').trim();
        } catch (e) {
            return '';
        }
    }

    async function __tmReconcileNativeDocCheckboxStatus(blockId, taskId, statusPatch, expectedDone, syncVersion = 0) {
        const rawId = String(blockId || '').trim();
        const tid = String(taskId || '').trim();
        const expectedStatus = String(statusPatch?.customStatus || '').trim();
        const done = !!expectedDone;
        if (!rawId || !tid || !expectedStatus || !__tmIsNativeDocCheckboxReconcileVersionCurrent(rawId, syncVersion)) return false;
        const domDone = __tmReadNativeDocTaskDoneFromDom(rawId);
        const beforeStatus = await __tmReadDocCheckboxBlockAttrs(tid);
        if (!__tmIsNativeDocCheckboxReconcileVersionCurrent(rawId, syncVersion)) return false;
        if (domDone !== done || beforeStatus === expectedStatus) return false;
        __tmMirrorNativeDocTaskStatusAttr([rawId, tid], expectedStatus);
        await __tmPersistMetaAndAttrsKernel(tid, statusPatch, {
            touchMetaStore: false,
            skipFlush: false,
        });
        if (!__tmIsNativeDocCheckboxReconcileVersionCurrent(rawId, syncVersion)) return false;
        const afterStatus = await __tmReadDocCheckboxBlockAttrs(tid);
        return afterStatus === expectedStatus;
    }

    function __tmScheduleNativeDocCheckboxStatusReconcile(blockId, taskId, statusPatch, expectedDone, syncVersion) {
        const rawId = String(blockId || '').trim();
        const tid = String(taskId || '').trim();
        if (!rawId || !tid || !statusPatch || typeof statusPatch !== 'object') return;
        __tmClearNativeDocCheckboxReconcileTimers(rawId);
        const timers = [260, 900].map((delayMs) => setTimeout(() => {
            if (!__tmIsNativeDocCheckboxReconcileVersionCurrent(rawId, syncVersion)) return;
            __tmReconcileNativeDocCheckboxStatus(rawId, tid, statusPatch, expectedDone, syncVersion).catch(() => null);
        }, delayMs));
        __tmNativeDocCheckboxReconcileTimers.set(rawId, timers);
    }

    function __tmApplyNativeDocCheckboxLocalState(taskId, done, statusValue = '', taskLike = null) {
        const tid = String(taskId || '').trim();
        const nextDone = !!done;
        const nextStatus = String(statusValue || '').trim();
        if (!tid) return false;
        try {
            const liveTask = state.flatTasks?.[tid];
            if (liveTask && typeof liveTask === 'object') {
                liveTask.done = nextDone;
                if (nextStatus) {
                    liveTask.customStatus = nextStatus;
                    liveTask.custom_status = nextStatus;
                }
            }
        } catch (e) {}
        try {
            const pendingTask = state.pendingInsertedTasks?.[tid];
            if (pendingTask && typeof pendingTask === 'object') {
                pendingTask.done = nextDone;
                if (nextStatus) {
                    pendingTask.customStatus = nextStatus;
                    pendingTask.custom_status = nextStatus;
                }
            }
        } catch (e) {}
        try {
            if (!state.doneOverrides || typeof state.doneOverrides !== 'object') state.doneOverrides = {};
            state.doneOverrides[tid] = nextDone;
        } catch (e) {}
        try {
            const content = String(taskLike?.content || state.flatTasks?.[tid]?.content || state.pendingInsertedTasks?.[tid]?.content || '').trim();
            const metaPatch = { done: nextDone, content };
            if (nextStatus) metaPatch.customStatus = nextStatus;
            MetaStore.set(tid, metaPatch);
        } catch (e) {}
        return true;
    }

    async function __tmSyncNativeDocCheckboxLinkedStatus(blockId) {
        const rawId = String(blockId || '').trim();
        if (!rawId) return false;
        const syncVersion = __tmBumpNativeDocCheckboxReconcileVersion(rawId);
        try {
            await __tmFlushSqlTransactionsSafe('native-doc-checkbox-status-sync');
        } catch (e) {}

        const domDone = __tmReadNativeDocTaskDoneFromDom(rawId);
        if (domDone === null) return false;

        let taskId = '';
        try { taskId = await __tmResolveTaskIdFromAnyBlockId(rawId); } catch (e) { taskId = ''; }
        const tid = String(taskId || rawId || '').trim();
        if (!tid) return false;

        let task = null;
        try { task = state.flatTasks?.[tid] ? { ...state.flatTasks[tid] } : null; } catch (e) { task = null; }
        if (!task || typeof task !== 'object') {
            try { task = await API.getTaskById(tid); } catch (e) { task = null; }
        }
        if (!task || typeof task !== 'object') {
            try { task = await __tmBuildTaskLikeFromBlockId(tid); } catch (e) { task = null; }
        }
        if (!task || typeof task !== 'object') return false;
        try { normalizeTaskFields(task, String(task.doc_name || task.docName || '').trim()); } catch (e) {}

        const statusOptions = Array.isArray(SettingsStore?.data?.customStatusOptions) ? SettingsStore.data.customStatusOptions : [];
        const expectedStatus = String(__tmResolveCheckboxLinkedStatusId(!!domDone, statusOptions) || '').trim();
        const currentStatus = String(task.customStatus || '').trim();
        const persistedStatusBefore = String(await __tmReadDocCheckboxBlockAttrs(tid) || '').trim();
        const shouldApplyExpectedStatus = !!domDone || __tmShouldApplyUndoneStatusFallback(task, expectedStatus, currentStatus, persistedStatusBefore, statusOptions);
        const targetStatus = String(shouldApplyExpectedStatus ? expectedStatus : (persistedStatusBefore || currentStatus || '')).trim();
        const shouldPersistStatus = !!targetStatus && persistedStatusBefore !== targetStatus;
        const shouldSyncLocalStatus = !!targetStatus && currentStatus !== targetStatus;
        const statusPatch = shouldPersistStatus ? { customStatus: targetStatus } : (shouldSyncLocalStatus ? { customStatus: targetStatus } : null);
        if (!statusPatch || Object.keys(statusPatch).length === 0) {
            const resolvedStatus = String(targetStatus || expectedStatus || persistedStatusBefore || currentStatus || '').trim();
            __tmApplyNativeDocCheckboxLocalState(tid, !!domDone, resolvedStatus, task);
            try {
                const docId = String(task.root_id || task.docId || '').trim();
                if (docId) __tmInvalidateTasksQueryCacheByDocId(docId);
            } catch (e) {}
            try {
                if (typeof __tmIsPluginVisibleNow === 'function' && __tmIsPluginVisibleNow()) {
                    __tmScheduleRender({ withFilters: true });
                }
            } catch (e) {}
            try { globalThis.__taskHorizonQuickbarRefreshInline?.(); } catch (e) {}
            try { globalThis.__taskHorizonQuickbarRefresh?.(); } catch (e) {}
            if (domDone) {
                try {
                    __tmScheduleRecurringTaskAdvanceAfterCompletion(tid, {
                        source: 'native-doc-checkbox-sync',
                        completedAt: new Date().toISOString(),
                    });
                } catch (e) {}
            } else {
                try { __tmClearRecurringTaskAdvanceTimer(tid); } catch (e) {}
            }
            return true;
        }

        let persistedStatus = persistedStatusBefore;
        if (shouldPersistStatus) {
            __tmMirrorNativeDocTaskStatusAttr([rawId, tid], String(statusPatch.customStatus || '').trim());
            await __tmPersistMetaAndAttrsKernel(tid, statusPatch, {
                touchMetaStore: false,
                skipFlush: false,
            });
            persistedStatus = await __tmReadDocCheckboxBlockAttrs(tid);
            if (persistedStatus !== targetStatus && __tmIsNativeDocCheckboxReconcileVersionCurrent(rawId, syncVersion)) {
                await __tmReconcileNativeDocCheckboxStatus(rawId, tid, statusPatch, !!domDone, syncVersion);
                persistedStatus = await __tmReadDocCheckboxBlockAttrs(tid);
            }
        }
        try {
            __tmApplyAttrPatchLocally(tid, statusPatch, {
                render: false,
                withFilters: false,
            });
            __tmMirrorDocCheckboxStatusPatch(tid, statusPatch);
        } catch (e) {}
        __tmApplyNativeDocCheckboxLocalState(tid, !!domDone, targetStatus, task);
        try {
            const docId = String(task.root_id || task.docId || '').trim();
            if (docId) __tmInvalidateTasksQueryCacheByDocId(docId);
        } catch (e) {}
        try {
            if (typeof __tmIsPluginVisibleNow === 'function' && __tmIsPluginVisibleNow()) {
                __tmScheduleRender({ withFilters: true });
            }
        } catch (e) {}
        try {
            __tmDispatchTaskAttrPatchUpdated(rawId, statusPatch, {
                resolvedTaskId: tid,
                source: 'native-doc-checkbox-sync',
            });
        } catch (e) {}
        try { globalThis.__taskHorizonQuickbarRefreshInline?.(); } catch (e) {}
        try { globalThis.__taskHorizonQuickbarRefresh?.(); } catch (e) {}
        if (domDone) {
            try {
                __tmScheduleRecurringTaskAdvanceAfterCompletion(tid, {
                    source: 'native-doc-checkbox-sync',
                    completedAt: new Date().toISOString(),
                });
            } catch (e) {}
        } else {
            try { __tmClearRecurringTaskAdvanceTimer(tid); } catch (e) {}
        }
        __tmScheduleNativeDocCheckboxStatusReconcile(rawId, tid, statusPatch, !!domDone, syncVersion);
        return true;
    }

    function __tmDrainNativeDocCheckboxSyncQueue() {
        if (__tmNativeDocCheckboxSyncQueueRunning) return;
        __tmNativeDocCheckboxSyncQueueRunning = true;
        Promise.resolve().then(async () => {
            try {
                while (__tmNativeDocCheckboxSyncQueue.length > 0) {
                    const nextBlockId = String(__tmNativeDocCheckboxSyncQueue.shift() || '').trim();
                    if (!nextBlockId) continue;
                    try {
                        await __tmSyncNativeDocCheckboxLinkedStatus(nextBlockId);
                    } catch (e) {}
                }
            } finally {
                __tmNativeDocCheckboxSyncQueueRunning = false;
                if (__tmNativeDocCheckboxSyncQueue.length > 0) {
                    __tmDrainNativeDocCheckboxSyncQueue();
                }
            }
        }).catch(() => {
            __tmNativeDocCheckboxSyncQueueRunning = false;
        });
    }

    function __tmEnqueueNativeDocCheckboxStatusSync(blockId) {
        const rawId = String(blockId || '').trim();
        if (!rawId) return;
        __tmNativeDocCheckboxSyncQueue.push(rawId);
        __tmDrainNativeDocCheckboxSyncQueue();
    }

    function __tmScheduleNativeDocCheckboxStatusSync(blockId) {
        const rawId = String(blockId || '').trim();
        if (!rawId) return;
        try {
            __tmNativeDocCheckboxPendingBatch.set(rawId, ++__tmNativeDocCheckboxBatchSeq);
        } catch (e) {}
        try {
            if (__tmNativeDocCheckboxBatchTimer) clearTimeout(__tmNativeDocCheckboxBatchTimer);
        } catch (e) {}
        __tmNativeDocCheckboxBatchTimer = setTimeout(() => {
            let batchIds = [];
            try {
                batchIds = Array.from(__tmNativeDocCheckboxPendingBatch.entries())
                    .sort((a, b) => Number(a[1]) - Number(b[1]))
                    .map(([id]) => String(id || '').trim())
                    .filter(Boolean);
                __tmNativeDocCheckboxPendingBatch.clear();
            } catch (e) {
                batchIds = rawId ? [rawId] : [];
            }
            __tmNativeDocCheckboxBatchTimer = null;
            batchIds.forEach((id) => __tmEnqueueNativeDocCheckboxStatusSync(id));
        }, __TM_NATIVE_DOC_CHECKBOX_SYNC_DELAY_MS);
    }

    function __tmBindNativeDocCheckboxStatusSync() {
        try {
            if (__tmNativeDocCheckboxSyncClickHandler) {
                document.removeEventListener('click', __tmNativeDocCheckboxSyncClickHandler, true);
                document.removeEventListener('pointerup', __tmNativeDocCheckboxSyncClickHandler, true);
            }
        } catch (e) {}
        try {
            __tmNativeDocCheckboxSyncObserver?.disconnect?.();
            __tmNativeDocCheckboxSyncObserver = null;
        } catch (e) {}

        __tmNativeDocCheckboxSyncClickHandler = (event) => {
            if (!event || event.isTrusted !== true) return;
            const blockId = __tmResolveNativeDocTaskToggleBlockId(event.target);
            if (!blockId) return;
            __tmScheduleNativeDocCheckboxStatusSync(blockId);
        };

        try { document.addEventListener('click', __tmNativeDocCheckboxSyncClickHandler, true); } catch (e) {}
        try { document.addEventListener('pointerup', __tmNativeDocCheckboxSyncClickHandler, true); } catch (e) {}
        try {
            __tmNativeDocCheckboxSyncObserver = new MutationObserver((mutations) => {
                const touched = new Set();
                const collect = (target) => {
                    const blockId = __tmResolveNativeDocTaskBlockId(target);
                    if (blockId) touched.add(blockId);
                };
                (Array.isArray(mutations) ? mutations : []).forEach((mutation) => {
                    const target = mutation?.target;
                    const type = String(mutation?.type || '').trim();
                    if (type === 'attributes') {
                        const targetEl = target instanceof Element ? target : null;
                        const attrName = String(mutation?.attributeName || '').trim();
                        if (!targetEl) return;
                        if (attrName === 'class') {
                            const oldDone = /\bprotyle-task--done\b/.test(String(mutation?.oldValue || ''));
                            const newDone = !!targetEl.classList?.contains?.('protyle-task--done');
                            if (oldDone === newDone) return;
                            if (!(targetEl.matches?.('.protyle-action--task, [data-type="NodeListItem"], .li[data-node-id]') || targetEl.closest?.('.protyle-action--task, [data-type="NodeListItem"], .li[data-node-id]'))) return;
                        } else if (attrName === 'href' || attrName === 'xlink:href') {
                            if (!(targetEl.matches?.('use') || targetEl.closest?.('.protyle-action--task'))) return;
                            const oldHref = String(mutation?.oldValue || '').trim();
                            const oldDone = oldHref === '#iconCheck' ? true : (oldHref === '#iconUncheck' ? false : null);
                            const newDone = __tmReadNativeDocCheckboxIconDoneState(targetEl);
                            if (oldDone === null && newDone === null) return;
                            if (oldDone === newDone) return;
                        } else {
                            return;
                        }
                        collect(targetEl);
                        return;
                    }
                    if (type === 'childList') {
                        try {
                            (Array.from(mutation?.addedNodes || [])).forEach((node) => {
                                const el = node instanceof Element ? node : null;
                                const useEl = el?.matches?.('use')
                                    ? el
                                    : (el?.querySelector?.('.protyle-action--task use') || null);
                                const iconDone = __tmReadNativeDocCheckboxIconDoneState(useEl);
                                const hasCheckboxInput = !!(el?.matches?.('input[type="checkbox"]') || el?.querySelector?.('input[type="checkbox"]'));
                                if (iconDone !== null || hasCheckboxInput) {
                                    collect(el);
                                }
                            });
                        } catch (e) {}
                    }
                });
                touched.forEach((blockId) => __tmScheduleNativeDocCheckboxStatusSync(blockId));
            });
            __tmNativeDocCheckboxSyncObserver.observe(document.body, {
                subtree: true,
                childList: true,
                attributes: true,
                attributeFilter: ['class', 'href', 'xlink:href'],
                attributeOldValue: true,
            });
        } catch (e) {}
    }

    async function init() {
        const bindShellEntrances = !__tmIsDockHost();
        try { __tmBindUndoShortcut(); } catch (e) {}
        if (bindShellEntrances) {
            try { __tmBindWakeReload(); } catch (e) {}
            try { __tmBindTabEnterAutoRefresh(); } catch (e) {}
            try { __tmBindNativeDocCheckboxStatusSync(); } catch (e) {}
        }
        try { __tmBindCalendarScheduleUpdated(); } catch (e) {}
        if (bindShellEntrances) {
            try { __tmBindDocGroupMenuEntry(); } catch (e) {}
        }

        // 监听悬浮条修改任务事件
        try {
            if (__tmQuickbarTaskUpdateHandler) {
                try { window.removeEventListener('tm-task-attr-updated', __tmQuickbarTaskUpdateHandler); } catch (e) {}
            }
            __tmQuickbarTaskUpdateHandler = (e) => {
                if (!e || !e.detail || !e.detail.taskId) return;
                const taskId = String(e.detail.taskId || '').trim();
                if (!taskId) return;
                const attrKey = String(e.detail.attrKey || '').trim();
                const attrValue = String(e.detail.value ?? '');
                if (__tmIsVisibleDateAttrKey(attrKey)) {
                    __tmMarkVisibleDateFallbackTask(taskId);
                }
                
                // 使用 localStorage 持久化存储，以便在插件重新加载后仍能检测到
                try {
                    const stored = JSON.parse(localStorage.getItem('__tmQuickbarModifiedTasks') || '[]');
                    if (!stored.includes(taskId)) {
                        stored.push(taskId);
                        localStorage.setItem('__tmQuickbarModifiedTasks', JSON.stringify(stored));
                    }
                } catch (ex) {}
                
                // 同时更新内存中的状态
                state.quickbarModifiedTaskIds.add(taskId);
                state.lastQuickbarUpdateTime = Date.now();
                if (attrKey) {
                    const applied = __tmApplyQuickbarAttrUpdateInState(taskId, attrKey, attrValue);
                    if (!applied) {
                        Promise.resolve(__tmResolveTaskIdFromAnyBlockId(taskId))
                            .then((resolvedTaskId) => {
                                const nextTaskId = String(resolvedTaskId || '').trim();
                                if (!nextTaskId || nextTaskId === taskId) return;
                                __tmApplyQuickbarAttrUpdateInState(nextTaskId, attrKey, attrValue);
                            })
                            .catch(() => null);
                    }
                }
                if (attrKey === 'bookmark') {
                    try { __tmSetTaskReminderMark(taskId, attrValue.includes('⏰')); } catch (ex) {}
                    try {
                        if (state.modal && document.body.contains(state.modal)) {
                            __tmApplyReminderTaskNameMarks(state.modal);
                        }
                    } catch (ex) {}
                    try { __tmRefreshReminderMarkForTask(taskId, 240); } catch (ex) {}
                } else if (attrKey === 'custom-reminder' || !attrKey) {
                    try { __tmRefreshReminderMarkForTask(taskId, 240); } catch (ex) {}
                }
            };
            window.addEventListener('tm-task-attr-updated', __tmQuickbarTaskUpdateHandler);
        } catch (e) {}
        
        // 检查是否有悬浮条修改的任务需要刷新（从 localStorage 恢复）
        try {
            const stored = JSON.parse(localStorage.getItem('__tmQuickbarModifiedTasks') || '[]');
            if (stored.length > 0) {
                stored.forEach(taskId => state.quickbarModifiedTaskIds.add(taskId));
                state.lastQuickbarUpdateTime = Date.now();
            }
        } catch (ex) {}

        // 1. 先加载设置（包括文档ID）
        try {
            await __tmEnsureSettingsLoaded();
            try {
                if (globalThis.__tmCalendar && typeof globalThis.__tmCalendar.setSettingsStore === 'function') {
                    globalThis.__tmCalendar.setSettingsStore(SettingsStore);
                }
            } catch (e) {}
            await WhiteboardStore.load();

            // 初始化状态
            state.selectedDocIds = SettingsStore.data.selectedDocIds;
            state.queryLimit = SettingsStore.data.queryLimit;
            state.recursiveDocLimit = SettingsStore.data.recursiveDocLimit;
            const gm0 = String(SettingsStore.data.groupMode || '').trim();
            const validModes = new Set(['none', 'doc', 'time', 'quadrant', 'task']);
            if (!validModes.has(gm0)) {
                // groupMode 无效时，使用已加载的标志位
                state.groupByDocName = SettingsStore.data.groupByDocName;
                state.groupByTaskName = SettingsStore.data.groupByTaskName;
                state.groupByTime = SettingsStore.data.groupByTime;
                state.quadrantEnabled = SettingsStore.data.quadrantConfig?.enabled || false;
            }
            // 根据 groupMode 设置标志位，但 groupByTaskName 只在 groupMode === 'task' 时才设置为 true
            if (gm0 === 'doc') {
                state.groupByDocName = true;
                state.groupByTime = false;
                state.quadrantEnabled = false;
            } else if (gm0 === 'time') {
                state.groupByDocName = false;
                state.groupByTime = true;
                state.quadrantEnabled = false;
            } else if (gm0 === 'task') {
                state.groupByDocName = false;
                state.groupByTaskName = true;
                state.groupByTime = false;
                state.quadrantEnabled = false;
            } else if (gm0 === 'quadrant') {
                state.groupByDocName = false;
                state.groupByTime = false;
                state.quadrantEnabled = true;
            } else {
                // 当 groupMode 为 'none' 时（用户选择了"不分组"），将 state.groupByTaskName 设置为 false
                // 这样可以正确显示"不分组"选项为选中状态
                // 注意：这里不检查 SettingsStore.data.groupByTaskName，因为它只控制开关显示，不影响当前分组模式
                state.groupByDocName = false;
                state.groupByTaskName = false;
                state.groupByTime = false;
                state.quadrantEnabled = false;
            }
            state.collapsedTaskIds = new Set(SettingsStore.data.collapsedTaskIds || []);
            state.collapsedGroups = new Set(SettingsStore.data.collapsedGroups || []);
            state.currentRule = SettingsStore.data.currentRule;
            state.columnWidths = SettingsStore.data.columnWidths;
            state.docTabsHidden = !!Storage.get('tm_doc_tabs_hidden', false);

            // 加载筛选规则
            state.filterRules = await __tmEnsureFilterRulesLoaded();
        } catch (e) {
            console.error('[初始化] 加载设置失败:', e);
        }

        try {
            if (__tmThemeModeObserver) {
                __tmThemeModeObserver.disconnect();
                __tmThemeModeObserver = null;
            }
            __tmThemeModeObserver = new MutationObserver(() => {
                try { __tmApplyAppearanceThemeVars(); } catch (e) {}
                try { if (state.modal) render(); } catch (e) {}
            });
            __tmThemeModeObserver.observe(document.documentElement, { attributes: true, attributeFilter: ['data-theme-mode'] });
        } catch (e) {}
        try { __tmApplyAppearanceThemeVars(); } catch (e) {}

        // 2. 获取所有文档列表
        try {
            state.allDocuments = await __tmEnsureAllDocumentsLoaded(false);
        } catch (e) {
            console.error('[初始化] 加载文档列表失败:', e);
        }

        // 3. 创建浮动按钮 (已禁用)
        /*
        const fab = document.createElement('button');
        fab.className = 'tm-fab';
        fab.innerHTML = '📋 任务管理';
        fab.onclick = openManager;
        document.body.appendChild(fab);

        // 显示已选文档数量
        if (state.selectedDocIds.length > 0) {
            fab.title = `任务管理 (已选 ${state.selectedDocIds.length} 个文档)`;
        }
        */

        // 启动面包屑按钮观察者
        if (bindShellEntrances) {
            observeBreadcrumb();
        }
        try { __tmBootstrapCalendarBackgroundRefresh(0); } catch (e) {}
    }

    async function __tmEnsureTabOpened(maxWaitMs = 1500) {
        if (typeof globalThis.__taskHorizonOpenTabView !== 'function') return;
        try {
            if (window.siyuan?.config?.isMobile) return;
        } catch (e) {}
        if (__tmIsRuntimeMobileClient()) return;
        __tmEnsureMount();
        // Removed aggressive openTabView call if mount exists, relying on findExistingModel logic instead
        
        try {
            const custom = __tmFindExistingTaskHorizonCustomModel();
            if (custom) {
                try {
                    const tab = custom.tab || custom;
                    if (tab && window.siyuan?.layout?.centerLayout?.switchTab) {
                        window.siyuan.layout.centerLayout.switchTab(tab);
                    } else if (tab?.headElement?.click) {
                        tab.headElement.click();
                    }
                } catch (e2) {}
                try {
                    const el = await __tmWaitForTaskHorizonTabRoot(900) || custom.element;
                    if (el && document.body.contains(el)) {
                        try { globalThis.__taskHorizonTabElement = el; } catch (e3) {}
                        __tmSetMount(el);
                    }
                } catch (e2) {}
                return;
            }
        } catch (e) {}
        try {
            const existingTab = __tmFindExistingTaskManagerTab?.();
            if (existingTab) {
                try { __tmSwitchToTab(existingTab); } catch (e) {}
                try {
                    await new Promise(resolve => requestAnimationFrame(() => requestAnimationFrame(resolve)));
                } catch (e) {}
                const best = await __tmWaitForTaskHorizonTabRoot(900);
                if (best && document.body.contains(best)) {
                    try { globalThis.__taskHorizonTabElement = best; } catch (e) {}
                    __tmSetMount(best);
                }
                return;
            }
        } catch (e) {}
        
        // 尝试查找并点击标签页标题 (Fallback)
        try {
            const headers = document.querySelectorAll('.layout-tab-bar__item');
            for (const h of headers) {
                if (__tmIsTaskHorizonTabHeaderEl(h)) {
                    h.click();
                    
                    const resolved = await __tmWaitForTaskHorizonTabRoot(2000);
                    if (resolved && document.body.contains(resolved)) {
                        try { globalThis.__taskHorizonTabElement = resolved; } catch (e) {}
                        __tmSetMount(resolved);
                        return;
                    }
                    // 即使超时，只要找到了 header，我们也认为不需要新建，避免重复
                    return;
                }
            }
        } catch(e) {}

        if (__tmEnsureTabPromise) return __tmEnsureTabPromise;
        __tmEnsureTabPromise = (async () => {
            try {
                try { globalThis.__taskHorizonOpenTabView(); } catch (e) {}
                const resolved = await __tmWaitForTaskHorizonTabRoot(maxWaitMs);
                if (resolved && document.body.contains(resolved)) {
                    try { globalThis.__taskHorizonTabElement = resolved; } catch (e) {}
                    __tmSetMount(resolved);
                }
            } finally {
                __tmEnsureTabPromise = null;
            }
        })();
        return __tmEnsureTabPromise;
    }

    // 检查是否有任何分组包含文档（支持全部文档和自定义分组）
    async function checkAnyGroupHasDocs() {
        // 检查全部文档分组
        if (SettingsStore.data.selectedDocIds && SettingsStore.data.selectedDocIds.length > 0) {
            return true;
        }
        
        // 检查自定义分组
        const groups = SettingsStore.data.docGroups || [];
        for (const group of groups) {
            if ((group.docs && group.docs.length > 0) || String(group?.notebookId || '').trim()) {
                return true;
            }
        }
        
        return false;
    }

    // 查找已打开的任务管理器标签页
    function __tmFindExistingTaskManagerTab() {
        try {
            const custom = __tmFindExistingTaskHorizonCustomModel?.();
            if (custom?.tab) return custom.tab;
            if (custom?.headElement instanceof Element) return custom.headElement;
            if (custom) return custom;
        } catch (e) {}
        try {
            const tabId = String(globalThis.__taskHorizonCustomTabId || '').trim();
            if (!tabId) return null;
            return document.querySelector(`.layout-tab-bar [data-id="${tabId}"], .layout-tab-bar [data-key="${tabId}"]`);
        } catch (e) {}
        return null;
    }

    // 切换到指定标签页
    function __tmSwitchToTab(tab) {
        try {
            if (!(tab instanceof Element) && window.siyuan && window.siyuan.layout && window.siyuan.layout.centerLayout) {
                window.siyuan.layout.centerLayout.switchTab(tab);
                return true;
            }
        } catch (e) {
        }
        try {
            const header = tab instanceof Element ? tab : (tab?.headElement instanceof Element ? tab.headElement : null);
            if (header) {
                try {
                    header.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true }));
                } catch (e) {
                    try { header.click(); } catch (e2) {}
                }
                return true;
            }
        } catch (e) {}
        try {
            if (typeof globalThis.__taskHorizonOpenTabView === 'function') {
                globalThis.__taskHorizonOpenTabView();
                return true;
            }
        } catch (e) {}
        return false;
    }

    async function openManager(options) {
        state.openToken = (Number(state.openToken) || 0) + 1;
        const token = Number(state.openToken) || 0;
        const perfTrace = __tmCreatePerfTrace('openManager', {
            token,
            runtimeMobile: __tmIsRuntimeMobileClient() ? 1 : 0,
            forceOpenTab: options?.forceOpenTab ? 1 : 0,
            skipEnsureTabOpened: options?.skipEnsureTabOpened ? 1 : 0,
        });
        __tmPerfTraceMark(perfTrace, 'open:start', { token });
        try { __tmListenPinnedChanged(); } catch (e) {}
        let reusedExistingModal = false;
        const shouldEnsureDesktopTab = !!(options && options.forceOpenTab)
            || !__tmIsRuntimeMobileClient();

        if (shouldEnsureDesktopTab) {
            if (!options || !options.skipEnsureTabOpened) {
                await __tmEnsureTabOpened();
            } else {
                __tmEnsureMount();
            }
            try {
                setTimeout(() => { try { __tmPatchTaskHorizonTabIcon(); } catch (e) {} }, 0);
                setTimeout(() => { try { __tmPatchTaskHorizonTabIcon(); } catch (e) {} }, 250);
                setTimeout(() => { try { __tmPatchTaskHorizonTabIcon(); } catch (e) {} }, 900);
            } catch (e) {}
        }
        __tmPerfTraceMark(perfTrace, 'open:mount-ready', {
            ensureDesktopTab: shouldEnsureDesktopTab ? 1 : 0,
        });

        // 仅在必要时重渲染，避免页签切换返回时闪烁和滚动位置丢失
        try {
            try { __tmTryReattachExistingModalToMount(__tmMountEl || document.body); } catch (e) {}
            const modalEl = state.modal;
            const currentMount = __tmMountEl || document.body;
            const mounted = !!(modalEl && modalEl instanceof HTMLElement && document.body.contains(modalEl));
            const inCurrentMount = !!(currentMount && modalEl && modalEl.parentElement === currentMount);
            reusedExistingModal = mounted && inCurrentMount;
            if (!reusedExistingModal) {
                try { render(); } catch (e) {
                    console.error('[OpenManager] Render failed:', e);
                }
            }
        } catch (e) {
            try { render(); } catch (e2) {
                console.error('[OpenManager] Render failed:', e2);
            }
        }
        __tmPerfTraceMark(perfTrace, 'open:shell-render', {
            reusedExistingModal: reusedExistingModal ? 1 : 0,
        });
        __tmPerfTraceMark(perfTrace, 'open:shell-first-paint', {
            reusedExistingModal: reusedExistingModal ? 1 : 0,
        });

        let hasDataReadyForSoftReuse0 = false;
        try {
            const treeReady = Array.isArray(state.taskTree) && state.taskTree.length > 0;
            const flatReady = state.flatTasks && Object.keys(state.flatTasks).length > 0;
            hasDataReadyForSoftReuse0 = !!(treeReady || flatReady);
        } catch (e) {
            hasDataReadyForSoftReuse0 = false;
        }
        const quickbarDirty0 = __tmHasQuickbarModificationsSync();
        const hasPendingInsertedTasks0 = (() => {
            try {
                return Object.keys(state.pendingInsertedTasks || {}).some((id) => !!String(id || '').trim());
            } catch (e) {
                return false;
            }
        })();
        const shouldShowInlineLoading = !state.wasHidden
            && !(options && options.skipLoadingHint)
            && !(options && options.skipEnsureTabOpened)
            && !(reusedExistingModal && hasDataReadyForSoftReuse0 && !quickbarDirty0 && !hasPendingInsertedTasks0);
        state.wasHidden = false;

        await __tmEnsureSettingsLoaded();
        try { await __tmRefreshNotebookCache(); } catch (e) {}
        try {
            if (globalThis.__tmCalendar && typeof globalThis.__tmCalendar.setSettingsStore === 'function') {
                globalThis.__tmCalendar.setSettingsStore(SettingsStore);
            }
        } catch (e) {}
        try {
            const allow = new Set(['list', 'checklist', 'timeline', 'kanban', 'calendar', 'whiteboard']);
            const isMobileDevice = __tmIsMobileDevice();
            const preserve = !!(options && options.preserveViewMode);
            const current = String(state.viewMode || '').trim();
            if (preserve && state.viewModeInitialized === true && allow.has(current)) {
                state.viewMode = __tmGetSafeViewMode(current);
            } else {
                state.viewMode = __tmGetConfiguredDefaultViewMode(isMobileDevice);
            }
            state.viewModeInitialized = true;
        } catch (e) {
            state.viewMode = 'list';
            state.viewModeInitialized = true;
        }
        try {
            const ids = Array.isArray(SettingsStore.data.kanbanCollapsedTaskIds) ? SettingsStore.data.kanbanCollapsedTaskIds : [];
            state.__tmKanbanCollapsedIds = new Set(ids.map(x => String(x || '').trim()).filter(Boolean));
        } catch (e) {
            state.__tmKanbanCollapsedIds = new Set();
        }
        if (SettingsStore.data.enableTomatoIntegration) {
            try { __tmHookTomatoTimer(); } catch (e) {}
            try { __tmListenTomatoAssociationCleared(); } catch (e) {}
        }
        state.selectedDocIds = SettingsStore.data.selectedDocIds;

        // 检查是否至少有一个分组包含文档
        const hasDocs = await checkAnyGroupHasDocs();
        if (!hasDocs) {
            hint('⚠ 请先在设置中添加要显示的文档', 'warning');
            if (state.modal && token === (Number(state.openToken) || 0)) showSettings();
            __tmPerfTraceFinish(perfTrace, {
                reason: 'no-doc-groups',
                reusedExistingModal: reusedExistingModal ? 1 : 0,
            });
            return;
        }

        if (!state.modal || token !== (Number(state.openToken) || 0)) {
            __tmPerfTraceFinish(perfTrace, {
                cancelled: 1,
                reason: 'modal-stale',
            });
            return;
        }
        try {
            await new Promise(resolve => {
                requestAnimationFrame(() => requestAnimationFrame(resolve));
            });
        } catch (e) {}
        const hasDataReadyForSoftReuse = (() => {
            try {
                const treeReady = Array.isArray(state.taskTree) && state.taskTree.length > 0;
                const flatReady = state.flatTasks && Object.keys(state.flatTasks).length > 0;
                return !!(treeReady || flatReady);
            } catch (e) {
                return false;
            }
        })();
        const quickbarDirty = __tmHasQuickbarModificationsSync();
        const hasPendingInsertedTasks = (() => {
            try {
                return Object.keys(state.pendingInsertedTasks || {}).some((id) => !!String(id || '').trim());
            } catch (e) {
                return false;
            }
        })();
        const canSkipRenderOnReuse = reusedExistingModal && hasDataReadyForSoftReuse && !quickbarDirty && !hasPendingInsertedTasks;
        if (canSkipRenderOnReuse) {
            try { __tmScheduleReminderTaskNameMarksRefresh(state.modal, true); } catch (e) {}
            try {
                if (String(state.viewMode || '').trim() === 'calendar' && globalThis.__tmCalendar?.refreshInPlace) {
                    globalThis.__tmCalendar.refreshInPlace({ layoutOnly: true, hard: false });
                }
            } catch (e) {}
            __tmPerfTraceFinish(perfTrace, {
                softReuse: 1,
                reusedExistingModal: 1,
                viewMode: String(state.viewMode || '').trim() || 'list',
            });
            return;
        }
        if (quickbarDirty) {
            __tmClearQuickbarModifications();
            try { await new Promise(resolve => setTimeout(resolve, 200)); } catch (e) {}
            try { window.__tmCalendarAllTasksCache = null; } catch (e) {}
        }
        try {
            state.activeDocId = String(state.activeDocId || 'all').trim() || 'all';
            await __tmApplyCurrentContextViewProfile();
        } catch (e) {}
        __tmPerfTraceMark(perfTrace, 'open:load-dispatched', {
            viewMode: String(state.viewMode || '').trim() || 'list',
            preferFastFirstPaint: __tmIsRuntimeMobileClient() ? 1 : 0,
        });
        loadSelectedDocuments({
            skipRender: canSkipRenderOnReuse,
            preferFastFirstPaint: !canSkipRenderOnReuse && __tmIsRuntimeMobileClient(),
            showInlineLoading: shouldShowInlineLoading,
            perfTrace,
            source: 'openManager'
        }).then(() => {
            if (!canSkipRenderOnReuse) return;
            try {
                if (String(state.viewMode || '').trim() === 'calendar' && globalThis.__tmCalendar?.refreshInPlace) {
                    globalThis.__tmCalendar.refreshInPlace({ layoutOnly: true, hard: false });
                }
            } catch (e) {}
        }).catch(e => {
            __tmPerfTraceFinish(perfTrace, {
                error: String(e?.message || e || '').trim() || 'open-load-failed',
                viewMode: String(state.viewMode || '').trim() || 'list',
            });
            hint(`❌ 加载失败: ${e.message}`, 'error');
        });
    }

